import React, { useState, useMemo } from 'react';
import { MOCK_DATA } from './constants';
import { AppData, TransactionType } from './types';
import Dashboard from './components/Dashboard';
import Professionals from './components/Professionals';
import CashFlow from './components/CashFlow';
import Expenses from './components/Expenses';
import Config from './components/Config';
import Navigation from './components/Navigation';

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [pin, setPin] = useState('');
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedYear, setSelectedYear] = useState(2024);
  const [data, setData] = useState<AppData>(MOCK_DATA);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '1234') {
      setIsLoggedIn(true);
    } else {
      alert('PIN Incorreto (Dica: 1234)');
      setPin('');
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 p-6">
        <div className="w-full max-w-sm bg-white p-8 rounded-3xl shadow-xl border border-slate-100 text-center">
          <div className="mb-8">
            <h1 className="text-2xl font-extrabold text-slate-800 tracking-tight">Fechamento Anual</h1>
            <p className="text-slate-500 text-sm mt-1 uppercase tracking-widest font-semibold">Business Intelligence</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Digite o PIN de Acesso</label>
              <input
                type="password"
                maxLength={4}
                value={pin}
                onChange={(e) => setPin(e.target.value)}
                autoFocus
                className="w-full text-center text-4xl tracking-[1em] py-3 border-b-2 border-slate-200 focus:border-blue-500 focus:outline-none bg-transparent"
              />
            </div>
            <button
              type="submit"
              className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-slate-800 transition-all shadow-lg active:scale-95"
            >
              Acessar Painel
            </button>
          </form>
          <p className="mt-8 text-[10px] text-slate-400">© 2024 BarberPro BI Solutions</p>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard data={data} year={selectedYear} />;
      case 'professionals': return <Professionals data={data} year={selectedYear} />;
      case 'fluxo': return <CashFlow data={data} year={selectedYear} />;
      case 'gastos': return <Expenses data={data} year={selectedYear} />;
      case 'config': return <Config data={data} setData={setData} selectedYear={selectedYear} setSelectedYear={setSelectedYear} />;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col pb-24 md:pb-0 md:pl-0">
      <header className="bg-white/80 backdrop-blur-md sticky top-0 z-50 px-6 py-4 flex justify-between items-center border-b border-slate-100">
        <div>
          <h2 className="text-lg font-extrabold text-slate-800">Barbearia BI</h2>
          <span className="text-[10px] text-blue-600 font-bold uppercase tracking-widest">Ano Base: {selectedYear}</span>
        </div>
        <div className="bg-slate-100 px-3 py-1 rounded-full text-xs font-bold text-slate-600">
          v1.0.2
        </div>
      </header>

      <main className="flex-1 p-6 max-w-5xl mx-auto w-full">
        {renderContent()}
      </main>

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
    </div>
  );
};

export default App;

import React from 'react';
import { LayoutDashboard, Users, Repeat, Receipt, Settings } from 'lucide-react';

interface NavigationProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Navigation: React.FC<NavigationProps> = ({ activeTab, setActiveTab }) => {
  const items = [
    { id: 'dashboard', label: 'Home', icon: LayoutDashboard },
    { id: 'professionals', label: 'Equipe', icon: Users },
    { id: 'fluxo', label: 'Fluxo', icon: Repeat },
    { id: 'gastos', label: 'Gastos', icon: Receipt },
    { id: 'config', label: 'Ajustes', icon: Settings },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 glass-nav h-20 px-6 flex justify-around items-center z-50">
      {items.map((item) => {
        const Icon = item.icon;
        const isActive = activeTab === item.id;
        return (
          <button
            key={item.id}
            onClick={() => setActiveTab(item.id)}
            className={`flex flex-col items-center justify-center space-y-1 transition-all ${
              isActive ? 'text-blue-600' : 'text-slate-400'
            }`}
          >
            <div className={`p-2 rounded-xl transition-all ${isActive ? 'bg-blue-50' : ''}`}>
              <Icon size={22} strokeWidth={isActive ? 2.5 : 2} />
            </div>
            <span className="text-[10px] font-bold uppercase tracking-tighter">{item.label}</span>
          </button>
        );
      })}
    </nav>
  );
};

export default Navigation;

import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Cell } from 'recharts';
import { AppData } from '../types';
import { TrendingUp, DollarSign, Wallet, Star, Coffee } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const producaoAno = data.producao.filter(p => p.ano === year);
  const receitasExtrasAno = data.receitasExtras.filter(r => r.ano === year);
  const gastosAno = data.gastos.filter(g => g.ano === year);
  const parametros = data.parametros.find(p => p.ano === year) || data.parametros[0];

  const totalProducao = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0);
  const totalAssinaturas = receitasExtrasAno.reduce((acc, curr) => acc + curr.assinaturas, 0);
  const totalGeladeira = receitasExtrasAno.reduce((acc, curr) => acc + curr.geladeira, 0);
  const totalReceita = totalProducao + totalAssinaturas + totalGeladeira;

  const totalGastos = gastosAno.reduce((acc, curr) => acc + curr.valor, 0);
  const totalRepasses = producaoAno.reduce((acc, curr) => acc + curr.repasseProfissional, 0);
  const resultadoFinal = totalReceita - totalGastos - totalRepasses;

  const mensalData = Array.from({ length: 12 }, (_, i) => {
    const mes = i + 1;
    const prodMes = producaoAno.filter(p => p.mes === mes).reduce((s, c) => s + c.producaoBruta, 0);
    const extraMes = receitasExtrasAno.find(r => r.mes === mes);
    return {
      name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i],
      receita: prodMes + (extraMes?.assinaturas || 0) + (extraMes?.geladeira || 0)
    };
  });

  const percMeta = (totalReceita / parametros.metaFaturamento) * 100;

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <SummaryCard label="Faturamento Ano" value={totalReceita} icon={DollarSign} color="text-blue-600" />
        <SummaryCard label="Resultado Final" value={resultadoFinal} icon={TrendingUp} color="text-emerald-600" />
        <SummaryCard label="Assinaturas" value={totalAssinaturas} icon={Star} color="text-amber-500" />
        <SummaryCard label="Geladeira" value={totalGeladeira} icon={Coffee} color="text-indigo-500" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 bg-white p-6 rounded-3xl card-shadow border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-bold text-slate-800">Evolução do Faturamento</h3>
            <span className="text-xs font-bold text-slate-400 uppercase">12 Meses</span>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={mensalData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                <YAxis hide />
                <Tooltip 
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}}
                  formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`}
                />
                <Line type="monotone" dataKey="receita" stroke="#2563eb" strokeWidth={4} dot={{r: 4, fill: '#2563eb'}} activeDot={{r: 6}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl card-shadow border border-slate-100 flex flex-col items-center justify-center text-center">
          <h3 className="font-bold text-slate-800 mb-2">Meta Anual</h3>
          <div className="relative w-32 h-32 flex items-center justify-center mb-4">
            <svg className="w-full h-full transform -rotate-90">
              <circle cx="64" cy="64" r="58" stroke="#f1f5f9" strokeWidth="12" fill="transparent" />
              <circle cx="64" cy="64" r="58" stroke="#2563eb" strokeWidth="12" fill="transparent" strokeDasharray={364} strokeDashoffset={364 - (364 * Math.min(percMeta, 100)) / 100} strokeLinecap="round" />
            </svg>
            <span className="absolute text-xl font-extrabold text-slate-800">{Math.round(percMeta)}%</span>
          </div>
          <p className="text-xs text-slate-500">Realidade: <span className="font-bold text-slate-800">R$ {totalReceita.toLocaleString('pt-BR')}</span></p>
          <p className="text-xs text-slate-500">Meta: <span className="font-bold text-slate-800">R$ {parametros.metaFaturamento.toLocaleString('pt-BR')}</span></p>
          <div className={`mt-4 px-3 py-1 rounded-full text-[10px] font-bold uppercase ${totalReceita >= parametros.metaFaturamento ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
            {totalReceita >= parametros.metaFaturamento ? 'Meta Atingida' : `Faltam R$ ${(parametros.metaFaturamento - totalReceita).toLocaleString('pt-BR')}`}
          </div>
        </div>
      </div>
    </div>
  );
};

const SummaryCard = ({ label, value, icon: Icon, color }: any) => (
  <div className="bg-white p-4 rounded-3xl card-shadow border border-slate-100">
    <div className={`w-8 h-8 rounded-xl flex items-center justify-center mb-3 bg-slate-50 ${color}`}>
      <Icon size={18} />
    </div>
    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{label}</p>
    <p className="text-lg font-extrabold text-slate-800 mt-1 truncate">R$ {value.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</p>
  </div>
);

export default Dashboard;

import React from 'react';
import { AppData } from '../types';
import { Trophy, Award, Medal } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, year }) => {
  const producaoAno = data.producao.filter(p => p.ano === year);
  const parametros = data.parametros.find(p => p.ano === year) || data.parametros[0];

  const ranking = data.profissionais.map(prof => {
    const totalProd = producaoAno.filter(p => p.profissionalId === prof.id).reduce((s, c) => s + c.producaoBruta, 0);
    const totalCasa = producaoAno.filter(p => p.profissionalId === prof.id).reduce((s, c) => s + c.recebidoPelaCasa, 0);
    const mediaMensal = totalProd / 12;
    return {
      ...prof,
      totalProd,
      totalCasa,
      mediaMensal,
      percMeta: (mediaMensal / parametros.metaPorCadeira) * 100
    };
  }).sort((a, b) => b.totalProd - a.totalProd);

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex justify-between items-end mb-2">
        <div>
          <h2 className="text-2xl font-extrabold text-slate-800">Ranking Anual</h2>
          <p className="text-sm text-slate-500">Desempenho por cadeira e meta individual</p>
        </div>
        <div className="text-right">
          <p className="text-[10px] text-slate-400 font-bold uppercase">Meta Mensal/Cadeira</p>
          <p className="text-lg font-bold text-blue-600">R$ {parametros.metaPorCadeira.toLocaleString('pt-BR')}</p>
        </div>
      </header>

      <div className="space-y-4">
        {ranking.map((prof, idx) => (
          <div key={prof.id} className="bg-white p-5 rounded-3xl card-shadow border border-slate-100 flex flex-col gap-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg ${
                  idx === 0 ? 'bg-amber-100 text-amber-600' : 
                  idx === 1 ? 'bg-slate-100 text-slate-500' :
                  idx === 2 ? 'bg-orange-100 text-orange-600' : 'bg-slate-50 text-slate-300'
                }`}>
                  {idx + 1}º
                </div>
                <div>
                  <h4 className="font-bold text-slate-800 leading-none">{prof.nome}</h4>
                  <span className="text-[10px] text-slate-400 uppercase font-bold">Cadeira {prof.cadeira}</span>
                </div>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-slate-400 font-bold uppercase leading-none">Produção Anual</p>
                <p className="text-xl font-extrabold text-slate-800">R$ {prof.totalProd.toLocaleString('pt-BR')}</p>
              </div>
            </div>

            <div className="w-full h-2 bg-slate-50 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-1000 ${prof.percMeta >= 100 ? 'bg-emerald-500' : 'bg-blue-500'}`} 
                style={{ width: `${Math.min(prof.percMeta, 100)}%` }} 
              />
            </div>

            <div className="grid grid-cols-3 gap-2">
              <div className="text-center">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Média Mês</p>
                <p className="text-xs font-bold text-slate-700">R$ {prof.mediaMensal.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
              </div>
              <div className="text-center border-x border-slate-100">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Atingimento</p>
                <p className={`text-xs font-bold ${prof.percMeta >= 100 ? 'text-emerald-600' : 'text-slate-700'}`}>{Math.round(prof.percMeta)}%</p>
              </div>
              <div className="text-center">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Retorno Casa</p>
                <p className="text-xs font-bold text-slate-700">R$ {prof.totalCasa.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Professionals;

import React from 'react';
import { AppData } from '../types';

interface CashFlowProps {
  data: AppData;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, year }) => {
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const matrix = meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastos = data.gastos.filter(g => g.ano === year && g.mes === mes).reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + (extra?.assinaturas || 0) + (extra?.geladeira || 0);
    const repasse = prod.reduce((s, c) => s + c.repasseProfissional, 0);
    const liquido = bruta - repasse - gastos;

    return { nome, bruta, repasse, gastos, liquido };
  });

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <h2 className="text-2xl font-extrabold text-slate-800">Fluxo Mensal Consolidado</h2>

      <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-[10px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-4 py-4 sticky left-0 bg-slate-50">Mês</th>
                <th className="px-4 py-4 text-right">Rec. Bruta</th>
                <th className="px-4 py-4 text-right">Repasse</th>
                <th className="px-4 py-4 text-right">Gastos</th>
                <th className="px-4 py-4 text-right">Resultado</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {matrix.map((m) => (
                <tr key={m.nome} className="hover:bg-blue-50/30 transition-colors">
                  <td className="px-4 py-4 font-bold text-slate-700 sticky left-0 bg-white">{m.nome}</td>
                  <td className="px-4 py-4 text-right font-medium text-slate-600">R$ {m.bruta.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className="px-4 py-4 text-right text-amber-600 font-medium">R$ {m.repasse.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className="px-4 py-4 text-right text-red-500 font-medium">R$ {m.gastos.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className={`px-4 py-4 text-right font-bold ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                    R$ {m.liquido.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}
                  </td>
                </tr>
              ))}
            </tbody>
            <tfoot className="bg-slate-900 text-white font-bold">
              <tr>
                <td className="px-4 py-5 text-[10px] uppercase">TOTAL</td>
                <td className="px-4 py-5 text-right">R$ {matrix.reduce((s, m) => s + m.bruta, 0).toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                <td className="px-4 py-5 text-right">R$ {matrix.reduce((s, m) => s + m.repasse, 0).toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                <td className="px-4 py-5 text-right">R$ {matrix.reduce((s, m) => s + m.gastos, 0).toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                <td className="px-4 py-5 text-right text-blue-400 text-lg">R$ {matrix.reduce((s, m) => s + m.liquido, 0).toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
              </tr>
            </tfoot>
          </table>
        </div>
      </div>
    </div>
  );
};

export default CashFlow;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip, BarChart, Bar, XAxis, YAxis } from 'recharts';
import { AppData } from '../types';

interface ExpensesProps {
  data: AppData;
  year: number;
}

const Expenses: React.FC<ExpensesProps> = ({ data, year }) => {
  const gastosAno = data.gastos.filter(g => g.ano === year);

  const porCategoria = Object.entries(
    gastosAno.reduce((acc: any, curr) => {
      acc[curr.categoria] = (acc[curr.categoria] || 0) + curr.valor;
      return acc;
    }, {})
  ).map(([name, value]) => ({ name, value }));

  const COLORS = ['#2563eb', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#64748b'];

  const totalGastos = porCategoria.reduce((s, c) => s + (c.value as number), 0);

  return (
    <div className="space-y-6 animate-in zoom-in duration-500">
      <h2 className="text-2xl font-extrabold text-slate-800">Análise de Gastos</h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-3xl card-shadow border border-slate-100">
          <h3 className="font-bold text-slate-800 mb-6">Distribuição por Categoria</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={porCategoria}
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {porCategoria.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}}
                  formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`}
                />
                <Legend iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 pt-4 border-t border-slate-50 text-center">
            <p className="text-[10px] text-slate-400 uppercase font-bold">Investimento Total do Ano</p>
            <p className="text-2xl font-black text-slate-800">R$ {totalGastos.toLocaleString('pt-BR')}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl card-shadow border border-slate-100 flex flex-col">
          <h3 className="font-bold text-slate-800 mb-6">Ranking de Despesas</h3>
          <div className="flex-1 space-y-4">
            {porCategoria.sort((a, b) => (b.value as number) - (a.value as number)).map((item, idx) => (
              <div key={item.name} className="flex items-center justify-between p-3 bg-slate-50 rounded-2xl">
                <div className="flex items-center gap-3">
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }} />
                  <span className="text-xs font-bold text-slate-700">{item.name}</span>
                </div>
                <div className="text-right">
                  <p className="text-xs font-black text-slate-800">R$ {(item.value as number).toLocaleString('pt-BR')}</p>
                  <p className="text-[9px] text-slate-400 font-bold">{Math.round(((item.value as number) / totalGastos) * 100)}%</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Expenses;

