import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { AppData } from '../types';
import { TrendingUp, DollarSign, Star, Coffee, Trophy } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const producaoAno = data.producao.filter(p => p.ano === year);
  const receitasExtrasAno = data.receitasExtras.filter(r => r.ano === year);
  const gastosAno = data.gastos.filter(g => g.ano === year);
  const parametros = data.parametros.find(p => p.ano === year) || data.parametros[0];

  const totalProducao = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0);
  const totalAssinaturas = receitasExtrasAno.reduce((acc, curr) => acc + curr.assinaturas, 0);
  const totalGeladeira = receitasExtrasAno.reduce((acc, curr) => acc + curr.geladeira, 0);
  const totalReceita = totalProducao + totalAssinaturas + totalGeladeira;

  const totalGastos = gastosAno.reduce((acc, curr) => acc + curr.valor, 0);
  const totalRepasses = producaoAno.reduce((acc, curr) => acc + curr.repasseProfissional, 0);
  const resultadoFinal = totalReceita - totalGastos - totalRepasses;

  const mensalData = Array.from({ length: 12 }, (_, i) => {
    const mes = i + 1;
    const prodMes = producaoAno.filter(p => p.mes === mes).reduce((s, c) => s + c.producaoBruta, 0);
    const extraMes = receitasExtrasAno.find(r => r.mes === mes);
    return {
      name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i],
      receita: prodMes + (extraMes?.assinaturas || 0) + (extraMes?.geladeira || 0)
    };
  });

  const percMeta = (totalReceita / (parametros?.metaFaturamento || 1)) * 100;

  // Ranking de Profissionais para o Dashboard
  const ranking = data.profissionais.map(prof => ({
    nome: prof.nome,
    total: data.producao.filter(p => p.ano === year && p.profissionalId === prof.id).reduce((s, c) => s + c.producaoBruta, 0)
  })).sort((a, b) => b.total - a.total).slice(0, 4);

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <SummaryCard label="Faturamento Ano" value={totalReceita} icon={DollarSign} color="text-blue-600" />
        <SummaryCard label="Resultado Final" value={resultadoFinal} icon={TrendingUp} color="text-emerald-600" />
        <SummaryCard label="Assinaturas" value={totalAssinaturas} icon={Star} color="text-amber-500" />
        <SummaryCard label="Geladeira" value={totalGeladeira} icon={Coffee} color="text-indigo-500" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 bg-white p-6 rounded-3xl card-shadow border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-bold text-slate-800">Evolução do Faturamento</h3>
