import React, { useState } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal } from '../types';
import { PlusCircle, X } from 'lucide-react';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  // State para o form de fechamento
  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0 })),
    gastos: [
      { categoria: 'Aluguel', valor: 0 },
      { categoria: 'Água/Luz', valor: 0 },
      { categoria: 'Produtos', valor: 0 },
      { categoria: 'Marketing', valor: 0 }
    ]
  });

  const matrix = meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastos = data.gastos.filter(g => g.ano === year && g.mes === mes).reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional, 0);
    const liquido = bruta - repasse - gastos;

    return { nome, bruta, repasse, gastos, liquido };
  });

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year,
      mes: formData.mes,
      dinheiro: formData.dinheiro,
      cartao: formData.cartao,
      pix: formData.pix,
      assinaturas: formData.assinaturas,
      pacotes: formData.pacotes,
      geladeira: 0,
      outras: 0
    };

    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year,
      mes: formData.mes,
      profissionalId: p.id,
      producaoBruta: p.bruta,
      repasseProfissional: p.repasse,
      recebidoPelaCasa: p.bruta - p.repasse
    }));

    const newGastos: GastoMensal[] = formData.gastos.map(g => ({
      ano: year,
      mes: formData.mes,
      categoria: g.categoria,
      valor: g.valor
    }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });

    setShowModal(false);
    alert('Fechamento registrado!');
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-extrabold text-slate-800">Fluxo Consolidado</h2>
        <button 
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-xl font-bold text-sm hover:bg-blue-700 transition-all"
        >
          <PlusCircle size={18} />
          Registrar Fechamento
        </button>
      </div>

      <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-[10px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-4 py-4 sticky left-0 bg-slate-50">Mês</th>
                <th className="px-4 py-4 text-right">Rec. Bruta</th>
                <th className="px-4 py-4 text-right">Repasse</th>
                <th className="px-4 py-4 text-right">Gastos</th>
                <th className="px-4 py-4 text-right">Resultado</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {matrix.map((m) => (
                <tr key={m.nome} className="hover:bg-blue-50/30 transition-colors">
                  <td className="px-4 py-4 font-bold text-slate-700 sticky left-0 bg-white">{m.nome}</td>
                  <td className="px-4 py-4 text-right font-medium text-slate-600">R$ {m.bruta.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className="px-4 py-4 text-right text-amber-600 font-medium">R$ {m.repasse.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className="px-4 py-4 text-right text-red-500 font-medium">R$ {m.gastos.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className={`px-4 py-4 text-right font-bold ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                    R$ {m.liquido.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] bg-slate-900/50 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">Lançar Fechamento Mensal</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600"><X /></button>
            </div>

            <div className="p-6 overflow-y-auto space-y-6 flex-1">
              {/* Seção Mês */}
              <div className="grid grid-cols-1 gap-4">
                <label className="text-xs font-bold text-slate-400 uppercase">Selecione o Mês</label>
                <select 
                  className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl"
                  value={formData.mes}
                  onChange={(e) => setFormData({...formData, mes: Number(e.target.value)})}
                >
                  {meses.map((m, i) => <option key={m} value={i+1}>{m}</option>)}
                </select>
              </div>

              {/* Seção Financeiro */}
              <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                <Input label="Dinheiro" value={formData.dinheiro} onChange={(v) => setFormData({...formData, dinheiro: v})} />
                <Input label="Cartão" value={formData.cartao} onChange={(v) => setFormData({...formData, cartao: v})} />
                <Input label="Pix" value={formData.pix} onChange={(v) => setFormData({...formData, pix: v})} />
                <Input label="Assinaturas" value={formData.assinaturas} onChange={(v) => setFormData({...formData, assinaturas: v})} />
                <Input label="Pacotes" value={formData.pacotes} onChange={(v) => setFormData({...formData, pacotes: v})} />
              </div>

              {/* Produção Equipe */}
              <div>
                <h4 className="font-bold text-slate-700 mb-3 border-b pb-1">Produção Cadeira</h4>
                <div className="space-y-3">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="grid grid-cols-3 gap-2 items-center">
                      <span className="text-xs font-bold text-slate-500 truncate">{p.nome}</span>
                      <Input label="Bruto" value={p.bruta} onChange={(v) => {
                        const newProds = [...formData.producoes];
                        newProds[idx].bruta = v;
                        setFormData({...formData, producoes: newProds});
                      }} />
                      <Input label="Repasse" value={p.repasse} onChange={(v) => {
                        const newProds = [...formData.producoes];
                        newProds[idx].repasse = v;
                        setFormData({...formData, producoes: newProds});
                      }} />
                    </div>
                  ))}
                </div>
              </div>

              {/* Gastos */}
              <div>
                <h4 className="font-bold text-slate-700 mb-3 border-b pb-1">Gastos do Mês</h4>
                <div className="grid grid-cols-2 gap-4">
                  {formData.gastos.map((g, idx) => (
                    <Input key={g.categoria} label={g.categoria} value={g.valor} onChange={(v) => {
                      const newGastos = [...formData.gastos];
                      newGastos[idx].valor = v;
                      setFormData({...formData, gastos: newGastos});
                    }} />
                  ))}
                </div>
              </div>
            </div>

            <div className="p-6 bg-slate-50 border-t border-slate-100">
              <button 
                onClick={handleSaveClosing}
                className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-blue-200"
              >
                Salvar Fechamento
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const Input = ({ label, value, onChange }: any) => (
  <div>
    <label className="text-[9px] font-bold text-slate-400 uppercase">{label}</label>
    <input 
      type="number"
      value={value}
      onChange={(e) => onChange(Number(e.target.value))}
      className="w-full p-2 bg-white border border-slate-200 rounded-lg text-sm"
    />
  </div>
);

export default CashFlow;

import React, { useState } from 'react';
import { AppData, Profissional } from '../types';
import { Plus, Trash2, Edit2, Check, X } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, setData, year }) => {
  const [isEditingMetas, setIsEditingMetas] = useState(false);
  const [isAddingProf, setIsAddingProf] = useState(false);

  const producaoAno = data.producao.filter(p => p.ano === year);
  const parametros = data.parametros.find(p => p.ano === year) || data.parametros[0];

  const [localMetas, setLocalMetas] = useState({
    metaFaturamento: parametros.metaFaturamento,
    metaPorCadeira: parametros.metaPorCadeira
  });

  const [newProf, setNewProf] = useState({ nome: '', cadeira: 1 });

  const ranking = data.profissionais.map(prof => {
    const records = data.producao.filter(p => p.profissionalId === prof.id);
    const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
    const totalCasa = records.reduce((s, c) => s + c.recebidoPelaCasa, 0);
    const mesesComProducao = new Set(records.map(r => r.mes)).size || 1;
    const mediaMensal = totalProd / mesesComProducao;

    return {
      ...prof,
      totalProd,
      totalCasa,
      mediaMensal,
      percMeta: (mediaMensal / (parametros?.metaPorCadeira || 1)) * 100
    };
  }).sort((a, b) => b.totalProd - a.totalProd);

  const handleSaveMetas = () => {
    const newParams = data.parametros.map(p => 
      p.ano === year ? { ...p, ...localMetas } : p
    );
    setData({ ...data, parametros: newParams });
    setIsEditingMetas(false);
  };

  const handleAddProf = () => {
    if (!newProf.nome) return;
    const nProf: Profissional = {
      id: Math.random().toString(36).substr(2, 9),
      nome: newProf.nome,
      cadeira: newProf.cadeira,
      comissao: 50,
      ativo: true
    };
    setData({ ...data, profissionais: [...data.profissionais, nProf] });
    setIsAddingProf(false);
    setNewProf({ nome: '', cadeira: 1 });
  };

  const handleDeleteProf = (id: string) => {
    if (confirm("Deseja realmente remover este profissional? Todos os registros históricos serão mantidos, mas ele sairá da lista ativa.")) {
      setData({ ...data, profissionais: data.profissionais.filter(p => p.id !== id) });
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <header className="flex justify-between items-start">
        <div>
          <h2 className="text-2xl font-extrabold text-slate-800">Equipe e Performance</h2>
          <p className="text-sm text-slate-500">Gestão de cadeiras e metas acumuladas</p>
        </div>
        <button 
          onClick={() => setIsAddingProf(true)}
          className="bg-slate-900 text-white p-2 rounded-xl"
        >
          <Plus size={20} />
        </button>
      </header>

      {/* Seção de Metas */}
      <div className="bg-white p-6 rounded-3xl card-shadow border border-slate-100">
        <div className="flex justify-between items-center mb-4">
          <h3 className="font-bold text-slate-800 flex items-center gap-2">Configurar Metas</h3>
          {!isEditingMetas ? (
            <button onClick={() => setIsEditingMetas(true)} className="text-blue-600"><Edit2 size={16} /></button>
          ) : (
            <div className="flex gap-2">
              <button onClick={handleSaveMetas} className="text-emerald-600"><Check size={20} /></button>
              <button onClick={() => setIsEditingMetas(false)} className="text-red-500"><X size={20} /></button>
            </div>
          )}
        </div>
        <div className="grid grid-cols-2 gap-6">
          <div>
            <p className="text-[10px] text-slate-400 font-bold uppercase">Meta Anual Global</p>
            {isEditingMetas ? (
              <input 
                type="number" value={localMetas.metaFaturamento} 
                onChange={(e) => setLocalMetas({...localMetas, metaFaturamento: Number(e.target.value)})}
                className="w-full border-b-2 border-blue-500 text-lg font-bold focus:outline-none"
              />
            ) : (
              <p className="text-lg font-bold text-slate-700">R$ {parametros.metaFaturamento.toLocaleString('pt-BR')}</p>
            )}
          </div>
          <div>
            <p className="text-[10px] text-slate-400 font-bold uppercase">Meta Mensal p/ Cadeira</p>
            {isEditingMetas ? (
              <input 
                type="number" value={localMetas.metaPorCadeira} 
                onChange={(e) => setLocalMetas({...localMetas, metaPorCadeira: Number(e.target.value)})}
                className="w-full border-b-2 border-blue-500 text-lg font-bold focus:outline-none"
              />
            ) : (
              <p className="text-lg font-bold text-blue-600">R$ {parametros.metaPorCadeira.toLocaleString('pt-BR')}</p>
            )}
          </div>
        </div>
      </div>

      {isAddingProf && (
        <div className="bg-blue-50 p-6 rounded-3xl border border-blue-100 flex gap-4 items-end animate-in fade-in zoom-in">
          <div className="flex-1">
            <label className="text-[10px] font-bold text-blue-400 uppercase">Nome do Profissional</label>
            <input 
              className="w-full bg-white p-2 rounded-lg border border-blue-200 mt-1"
              value={newProf.nome}
              onChange={(e) => setNewProf({...newProf, nome: e.target.value})}
            />
          </div>
          <div>
            <label className="text-[10px] font-bold text-blue-400 uppercase">Cadeira</label>
            <input 
              type="number" className="w-16 bg-white p-2 rounded-lg border border-blue-200 mt-1"
              value={newProf.cadeira}
              onChange={(e) => setNewProf({...newProf, cadeira: Number(e.target.value)})}
            />
          </div>
          <button onClick={handleAddProf} className="bg-blue-600 text-white p-2.5 rounded-xl"><Check size={20}/></button>
          <button onClick={() => setIsAddingProf(false)} className="bg-slate-200 text-slate-500 p-2.5 rounded-xl"><X size={20}/></button>
        </div>
      )}

      <div className="space-y-4">
        {ranking.map((prof, idx) => (
          <div key={prof.id} className="bg-white p-5 rounded-3xl card-shadow border border-slate-100 flex flex-col gap-4 group relative">
            <button 
              onClick={() => handleDeleteProf(prof.id)}
              className="absolute top-4 right-4 text-slate-200 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100"
            >
              <Trash2 size={16} />
            </button>
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg ${
                  idx === 0 ? 'bg-amber-100 text-amber-600' : 
                  idx === 1 ? 'bg-slate-100 text-slate-500' :
                  idx === 2 ? 'bg-orange-100 text-orange-600' : 'bg-slate-50 text-slate-300'
                }`}>
                  {idx + 1}º
                </div>
                <div>
                  <h4 className="font-bold text-slate-800 leading-none">{prof.nome}</h4>
                  <span className="text-[10px] text-slate-400 uppercase font-bold">Cadeira {prof.cadeira}</span>
                </div>
              </div>
              <div className="text-right mr-4">
                <p className="text-[10px] text-slate-400 font-bold uppercase leading-none">Produção Histórica</p>
                <p className="text-xl font-extrabold text-slate-800">R$ {prof.totalProd.toLocaleString('pt-BR')}</p>
              </div>
            </div>

            <div className="w-full h-2 bg-slate-50 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-1000 ${prof.percMeta >= 100 ? 'bg-emerald-500' : 'bg-blue-500'}`} 
                style={{ width: `${Math.min(prof.percMeta, 100)}%` }} 
              />
            </div>

            <div className="grid grid-cols-3 gap-2">
              <div className="text-center">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Média Mês</p>
                <p className="text-xs font-bold text-slate-700">R$ {prof.mediaMensal.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
              </div>
              <div className="text-center border-x border-slate-100">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Atingimento</p>
                <p className={`text-xs font-bold ${prof.percMeta >= 100 ? 'text-emerald-600' : 'text-slate-700'}`}>{Math.round(prof.percMeta)}%</p>
              </div>
              <div className="text-center">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Retorno Casa</p>
                <p className="text-xs font-bold text-slate-700">R$ {prof.totalCasa.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Professionals;

