      id: Math.random().toString(36).substr(2, 9),
      profissionalId: selectedProf,
      data: new Date().toISOString(),
      texto: newNote
    };
    setData({
      ...data,
      meetingNotes: [...(data.meetingNotes || []), note]
    });
    setNewNote('');
  };

  const handleGenerateScript = async () => {
    if (notes.length === 0) {
      alert("Adicione algumas notas semanais antes de gerar o roteiro.");
      return;
    }

    setIsGenerating(true);
    setAiScript('');

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `
      Você é um expert em gestão de pessoas para barbearias, com abordagem pscanalítica, cristocêntrica e profundo conhecimento administrativo.

      ANALISE AS SEGUINTES NOTAS SEMANAIS DO PROFISSIONAL "${profName}":
      ${notes.map(n => `- ${new Date(n.data).toLocaleDateString()}: ${n.texto}`).join('\n')}

      CRIE UM ROTEIRO PARA A REUNIÃO MENSAL:
      1. Comece com um feedback positivo baseado nas virtudes demonstradas.
      2. Aborde os pontos de correção com sabedoria, usando analogias de gestão e valores.
      3. Defina 2 metas comportamentais e 1 técnica para o próximo mês.
      4. Termine com uma palavra de encorajamento cristocêntrica focada em servir o próximo através do ofício da barbearia.

      Seja direto, profundo e inspirador. Use tom de mentoria.
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiScript(response.text || "Erro ao processar roteiro.");
    } catch (error) {
      setAiScript("Não foi possível conectar com a IA agora.");
    } finally {
      setIsGenerating(false);
    }
  };

  const deleteNote = (id: string) => {
    setData({
      ...data,
      meetingNotes: data.meetingNotes.filter(n => n.id !== id)
    });
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-24">
      <header>
        <h2 className="text-2xl font-extrabold text-slate-800">Mentoria e Reuniões</h2>
        <p className="text-sm text-slate-500">Desenvolvimento de equipe assistido por IA</p>
      </header>

      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
        {data.profissionais.map(p => (
          <button
            key={p.id}
            onClick={() => { setSelectedProf(p.id); setAiScript(''); }}
            className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${
              selectedProf === p.id 
              ? 'bg-blue-600 border-blue-600 text-white shadow-lg' 
              : 'bg-white border-slate-200 text-slate-500'
            }`}
          >
            {p.nome}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Lado das Notas */}
        <div className="space-y-4">
          <div className="bg-white p-6 rounded-3xl card-shadow border border-slate-100">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Plus size={18} className="text-blue-500" />
              Nova Anotação Semanal
            </h3>
            <textarea
              className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm min-h-[100px] focus:outline-none focus:ring-2 focus:ring-blue-500/20"
              placeholder={`O que aconteceu com ${profName} esta semana?`}
              value={newNote}
              onChange={(e) => setNewNote(e.target.value)}
            />
            <button
              onClick={handleAddNote}
              className="w-full mt-3 bg-slate-900 text-white py-3 rounded-xl font-bold text-sm hover:bg-slate-800"
            >
              Salvar Nota
            </button>
          </div>

          <div className="space-y-3">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Histórico Recente</h3>
            {notes.length === 0 && <p className="text-center py-10 text-slate-300 text-sm italic">Nenhuma nota para este profissional.</p>}
            {notes.sort((a,b) => b.data.localeCompare(a.data)).map(note => (
              <div key={note.id} className="bg-white p-4 rounded-2xl border border-slate-100 group">
                <div className="flex justify-between items-start mb-2">
                  <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400">
                    <Calendar size={12} />
                    {new Date(note.data).toLocaleDateString('pt-BR')}
                  </div>
                  <button onClick={() => deleteNote(note.id)} className="text-slate-200 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all">
                    <Trash2 size={14} />
                  </button>
                </div>
                <p className="text-sm text-slate-600 leading-relaxed">{note.texto}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Lado da IA */}
        <div className="space-y-4">
          <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-6 rounded-3xl shadow-xl text-white">
            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 bg-white/20 rounded-xl">
                <BrainCircuit size={24} />
              </div>
              <div>
                <h3 className="font-bold leading-tight">Direcionamento de Reunião</h3>
                <p className="text-[10px] text-blue-100 uppercase font-medium tracking-wider">Expertise BarberPro AI</p>
              </div>
            </div>

            <p className="text-xs text-blue-50 mb-6 leading-relaxed">
              Consolide todas as notas semanais em um roteiro estratégico baseado em princípios de liderança e psicologia.
            </p>

            <button
              onClick={handleGenerateScript}
              disabled={isGenerating}
              className="w-full bg-white text-blue-600 py-4 rounded-2xl font-black text-sm flex items-center justify-center gap-2 hover:bg-blue-50 transition-all shadow-lg active:scale-95 disabled:opacity-50"
            >
              {isGenerating ? (
                <>
                  <Sparkles className="animate-pulse" size={18} />
                  Processando Perfil...
                </>
              ) : (
                <>
                  <BrainCircuit size={18} />
                  GERAR ROTEIRO MENSAL
                </>
              )}
            </button>
          </div>

          {aiScript && (
            <div className="bg-white p-6 rounded-3xl border-2 border-blue-50 card-shadow animate-in slide-in-from-top-4">
              <div className="flex items-center gap-2 mb-4 text-blue-600">
                <MessageSquare size={18} />
                <h4 className="font-bold">Sugerido para {profName}:</h4>
              </div>
              <div className="prose prose-slate max-w-none">
                <div className="text-sm text-slate-600 whitespace-pre-line leading-relaxed italic">
                  "{aiScript}"
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

