import React, { useState, useMemo } from 'react';
import { AppData, Profissional } from '../types';
import { Plus, Trash2, Edit2, Check, X, Brain, TrendingUp, TrendingDown, Minus } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, setData, year }) => {
  const [isEditingMetas, setIsEditingMetas] = useState(false);
  const [isAddingProf, setIsAddingProf] = useState(false);

  const parametros = data.parametros.find(p => p.ano === year) || data.parametros[0];
  const [localMetas, setLocalMetas] = useState({
    metaFaturamento: parametros.metaFaturamento,
    metaPorCadeira: parametros.metaPorCadeira
  });

  const [newProf, setNewProf] = useState({ nome: '', cadeira: 1 });

  const ranking = useMemo(() => {
    return data.profissionais.map(prof => {
      const records = data.producao.filter(p => p.profissionalId === prof.id && p.ano === year);
      const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
      const totalCasa = records.reduce((s, c) => s + c.recebidoPelaCasa, 0);
      const mesesComProducao = new Set(records.map(r => r.mes)).size || 1;
      const mediaMensal = totalProd / mesesComProducao;

      // Lógica de Insight Curto
      const percMeta = (mediaMensal / (parametros?.metaPorCadeira || 1)) * 100;
      const profNotes = data.meetingNotes?.filter(n => n.profissionalId === prof.id) || [];

      let insight = "Desempenho estável.";
      let status: 'good' | 'neutral' | 'bad' = 'neutral';

      if (percMeta >= 100) {
        insight = "Meta batida! Foco em manter o ticket médio.";
        status = 'good';
      } else if (percMeta >= 85) {
        insight = "Perto da meta. Ajustar agenda para crescer.";
        status = 'neutral';
      } else {
        insight = "Abaixo da meta. Revisar técnica e conversão.";
        status = 'bad';
      }

      // Ajusta insight com base nas notas (Simples heurística)
      const badKeywords = ['atraso', 'conflito', 'baixa', 'reclamação', 'problema'];
      const goodKeywords = ['elogio', 'meta', 'venda', 'excelente', 'pontual'];

      const noteText = profNotes.map(n => n.texto.toLowerCase()).join(' ');
      const hasBad = badKeywords.some(k => noteText.includes(k));
      const hasGood = goodKeywords.some(k => noteText.includes(k));

      if (hasBad && status !== 'good') insight = "Atenção: Notas de comportamento requerem mentoria.";
      if (hasGood && status === 'good') insight = "Excepcional: Batendo metas com ótimos feedbacks.";

      return {
        ...prof,
        totalProd,
        totalCasa,
        mediaMensal,
        percMeta,
        insight,
        status
      };
    }).sort((a, b) => b.totalProd - a.totalProd);
  }, [data.profissionais, data.producao, data.meetingNotes, year, parametros]);

  const handleSaveMetas = () => {
    const newParams = data.parametros.map(p => 
      p.ano === year ? { ...p, ...localMetas } : p
    );
    setData({ ...data, parametros: newParams });
    setIsEditingMetas(false);
  };

  const handleAddProf = () => {
    if (!newProf.nome) return;
    const nProf: Profissional = {
      id: Math.random().toString(36).substr(2, 9),
      nome: newProf.nome,
      cadeira: newProf.cadeira,
      comissao: 50,
      ativo: true
    };
    setData({ ...data, profissionais: [...data.profissionais, nProf] });
    setIsAddingProf(false);
    setNewProf({ nome: '', cadeira: 1 });
  };

  const handleDeleteProf = (id: string) => {
    if (confirm("Remover este profissional da listagem ativa? (Registros históricos serão preservados no fluxo financeiro).")) {
      setData({ ...data, profissionais: data.profissionais.filter(p => p.id !== id) });
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <header className="flex justify-between items-start">
        <div>
          <h2 className="text-2xl font-extrabold text-slate-800">Equipe e Performance</h2>
          <p className="text-sm text-slate-500">Gestão de cadeiras e análise de competência</p>
        </div>
        <button 
          onClick={() => setIsAddingProf(true)}
          className="bg-blue-600 text-white p-3 rounded-2xl shadow-lg shadow-blue-100 hover:scale-105 transition-all"
        >
          <Plus size={22} />
        </button>
      </header>

      {/* Seção de Metas */}
      <div className="bg-white p-6 rounded-3xl card-shadow border border-slate-100">
        <div className="flex justify-between items-center mb-6">
          <h3 className="font-bold text-slate-800 flex items-center gap-2">Configuração de Metas</h3>
          {!isEditingMetas ? (
            <button onClick={() => setIsEditingMetas(true)} className="text-blue-600 bg-blue-50 px-3 py-1 rounded-lg text-xs font-bold hover:bg-blue-100 transition-all flex items-center gap-1">
              <Edit2 size={14} /> Editar
            </button>
          ) : (
            <div className="flex gap-2">
              <button onClick={handleSaveMetas} className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-lg text-xs font-bold">Salvar</button>
              <button onClick={() => setIsEditingMetas(false)} className="bg-red-50 text-red-500 px-3 py-1 rounded-lg text-xs font-bold">X</button>
            </div>
          )}
        </div>
        <div className="grid grid-cols-2 gap-6">
          <div>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-1">Faturamento Anual</p>
            {isEditingMetas ? (
              <input 
                type="number" value={localMetas.metaFaturamento} 
                onChange={(e) => setLocalMetas({...localMetas, metaFaturamento: Number(e.target.value)})}
                className="w-full border-b-2 border-blue-500 text-lg font-bold focus:outline-none bg-slate-50 p-1"
              />
            ) : (
              <p className="text-lg font-bold text-slate-800">R$ {parametros.metaFaturamento.toLocaleString('pt-BR')}</p>
            )}
          </div>
          <div>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-1">Mês/Cadeira</p>
            {isEditingMetas ? (
              <input 
                type="number" value={localMetas.metaPorCadeira} 
                onChange={(e) => setLocalMetas({...localMetas, metaPorCadeira: Number(e.target.value)})}
                className="w-full border-b-2 border-blue-500 text-lg font-bold focus:outline-none bg-slate-50 p-1"
              />
            ) : (
              <p className="text-lg font-bold text-blue-600">R$ {parametros.metaPorCadeira.toLocaleString('pt-BR')}</p>
            )}
          </div>
        </div>
      </div>

      {isAddingProf && (
        <div className="bg-slate-900 text-white p-6 rounded-3xl shadow-xl flex flex-col md:flex-row gap-4 items-end animate-in fade-in zoom-in">
          <div className="flex-1 w-full">
            <label className="text-[10px] font-bold text-slate-400 uppercase">Nome Completo</label>
            <input 
              className="w-full bg-slate-800 p-3 rounded-xl border border-slate-700 mt-1 focus:ring-2 focus:ring-blue-500/50 outline-none"
              placeholder="Ex: Marcus Barber"
              value={newProf.nome}
              onChange={(e) => setNewProf({...newProf, nome: e.target.value})}
            />
          </div>
          <div className="w-full md:w-24">
            <label className="text-[10px] font-bold text-slate-400 uppercase">Cadeira</label>
            <input 
              type="number" className="w-full bg-slate-800 p-3 rounded-xl border border-slate-700 mt-1"
              value={newProf.cadeira}
              onChange={(e) => setNewProf({...newProf, cadeira: Number(e.target.value)})}
            />
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleAddProf} className="flex-1 bg-blue-600 text-white p-3 rounded-xl font-bold">Adicionar</button>
            <button onClick={() => setIsAddingProf(false)} className="bg-slate-700 text-slate-400 p-3 rounded-xl"><X size={20}/></button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {ranking.map((prof, idx) => (
          <div key={prof.id} className="bg-white p-5 rounded-3xl card-shadow border border-slate-100 flex flex-col gap-4 group relative overflow-hidden">
            <button 
              onClick={() => handleDeleteProf(prof.id)}
              className="absolute top-4 right-4 text-slate-200 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100 z-10"
            >
              <Trash2 size={16} />
            </button>

            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg ${
                idx === 0 ? 'bg-amber-100 text-amber-600' : 
                idx === 1 ? 'bg-slate-100 text-slate-400' :
                idx === 2 ? 'bg-orange-100 text-orange-600' : 'bg-slate-50 text-slate-300'
              }`}>
                {idx + 1}º
              </div>
              <div className="flex-1">
                <h4 className="font-extrabold text-slate-800 leading-none">{prof.nome}</h4>
                <p className="text-[10px] text-slate-400 uppercase font-bold mt-1">Cadeira {prof.cadeira} • Ref: {year}</p>
              </div>
            </div>

            {/* Insight Area */}
            <div className={`p-3 rounded-2xl border flex gap-3 items-start transition-all ${
              prof.status === 'good' ? 'bg-emerald-50 border-emerald-100' : 
              prof.status === 'bad' ? 'bg-red-50 border-red-100' : 
              'bg-blue-50 border-blue-100'
            }`}>
              <div className="mt-1">
                {prof.status === 'good' ? <TrendingUp size={16} className="text-emerald-500" /> : 
                 prof.status === 'bad' ? <TrendingDown size={16} className="text-red-500" /> : 
                 <Minus size={16} className="text-blue-500" />}
              </div>
              <p className={`text-xs font-bold leading-relaxed ${
                prof.status === 'good' ? 'text-emerald-700' : 
                prof.status === 'bad' ? 'text-red-700' : 
                'text-blue-700'
              }`}>
                {prof.insight}
              </p>
            </div>

            <div className="space-y-3">
              <div className="flex justify-between items-end">
                <span className="text-[10px] font-black text-slate-300 uppercase">Atingimento de Meta</span>
                <span className={`text-xs font-black ${prof.percMeta >= 100 ? 'text-emerald-600' : 'text-slate-600'}`}>
                  {Math.round(prof.percMeta)}%
                </span>
              </div>
              <div className="w-full h-2 bg-slate-50 rounded-full overflow-hidden">
                <div 
                  className={`h-full transition-all duration-1000 ${prof.percMeta >= 100 ? 'bg-emerald-500' : 'bg-blue-600'}`} 
                  style={{ width: `${Math.min(prof.percMeta, 100)}%` }} 
                />
              </div>
            </div>

            <div className="grid grid-cols-3 gap-2 pt-2 border-t border-slate-50">
              <div className="text-center">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Produção</p>
                <p className="text-xs font-black text-slate-800">R$ {prof.totalProd.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
              </div>
              <div className="text-center border-x border-slate-100 px-1">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Média Mês</p>
                <p className="text-xs font-black text-slate-800">R$ {prof.mediaMensal.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
              </div>
              <div className="text-center">
                <p className="text-[9px] text-slate-400 uppercase font-bold">Retorno Casa</p>
                <p className="text-xs font-black text-emerald-600">R$ {prof.totalCasa.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

