              <div>
                <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 px-3 py-1 rounded-full">Raio-X do Mês</span>
                <h3 className="text-3xl font-black text-slate-800 mt-2">{selectedMonthSummary.nome} {year}</h3>
              </div>
              <button onClick={() => setShowSummaryModal(false)} className="bg-white p-3 rounded-full shadow-sm text-slate-400 hover:text-slate-600 transition-all">
                <X size={24} />
              </button>
