                <SummaryMiniCard label="Custo Operacional" value={selectedMonthSummary.gastosTotal} icon={Wallet} color="bg-red-500" />
                <SummaryMiniCard label="Repasse Equipe" value={selectedMonthSummary.repasse} icon={Users} color="bg-amber-500" />
                <SummaryMiniCard label="Lucro Líquido" value={selectedMonthSummary.liquido} icon={DollarSign} color="bg-emerald-600" />
