              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Entradas Detalhadas */}
                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <h4 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                    <PieIcon size={18} className="text-blue-600" /> Distribuição de Entradas
                  </h4>
                  <div className="space-y-4">
                    <EntryRow label="Dinheiro" value={selectedMonthSummary.extra?.dinheiro || 0} total={selectedMonthSummary.bruta} color="bg-emerald-400" />
                    <EntryRow label="Cartão" value={selectedMonthSummary.extra?.cartao || 0} total={selectedMonthSummary.bruta} color="bg-blue-500" />
                    <EntryRow label="Pix" value={selectedMonthSummary.extra?.pix || 0} total={selectedMonthSummary.bruta} color="bg-cyan-400" />
                    <EntryRow label="Assinaturas" value={selectedMonthSummary.extra?.assinaturas || 0} total={selectedMonthSummary.bruta} color="bg-indigo-500" />
                    <EntryRow label="Pacotes" value={selectedMonthSummary.extra?.pacotes || 0} total={selectedMonthSummary.bruta} color="bg-purple-500" />
                  </div>
