      )}

      {/* Modal Categorias Fixas */}
      {showCatModal && (
        <div className="fixed inset-0 z-[110] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800">Categorias Fixas</h3>
              <button onClick={() => setShowCatModal(false)} className="text-slate-400 hover:text-slate-600"><X /></button>
            </div>
            <div className="space-y-4">
              <div className="flex gap-2">
                <input 
                  type="text" placeholder="Nome da categoria..."
                  className="flex-1 p-3 bg-slate-50 border border-slate-100 rounded-xl text-sm"
                  value={newCatName} onChange={(e) => setNewCatName(e.target.value)}
                />
                <button onClick={handleAddCategory} className="bg-blue-600 text-white p-3 rounded-xl"><Plus size={20} /></button>
              </div>
              <div className="max-h-[300px] overflow-y-auto space-y-2">
                {data.categoriasGastos.map(cat => (
                  <div key={cat} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                    <span className="text-sm font-medium text-slate-700">{cat}</span>
                    <button onClick={() => handleRemoveCategory(cat)} className="text-slate-300 hover:text-red-500"><Trash2 size={16} /></button>
                  </div>
                ))}
              </div>
              <button onClick={() => setShowCatModal(false)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold">Fechar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const Input = ({ label, value, onChange }: any) => (
  <div className="space-y-1">
    <label className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">{label}</label>
    <div className="relative">
      <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[10px] text-slate-300 font-bold">R$</span>
      <input 
        type="number"
        value={value === 0 ? '' : value}
        onChange={(e) => onChange(e.target.value === '' ? 0 : Number(e.target.value))}
        className="w-full pl-7 pr-2 py-2 bg-white border border-slate-200 rounded-xl text-sm font-medium focus:ring-2 focus:ring-blue-500/10 focus:outline-none transition-all"
      />
    </div>
  </div>
);

const SummaryMiniCard = ({ label, value, icon: Icon, color }: any) => (
  <div className="bg-white p-4 rounded-3xl shadow-sm border border-slate-100">
    <div className={`w-10 h-10 ${color} text-white rounded-2xl flex items-center justify-center mb-3`}>
      <Icon size={20} />
    </div>
    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{label}</p>
    <p className="text-lg font-black text-slate-800">R$ {value.toLocaleString('pt-BR')}</p>
  </div>
);

const EntryRow = ({ label, value, total, color }: any) => {
  const percentage = total > 0 ? (value / total) * 100 : 0;
  return (
    <div className="space-y-1">
      <div className="flex justify-between text-[10px] font-bold text-slate-600">
        <span>{label}</span>
        <span>R$ {value.toLocaleString('pt-BR')} ({Math.round(percentage)}%)</span>
      </div>
      <div className="w-full h-1.5 bg-white rounded-full overflow-hidden">
        <div className={`h-full ${color} transition-all duration-700`} style={{ width: `${percentage}%` }} />
      </div>
    </div>
  );
};

export default CashFlow;

