import React, { useState, useEffect } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal } from '../types';
import { PlusCircle, X, Settings2, Trash2, Plus, Save, Edit2, Eye, TrendingUp, DollarSign, Wallet, Users, PieChart as PieIcon, Trophy, Star } from 'lucide-react';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showCatModal, setShowCatModal] = useState(false);
  const [showSummaryModal, setShowSummaryModal] = useState(false);
  const [selectedMonthSummary, setSelectedMonthSummary] = useState<any>(null);

  const [newCatName, setNewCatName] = useState('');
  const [extraCatName, setExtraCatName] = useState('');
  const [extraCatValue, setExtraCatValue] = useState<number | ''>('');

  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, 
          nome: prof.nome, 
          bruta: p?.producaoBruta || 0, 
          repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0 
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0,
        cartao: extra?.cartao || 0,
        pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0,
        pacotes: extra?.pacotes || 0,
        producoes: prods,
        gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;

    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  });

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year,
      mes: formData.mes,
      dinheiro: formData.dinheiro,
      cartao: formData.cartao,
      pix: formData.pix,
      assinaturas: formData.assinaturas,
      pacotes: formData.pacotes,
      geladeira: 0,
      outras: 0
    };

    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year,
      mes: formData.mes,
      profissionalId: p.id,
      producaoBruta: p.bruta,
      repasseProfissional: p.repasse,
      repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura
    }));

    const newGastos: GastoMensal[] = formData.gastos.map(g => ({
      ano: year,
      mes: formData.mes,
      categoria: g.categoria,
      valor: g.valor
    }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });

    setShowModal(false);
    alert('Registros salvos com sucesso!');
  };

  const handleAddExtraGasto = () => {
    if (!extraCatName || !extraCatValue) return;
    setFormData(prev => ({
      ...prev,
      gastos: [...prev.gastos, { categoria: extraCatName, valor: Number(extraCatValue) }]
    }));
    if (!data.categoriasGastos.includes(extraCatName)) {
      if (confirm(`Deseja salvar "${extraCatName}" como uma categoria permanente?`)) {
        setData({ ...data, categoriasGastos: [...data.categoriasGastos, extraCatName] });
      }
    }
    setExtraCatName('');
    setExtraCatValue('');
  };

  const handleAddCategory = () => {
    if (!newCatName || data.categoriasGastos.includes(newCatName)) return;
    setData({ ...data, categoriasGastos: [...data.categoriasGastos, newCatName] });
    setNewCatName('');
  };

  const handleRemoveCategory = (cat: string) => {
    if (confirm(`Remover categoria "${cat}"?`)) {
      setData({ ...data, categoriasGastos: data.categoriasGastos.filter(c => c !== cat) });
    }
  };

  const openSummary = (monthData: any) => {
    const profDetails = data.profissionais.map(p => {
      const prod = monthData.prod.find((pr: any) => pr.profissionalId === p.id);
      return {
        nome: p.nome,
        bruta: prod?.producaoBruta || 0,
        recebido: (prod?.repasseProfissional || 0) + (prod?.repasseAssinatura || 0)
      };
    }).sort((a, b) => b.bruta - a.bruta);

    const highlight = profDetails[0];

    setSelectedMonthSummary({ ...monthData, profDetails, highlight });
    setShowSummaryModal(true);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-extrabold text-slate-800">Fluxo Consolidado</h2>
          <p className="text-xs text-slate-400">Gerenciamento financeiro mensal detalhado</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setShowCatModal(true)}
            className="flex items-center gap-2 bg-slate-100 text-slate-600 px-4 py-2 rounded-xl font-bold text-sm hover:bg-slate-200 transition-all"
          >
            <Settings2 size={18} />
            Categorias Fixas
          </button>
          <button 
            onClick={() => setShowModal(true)}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-xl font-bold text-sm hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
          >
            <PlusCircle size={18} />
            Novo Lançamento
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-[10px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-4 py-4 sticky left-0 bg-slate-50">Mês</th>
                <th className="px-4 py-4 text-right">Rec. Bruta</th>
                <th className="px-4 py-4 text-right">Repasse</th>
                <th className="px-4 py-4 text-right">Gastos</th>
                <th className="px-4 py-4 text-right">Resultado</th>
                <th className="px-4 py-4 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {matrix.map((m) => (
                <tr key={m.nome} className="hover:bg-blue-50/30 transition-colors group">
                  <td className="px-4 py-4 font-bold text-slate-700 sticky left-0 bg-white">
                    <div className="flex items-center gap-2">
                      {m.nome}
                      <button onClick={() => openSummary(m)} className="p-1.5 bg-blue-50 text-blue-600 rounded-lg opacity-0 group-hover:opacity-100 transition-all flex items-center gap-1 text-[10px] font-bold">
                        <Eye size={12} /> VER MÊS
                      </button>
                    </div>
                  </td>
                  <td className="px-4 py-4 text-right font-medium text-slate-600">R$ {m.bruta.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className="px-4 py-4 text-right text-amber-600 font-medium">R$ {m.repasse.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className="px-4 py-4 text-right text-red-500 font-medium">R$ {m.gastosTotal.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</td>
                  <td className={`px-4 py-4 text-right font-bold ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                    R$ {m.liquido.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}
                  </td>
                  <td className="px-4 py-4 text-center">
                    <button 
                      onClick={() => {
                        setFormData(prev => ({ ...prev, mes: m.mes }));
                        setShowModal(true);
                      }}
                      className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                    >
                      <Edit2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal Raio-X do Mês */}
      {showSummaryModal && selectedMonthSummary && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[40px] shadow-2xl overflow-hidden max-h-[95vh] flex flex-col animate-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <div>
                <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 px-3 py-1 rounded-full">Painel Mensal Detalhado</span>
                <h3 className="text-3xl font-black text-slate-800 mt-2">{selectedMonthSummary.nome} {year}</h3>
              </div>
              <button onClick={() => setShowSummaryModal(false)} className="bg-white p-3 rounded-full shadow-sm text-slate-400 hover:text-slate-600 transition-all">
                <X size={24} />
              </button>
            </div>

            <div className="p-8 overflow-y-auto flex-1 space-y-8">
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <SummaryMiniCard label="Faturamento" value={selectedMonthSummary.bruta} icon={TrendingUp} color="bg-blue-600" />
                <SummaryMiniCard label="Gastos Cat." value={selectedMonthSummary.gastosTotal} icon={Wallet} color="bg-red-500" />
                <SummaryMiniCard label="Repasse Equipe" value={selectedMonthSummary.repasse} icon={Users} color="bg-amber-500" />
                <SummaryMiniCard label="Saldo Líquido" value={selectedMonthSummary.liquido} icon={DollarSign} color="bg-emerald-600" />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Ranking e Destaque */}
                <div className="space-y-6">
                  <div className="bg-amber-50 p-6 rounded-[32px] border border-amber-100 flex items-center gap-6 relative overflow-hidden">
                    <Trophy className="absolute -right-4 -bottom-4 text-amber-200 w-32 h-32 opacity-20" />
                    <div className="w-20 h-20 bg-amber-400 rounded-3xl flex items-center justify-center text-white shadow-xl shadow-amber-200">
                      <Star size={40} fill="currentColor" />
                    </div>
                    <div className="relative z-10">
                      <p className="text-[10px] font-black text-amber-600 uppercase">Destaque do Mês</p>
                      <h4 className="text-2xl font-black text-amber-900">{selectedMonthSummary.highlight?.nome}</h4>
                      <p className="text-sm font-bold text-amber-700">R$ {selectedMonthSummary.highlight?.bruta.toLocaleString('pt-BR')} em serviços</p>
                    </div>
                  </div>

                  <div className="bg-white p-6 rounded-[32px] border border-slate-100 card-shadow">
                    <h4 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                      <Trophy size={18} className="text-amber-500" /> Ranking de Produção
                    </h4>
                    <div className="space-y-3">
                      {selectedMonthSummary.profDetails.map((p: any, idx: number) => (
                        <div key={p.nome} className="flex items-center justify-between p-3 bg-slate-50 rounded-2xl">
                          <div className="flex items-center gap-3">
                            <span className="w-6 h-6 flex items-center justify-center rounded-full bg-slate-200 text-[10px] font-black">{idx + 1}º</span>
                            <span className="text-xs font-bold text-slate-700">{p.nome}</span>
                          </div>
                          <div className="text-right">
                            <p className="text-xs font-black text-slate-800">R$ {p.bruta.toLocaleString('pt-BR')}</p>
                            <p className="text-[9px] text-slate-400 font-bold">Ganho: R$ {p.recebido.toLocaleString('pt-BR')}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                {/* Gastos por Categoria */}
                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <h4 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
                    <PieIcon size={18} className="text-blue-600" /> Onde o dinheiro foi gasto
                  </h4>
                  <div className="space-y-4">
                    {selectedMonthSummary.gastosList.length === 0 && <p className="text-xs text-slate-400 italic text-center py-10">Nenhum gasto detalhado.</p>}
                    {selectedMonthSummary.gastosList.sort((a: any, b: any) => b.valor - a.valor).map((g: any) => (
                      <div key={g.categoria} className="space-y-1">
                        <div className="flex justify-between text-[10px] font-bold text-slate-600">
                          <span>{g.categoria}</span>
                          <span>R$ {g.valor.toLocaleString('pt-BR')}</span>
                        </div>
                        <div className="w-full h-1.5 bg-white rounded-full overflow-hidden">
                          <div 
                            className="h-full bg-red-400 transition-all duration-700" 
                            style={{ width: `${(g.valor / selectedMonthSummary.gastosTotal) * 100}%` }} 
                          />
