import React, { useState, useMemo } from 'react';
import { AppData, Profissional, ProfissionalPerfil } from '../types';
import { Plus, Trash2, Edit2, X, TrendingUp, TrendingDown, Minus, Wallet, BrainCircuit, Info, Scissors, Star, Banknote } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, setData, year }) => {
  const [isAddingProf, setIsAddingProf] = useState(false);
  const [newProf, setNewProf] = useState({ nome: '', cadeira: 1 });
  const [newPerfil, setNewPerfil] = useState<ProfissionalPerfil>({
    experiencia: '',
    perfilComportamental: '',
    especialidade: '',
    objetivo: ''
  });

  const ranking = useMemo(() => {
    const parametros = data.parametros.find(p => p.ano === year) || data.parametros[0];
    return data.profissionais.map(prof => {
      const records = data.producao.filter(p => p.profissionalId === prof.id && p.ano === year);
      const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
      const totalServico = records.reduce((s, c) => s + c.repasseProfissional, 0);
      const totalAssinatura = records.reduce((s, c) => s + c.repasseAssinatura, 0);
      const totalGanhoProf = totalServico + totalAssinatura;
      const totalCasa = records.reduce((s, c) => s + c.recebidoPelaCasa, 0);

      const mesesComProducao = new Set(records.map(r => r.mes)).size || 1;
      const mediaMensal = totalProd / mesesComProducao;

      const percMeta = (mediaMensal / (parametros?.metaPorCadeira || 1)) * 100;
      const profNotes = data.meetingNotes?.filter(n => n.profissionalId === prof.id) || [];

      let insight = "Desempenho estável.";
      let status: 'good' | 'neutral' | 'bad' = 'neutral';

      if (percMeta >= 100) { status = 'good'; insight = "Excepcional! Batendo metas e gerando lucro."; }
      else if (percMeta >= 80) { status = 'neutral'; insight = "Consistente. Ajustar detalhes para o próximo nível."; }
      else { status = 'bad'; insight = "Alerta: Necessita de acompanhamento técnico/comercial."; }

      return {
        ...prof,
        totalProd,
        totalServico,
        totalAssinatura,
        totalGanhoProf,
        totalCasa,
        percMeta,
        insight,
        status
      };
    }).sort((a, b) => b.totalProd - a.totalProd);
  }, [data.profissionais, data.producao, data.meetingNotes, year, data.parametros]);

  const handleAddProf = () => {
    if (!newProf.nome) return;
    const nProf: Profissional = {
      id: Math.random().toString(36).substr(2, 9),
      nome: newProf.nome,
      cadeira: newProf.cadeira,
      comissao: 50,
      ativo: true,
      perfil: newPerfil
    };
    setData({ ...data, profissionais: [...data.profissionais, nProf] });
    setIsAddingProf(false);
    setNewProf({ nome: '', cadeira: 1 });
    setNewPerfil({ experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const handleDeleteProf = (id: string) => {
    if (confirm("Remover este profissional?")) {
      setData({ ...data, profissionais: data.profissionais.filter(p => p.id !== id) });
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Equipe & Performance</h2>
          <p className="text-sm text-slate-500 font-medium">Análise financeira e perfil individual</p>
        </div>
        <button onClick={() => setIsAddingProf(true)} className="bg-blue-600 text-white flex items-center gap-2 px-6 py-3 rounded-2xl shadow-xl shadow-blue-100 hover:scale-105 transition-all font-bold">
          <Plus size={20} /> ADICIONAR BARBEIRO
        </button>
      </header>

      {/* Modal Adicionar Profissional com Captador IA */}
      {isAddingProf && (
        <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <div>
                <h3 className="text-2xl font-black text-slate-800">Novo Barbeiro</h3>
                <p className="text-xs text-blue-600 font-bold uppercase tracking-widest">Preencha o perfil para a inteligência de mentoria</p>
              </div>
              <button onClick={() => setIsAddingProf(false)} className="bg-white p-2 rounded-full text-slate-400 hover:text-slate-600 shadow-sm"><X /></button>
            </div>

            <div className="p-8 overflow-y-auto max-h-[70vh] space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome do Profissional</label>
                  <input className="w-full bg-slate-50 border border-slate-100 p-3 rounded-2xl text-sm focus:ring-2 focus:ring-blue-500/20" value={newProf.nome} onChange={(e) => setNewProf({...newProf, nome: e.target.value})} placeholder="Ex: Ricardo Navalha" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cadeira / Unidade</label>
                  <input type="number" className="w-full bg-slate-50 border border-slate-100 p-3 rounded-2xl text-sm" value={newProf.cadeira} onChange={(e) => setNewProf({...newProf, cadeira: Number(e.target.value)})} />
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex items-center gap-2 text-blue-600 font-bold text-sm">
                  <BrainCircuit size={18} /> Perfil Comportamental (Captador IA)
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <InputArea label="Tempo de experiência e onde trabalhou?" value={newPerfil.experiencia} onChange={(v) => setNewPerfil({...newPerfil, experiencia: v})} />
                  <InputArea label="Como se define como pessoa? (Temperamento)" value={newPerfil.perfilComportamental} onChange={(v) => setNewPerfil({...newPerfil, perfilComportamental: v})} />
                  <InputArea label="Qual sua principal especialidade técnica?" value={newPerfil.especialidade} onChange={(v) => setNewPerfil({...newPerfil, especialidade: v})} />
                  <InputArea label="Qual seu maior objetivo na barbearia?" value={newPerfil.objetivo} onChange={(v) => setNewPerfil({...newPerfil, objetivo: v})} />
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t border-slate-100 flex gap-4">
              <button onClick={() => setIsAddingProf(false)} className="flex-1 bg-white border border-slate-200 py-4 rounded-3xl font-bold text-slate-600">Cancelar</button>
              <button onClick={handleAddProf} className="flex-[2] bg-blue-600 text-white py-4 rounded-3xl font-black shadow-lg shadow-blue-100">SALVAR E INICIAR BARBEIRO</button>
            </div>
          </div>
        </div>
      )}

      {/* Cards de Profissionais */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {ranking.map((prof, idx) => (
          <div key={prof.id} className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden flex flex-col group relative">
            <button onClick={() => handleDeleteProf(prof.id)} className="absolute top-6 right-6 text-slate-200 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all z-10"><Trash2 size={20} /></button>

            <div className="p-8 pb-4 flex items-center gap-6">
              <div className={`w-20 h-20 rounded-3xl flex items-center justify-center font-black text-3xl shadow-inner ${
                idx === 0 ? 'bg-amber-100 text-amber-600' : idx === 1 ? 'bg-slate-100 text-slate-400' : 'bg-slate-50 text-slate-300'
              }`}>
                {idx + 1}º
              </div>
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <h4 className="text-2xl font-black text-slate-800 tracking-tighter">{prof.nome}</h4>
                  {prof.perfil?.perfilComportamental && <div className="p-1 bg-blue-50 text-blue-500 rounded-full" title="Perfil IA Configurado"><BrainCircuit size={14} /></div>}
                </div>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Cadeira {prof.cadeira} • Ref: {year}</p>
              </div>
            </div>

            <div className="px-8 pb-8 space-y-6">
              <div className={`p-4 rounded-3xl flex gap-3 items-center ${prof.status === 'good' ? 'bg-emerald-50 text-emerald-700' : prof.status === 'bad' ? 'bg-red-50 text-red-700' : 'bg-blue-50 text-blue-700'}`}>
                {prof.status === 'good' ? <TrendingUp size={18} /> : prof.status === 'bad' ? <TrendingDown size={18} /> : <Minus size={18} />}
                <p className="text-xs font-black">{prof.insight}</p>
              </div>

              {/* Grid Financeiro Detalhado */}
              <div className="grid grid-cols-2 gap-3">
                <MiniStats label="Produção Bruta" value={prof.totalProd} icon={Scissors} />
                <MiniStats label="Repasse Serviços" value={prof.totalServico} icon={Banknote} />
                <MiniStats label="Repasse Assinatura" value={prof.totalAssinatura} icon={Star} />
                <MiniStats label="Recebimento Total" value={prof.totalGanhoProf} icon={Wallet} primary />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <span>Eficiência de Meta</span>
                  <span>{Math.round(prof.percMeta)}%</span>
                </div>
                <div className="w-full h-2 bg-slate-50 rounded-full overflow-hidden">
                  <div className={`h-full transition-all duration-1000 ${prof.status === 'good' ? 'bg-emerald-500' : 'bg-blue-600'}`} style={{ width: `${Math.min(prof.percMeta, 100)}%` }} />
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const InputArea = ({ label, value, onChange }: any) => (
  <div className="space-y-1">
    <label className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{label}</label>
    <textarea className="w-full bg-white border border-slate-200 p-3 rounded-2xl text-xs min-h-[70px] focus:ring-2 focus:ring-blue-500/20 outline-none" value={value} onChange={(e) => onChange(e.target.value)} />
  </div>
