export default Professionals;

import React, { useState } from 'react';
import { AppData, MeetingNote } from '../types';
import { GoogleGenAI } from "@google/genai";
import { MessageSquare, Plus, BrainCircuit, Trash2, Calendar, Sparkles, UserCircle } from 'lucide-react';

interface MeetingsProps {
  data: AppData;
  setData: (data: AppData) => void;
}

const Meetings: React.FC<MeetingsProps> = ({ data, setData }) => {
  const [selectedProfId, setSelectedProfId] = useState(data.profissionais[0]?.id || '');
  const [newNote, setNewNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiScript, setAiScript] = useState('');

  const selectedProf = data.profissionais.find(p => p.id === selectedProfId);
  const notes = data.meetingNotes?.filter(n => n.profissionalId === selectedProfId) || [];

  const handleAddNote = () => {
    if (!newNote) return;
    const note: MeetingNote = {
      id: Math.random().toString(36).substr(2, 9),
      profissionalId: selectedProfId,
      data: new Date().toISOString(),
      texto: newNote
    };
    setData({ ...data, meetingNotes: [...(data.meetingNotes || []), note] });
    setNewNote('');
  };

  const handleGenerateScript = async () => {
    if (notes.length === 0) {
      alert("Adicione algumas notas semanais antes.");
      return;
    }

    setIsGenerating(true);
    setAiScript('');

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Preparando contexto do perfil para a IA
    const perfilContext = selectedProf?.perfil ? `
      CONTEXTO DO BARBEIRO:
      - Experiência: ${selectedProf.perfil.experiencia}
      - Perfil Comportamental/Temperamento: ${selectedProf.perfil.perfilComportamental}
      - Especialidade: ${selectedProf.perfil.especialidade}
      - Objetivo: ${selectedProf.perfil.objetivo}
    ` : 'Sem perfil comportamental detalhado.';

    const prompt = `
      Você é um expert em gestão de pessoas para barbearias, com abordagem pscanalítica, cristocêntrica e profundo conhecimento administrativo.

      ${perfilContext}

      NOTAS SEMANAIS RECENTES DE "${selectedProf?.nome}":
      ${notes.map(n => `- ${new Date(n.data).toLocaleDateString()}: ${n.texto}`).join('\n')}

      CRIE UM ROTEIRO PARA A REUNIÃO MENSAL:
      1. Comece com um feedback positivo que ressoe com o PERFIL dele.
      2. Aborde os pontos de correção com sabedoria, usando analogias que ele entenda (baseado na especialidade/experiência).
      3. Defina metas comportamentais alinhadas ao OBJETIVO dele.
      4. Termine com uma palavra de encorajamento cristocêntrica.

      Use um tom de mentoria inspirador e firme.
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiScript(response.text || "Erro ao processar roteiro.");
    } catch (error) {
      setAiScript("Não foi possível conectar com a IA agora.");
    } finally {
      setIsGenerating(false);
    }
  };

  const deleteNote = (id: string) => {
    setData({ ...data, meetingNotes: data.meetingNotes.filter(n => n.id !== id) });
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-24">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Mentoria Assistida</h2>
        <p className="text-sm text-slate-500 font-medium">Use as anotações para gerar feedback de alto impacto</p>
      </header>

      <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide">
        {data.profissionais.map(p => (
          <button
            key={p.id}
            onClick={() => { setSelectedProfId(p.id); setAiScript(''); }}
            className={`px-6 py-3 rounded-2xl text-xs font-black whitespace-nowrap transition-all border ${
              selectedProfId === p.id 
              ? 'bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-100 scale-105' 
              : 'bg-white border-slate-100 text-slate-400'
            }`}
          >
            {p.nome}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          {/* Card de Perfil Resumido */}
          {selectedProf?.perfil?.perfilComportamental && (
            <div className="bg-white p-6 rounded-[32px] border border-blue-50 shadow-sm flex items-start gap-4">
              <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl"><UserCircle size={24} /></div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Perfil Reconhecido</p>
                <p className="text-sm font-bold text-slate-700 leading-relaxed mt-1">{selectedProf.perfil.perfilComportamental}</p>
              </div>
            </div>
          )}

          <div className="bg-white p-8 rounded-[40px] card-shadow border border-slate-50">
            <h3 className="font-black text-slate-800 mb-6 flex items-center gap-2">
              <Plus size={20} className="text-blue-500" /> Nova Anotação
            </h3>
            <textarea
              className="w-full bg-slate-50 border border-slate-50 rounded-[32px] p-6 text-sm min-h-[120px] focus:ring-2 focus:ring-blue-500/10 outline-none"
              placeholder={`Notas sobre o comportamento e produção de ${selectedProf?.nome}...`}
              value={newNote}
              onChange={(e) => setNewNote(e.target.value)}
            />
            <button onClick={handleAddNote} className="w-full mt-4 bg-slate-900 text-white py-4 rounded-2xl font-black text-sm hover:bg-slate-800 shadow-xl transition-all">SALVAR ANOTAÇÃO</button>
          </div>

          <div className="space-y-4">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest px-4">Histórico de Mentoria</h3>
