import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { AppData } from '../types';
import { TrendingUp, DollarSign, Star, Coffee, Trophy, ArrowUpCircle, ArrowDownCircle, Crown, ShoppingBag, Scissors, Target } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const calculations = useMemo(() => {
    const params = data.parametros.find(p => p.ano === year) || data.parametros[0];
    const metaMensal = (params?.metaFaturamento || 0) / 12;

    const producaoAno = data.producao.filter(p => p.ano === year);
    const receitasExtrasAno = data.receitasExtras.filter(r => r.ano === year);
    const gastosAno = data.gastos.filter(g => g.ano === year);

    const entServicos = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0);
    const entProdutos = receitasExtrasAno.reduce((acc, curr) => acc + curr.pacotes, 0);
    const entAssinaturas = receitasExtrasAno.reduce((acc, curr) => acc + curr.assinaturas, 0);
    const entGeladeira = receitasExtrasAno.reduce((acc, curr) => acc + curr.geladeira, 0);
    const faturamentoAnual = entServicos + entProdutos + entAssinaturas + entGeladeira;

    const saidaGastos = gastosAno.reduce((acc, curr) => acc + curr.valor, 0);
    const saidaRepasses = producaoAno.reduce((acc, curr) => acc + curr.repasseProfissional + curr.repasseAssinatura, 0);
    const saidaTotal = saidaGastos + saidaRepasses;
    const saldoFinal = faturamentoAnual - saidaTotal;

    // Dados para Gráfico Meta x Realidade
    const meses = Array.from({ length: 12 }, (_, i) => {
      const mes = i + 1;
      const pMes = producaoAno.filter(p => p.mes === mes);
      const eMes = receitasExtrasAno.find(r => r.mes === mes);
      const gMes = gastosAno.filter(g => g.mes === mes).reduce((s, c) => s + c.valor, 0);

      const real = pMes.reduce((s, c) => s + c.producaoBruta, 0) + (eMes?.pacotes || 0) + (eMes?.assinaturas || 0) + (eMes?.geladeira || 0);
      const repasse = pMes.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
      const lucro = real - repasse - gMes;

      return { 
        name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i], 
        Real: real, 
        Meta: metaMensal,
        lucro 
      };
    });

    const melhorMesObj = [...meses].sort((a, b) => b.lucro - a.lucro)[0];

    // Ranking Profissionais
    const ranking = data.profissionais.map(prof => ({
      nome: prof.nome,
      total: data.producao.filter(p => p.ano === year && p.profissionalId === prof.id).reduce((s, c) => s + c.producaoBruta, 0)
    })).sort((a, b) => b.total - a.total);

    return { entServicos, entProdutos, entAssinaturas, entGeladeira, faturamentoAnual, saidaTotal, saldoFinal, meses, melhorMesObj, ranking, metaMensal };
  }, [data, year]);

  const { entServicos, entProdutos, entAssinaturas, entGeladeira, faturamentoAnual, saidaTotal, saldoFinal, meses, melhorMesObj, ranking, metaMensal } = calculations;

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      {/* Banner Principal Faturamento */}
      <div className="bg-slate-900 rounded-[40px] p-8 text-white relative overflow-hidden shadow-2xl shadow-blue-200">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/20 rounded-full -mr-20 -mt-20 blur-3xl"></div>
        <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="text-center md:text-left">
            <p className="text-blue-400 text-xs font-black uppercase tracking-[0.2em] mb-2">Faturamento Consolidado {year}</p>
            <h1 className="text-5xl md:text-6xl font-black tracking-tighter">
              R$ {faturamentoAnual.toLocaleString('pt-BR')}
            </h1>
          </div>
          <div className="flex gap-4">
            <div className="bg-white/10 backdrop-blur-md p-4 rounded-3xl border border-white/10 text-center min-w-[140px]">
              <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Melhor Mês</p>
              <div className="flex items-center justify-center gap-2">
                <Crown size={16} className="text-amber-400" />
                <span className="font-black text-lg">{melhorMesObj.name}</span>
              </div>
            </div>
            <div className="bg-emerald-500 p-4 rounded-3xl text-center min-w-[140px] shadow-lg shadow-emerald-500/20">
              <p className="text-[10px] text-emerald-100 uppercase font-bold mb-1">Saldo Final</p>
              <p className="font-black text-lg">R$ {saldoFinal.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
            </div>
          </div>
        </div>
      </div>

      {/* Grid de Entradas e Saídas */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 grid grid-cols-2 gap-4">
          <EntryCard label="Serviços" value={entServicos} icon={Scissors} color="text-blue-600" bg="bg-blue-50" />
          <EntryCard label="Venda de Produtos" value={entProdutos} icon={ShoppingBag} color="text-purple-600" bg="bg-purple-50" />
          <EntryCard label="Assinaturas" value={entAssinaturas} icon={Star} color="text-amber-500" bg="bg-amber-50" />
          <EntryCard label="Geladeira" value={entGeladeira} icon={Coffee} color="text-cyan-600" bg="bg-cyan-50" />
        </div>

        <div className="bg-white p-6 rounded-[32px] border border-red-50 flex flex-col justify-center text-center shadow-sm">
          <div className="w-12 h-12 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center mx-auto mb-4">
            <ArrowDownCircle size={24} />
          </div>
          <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Saída Total</p>
          <h3 className="text-3xl font-black text-slate-800 mb-2">R$ {saidaTotal.toLocaleString('pt-BR')}</h3>
          <p className="text-[10px] text-slate-400 px-4 leading-relaxed">Soma de repasses aos barbeiros + despesas operacionais da casa.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Realidade x Meta */}
        <div className="md:col-span-2 bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-8">
            <div>
              <h3 className="font-black text-slate-800 text-xl flex items-center gap-2">
                <Target size={20} className="text-blue-600" /> Realidade x Meta
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Comparativo de performance mensal</p>
            </div>
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-blue-600 rounded-sm"></div>
                <span className="text-[10px] font-bold text-slate-500 uppercase">Real</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-slate-200 rounded-sm"></div>
                <span className="text-[10px] font-bold text-slate-500 uppercase">Meta</span>
              </div>
            </div>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={meses}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 'bold'}} />
                <YAxis hide />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)'}}
                  formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`}
                />
                <Bar dataKey="Real" fill="#2563eb" radius={[4, 4, 0, 0]} barSize={20} />
                <Bar dataKey="Meta" fill="#e2e8f0" radius={[4, 4, 0, 0]} barSize={20} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Novo Ranking Visual */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 text-xl mb-6 flex items-center gap-2">
            <Trophy size={20} className="text-amber-500" /> Top Performance
          </h3>
          <div className="space-y-4">
            {ranking.slice(0, 5).map((prof, idx) => (
              <div key={prof.nome} className="group">
                <div className="flex justify-between items-end mb-1">
                  <div className="flex items-center gap-3">
                    <span className={`w-6 h-6 rounded-lg flex items-center justify-center text-[10px] font-black ${
                      idx === 0 ? 'bg-amber-400 text-white' : idx === 1 ? 'bg-slate-300 text-white' : 'bg-slate-100 text-slate-400'
                    }`}>
                      {idx + 1}º
                    </span>
                    <span className="text-sm font-bold text-slate-700">{prof.nome}</span>
                  </div>
                  <span className="text-xs font-black text-slate-900">R$ {prof.total.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</span>
                </div>
                <div className="w-full h-1.5 bg-slate-50 rounded-full overflow-hidden">
                  <div 
