import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell } from 'recharts';
import { AppData } from '../types';
import { TrendingUp, DollarSign, Star, Coffee, Trophy, ArrowUpCircle, ArrowDownCircle, Crown, ShoppingBag, Scissors, Target, CheckCircle2 } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const calculations = useMemo(() => {
    const params = data.parametros.find(p => p.ano === year) || data.parametros[0];
    const metaAnualFaturamento = params?.metaFaturamento || 0;
    const metaMensal = metaAnualFaturamento / 12;

    const producaoAno = data.producao.filter(p => p.ano === year);
    const receitasExtrasAno = data.receitasExtras.filter(r => r.ano === year);
    const gastosAno = data.gastos.filter(g => g.ano === year);

    const entServicos = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0);
    const entProdutos = receitasExtrasAno.reduce((acc, curr) => acc + curr.pacotes, 0);
    const entAssinaturas = receitasExtrasAno.reduce((acc, curr) => acc + curr.assinaturas, 0);
    const entGeladeira = receitasExtrasAno.reduce((acc, curr) => acc + curr.geladeira, 0);
    const faturamentoAnualRealizado = entServicos + entProdutos + entAssinaturas + entGeladeira;

    const saidaGastos = gastosAno.reduce((acc, curr) => acc + curr.valor, 0);
    const saidaRepasses = producaoAno.reduce((acc, curr) => acc + curr.repasseProfissional + curr.repasseAssinatura, 0);
    const saidaTotal = saidaGastos + saidaRepasses;
    const saldoFinal = faturamentoAnualRealizado - saidaTotal;

    const porcentagemAtingidaAnual = metaAnualFaturamento > 0 ? (faturamentoAnualRealizado / metaAnualFaturamento) * 100 : 0;

    // Dados para Gráfico Mensal Meta x Realidade
    const meses = Array.from({ length: 12 }, (_, i) => {
      const mes = i + 1;
      const pMes = producaoAno.filter(p => p.mes === mes);
      const eMes = receitasExtrasAno.find(r => r.mes === mes);
      const gMes = gastosAno.filter(g => g.mes === mes).reduce((s, c) => s + c.valor, 0);

      const real = pMes.reduce((s, c) => s + c.producaoBruta, 0) + (eMes?.pacotes || 0) + (eMes?.assinaturas || 0) + (eMes?.geladeira || 0);
      const repasse = pMes.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
      const lucro = real - repasse - gMes;

      return { 
        name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i], 
        Real: real, 
        Meta: metaMensal,
        lucro 
      };
    });

    const melhorMesObj = [...meses].sort((a, b) => b.lucro - a.lucro)[0];

    // Ranking Profissionais
    const ranking = data.profissionais.map(prof => ({
      nome: prof.nome,
      total: data.producao.filter(p => p.ano === year && p.profissionalId === prof.id).reduce((s, c) => s + c.producaoBruta, 0)
    })).sort((a, b) => b.total - a.total);

    return { 
      entServicos, entProdutos, entAssinaturas, entGeladeira, 
      faturamentoAnualRealizado, metaAnualFaturamento, porcentagemAtingidaAnual,
      saidaTotal, saldoFinal, meses, melhorMesObj, ranking 
    };
  }, [data, year]);

  const { 
    entServicos, entProdutos, entAssinaturas, entGeladeira, 
    faturamentoAnualRealizado, metaAnualFaturamento, porcentagemAtingidaAnual,
    saidaTotal, saldoFinal, meses, melhorMesObj, ranking 
  } = calculations;

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      {/* Banner Principal Faturamento */}
      <div className="bg-slate-900 rounded-[40px] p-8 text-white relative overflow-hidden shadow-2xl shadow-blue-200">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/20 rounded-full -mr-20 -mt-20 blur-3xl"></div>
        <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="text-center md:text-left">
            <p className="text-blue-400 text-xs font-black uppercase tracking-[0.2em] mb-2">Faturamento Consolidado {year}</p>
            <h1 className="text-5xl md:text-6xl font-black tracking-tighter">
              R$ {faturamentoAnualRealizado.toLocaleString('pt-BR')}
            </h1>
          </div>
          <div className="flex gap-4">
            <div className="bg-white/10 backdrop-blur-md p-4 rounded-3xl border border-white/10 text-center min-w-[140px]">
              <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Melhor Mês</p>
              <div className="flex items-center justify-center gap-2">
                <Crown size={16} className="text-amber-400" />
                <span className="font-black text-lg">{melhorMesObj.name}</span>
              </div>
            </div>
            <div className="bg-emerald-500 p-4 rounded-3xl text-center min-w-[140px] shadow-lg shadow-emerald-500/20">
              <p className="text-[10px] text-emerald-100 uppercase font-bold mb-1">Saldo Final</p>
              <p className="font-black text-lg">R$ {saldoFinal.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
            </div>
          </div>
        </div>
      </div>

      {/* NOVO DASHBOARD: Meta vs Realidade Anual */}
      <div className="bg-white p-8 rounded-[40px] border border-blue-50 shadow-sm overflow-hidden relative group">
        <div className="absolute top-0 right-0 p-8 text-blue-50/50 -mr-10 -mt-10">
          <Target size={120} />
        </div>
        <div className="relative z-10">
          <div className="flex justify-between items-end mb-6">
            <div>
              <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
                <Target size={22} className="text-blue-600" /> Meta Anual do Negócio
              </h3>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Realidade x Meta Estipulada para {year}</p>
            </div>
            <div className="text-right">
              <span className={`text-3xl font-black ${porcentagemAtingidaAnual >= 100 ? 'text-emerald-500' : 'text-blue-600'}`}>
                {Math.round(porcentagemAtingidaAnual)}%
              </span>
              <p className="text-[10px] text-slate-400 font-black uppercase">Atingido</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-center">
            <div className="space-y-4">
              <div className="flex justify-between text-sm font-bold">
                <span className="text-slate-400 uppercase text-[10px] tracking-widest">Realizado</span>
                <span className="text-slate-800">R$ {faturamentoAnualRealizado.toLocaleString('pt-BR')}</span>
              </div>
              <div className="w-full h-4 bg-slate-50 rounded-full overflow-hidden p-1 border border-slate-100">
                <div 
                  className={`h-full rounded-full transition-all duration-1000 ${porcentagemAtingidaAnual >= 100 ? 'bg-emerald-500' : 'bg-blue-600'}`}
                  style={{ width: `${Math.min(porcentagemAtingidaAnual, 100)}%` }}
                />
              </div>
              <div className="flex justify-between text-sm font-bold">
                <span className="text-slate-400 uppercase text-[10px] tracking-widest">Meta {year}</span>
                <span className="text-blue-600">R$ {metaAnualFaturamento.toLocaleString('pt-BR')}</span>
              </div>
            </div>

            <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100 flex flex-col justify-center">
              <div className="flex items-center gap-4">
                <div className={`p-3 rounded-2xl ${porcentagemAtingidaAnual >= 100 ? 'bg-emerald-100 text-emerald-600' : 'bg-blue-100 text-blue-600'}`}>
                  {porcentagemAtingidaAnual >= 100 ? <CheckCircle2 /> : <TrendingUp />}
                </div>
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase">Status Estratégico</p>
                  <p className="text-sm font-black text-slate-800">
                    {porcentagemAtingidaAnual >= 100 
                      ? 'Objetivo Anual Concluído!' 
                      : `Faltam R$ ${(metaAnualFaturamento - faturamentoAnualRealizado).toLocaleString('pt-BR')} para a meta.`}
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Grid de Entradas e Saídas */}
