import React, { useState } from 'react';
import { AppData, ParametrosAnuais } from '../types';
import { FileSpreadsheet, RefreshCw, CheckCircle2, CalendarPlus, Settings2, Save, Trash2 } from 'lucide-react';

interface ConfigProps {
  data: AppData;
  setData: (data: AppData) => void;
  selectedYear: number;
  setSelectedYear: (year: number) => void;
}

const Config: React.FC<ConfigProps> = ({ data, setData, selectedYear, setSelectedYear }) => {
  const [sheetUrl, setSheetUrl] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [showNewYearModal, setShowNewYearModal] = useState(false);

  // Form para novo ano
  const [newYearForm, setNewYearForm] = useState<ParametrosAnuais>({
    ano: new Date().getFullYear() + 1,
    metaFaturamento: 0,
    metaLucro: 0,
    metaAssinaturas: 0,
    metaGeladeira: 0,
    metaGastos: 0,
    metaPorCadeira: 5000
  });

  const handleSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      setIsSyncing(false);
      alert('Dados sincronizados com sucesso (Simulado)!');
    }, 2000);
  };

  const handleCreateNewYear = () => {
    if (data.parametros.some(p => p.ano === newYearForm.ano)) {
      alert('Este ano já está configurado!');
      return;
    }

    setData({
      ...data,
      parametros: [...data.parametros, newYearForm]
    });
    setSelectedYear(newYearForm.ano);
    setShowNewYearModal(false);
    alert(`Estratégia para ${newYearForm.ano} iniciada do zero!`);
  };

  const handleRemoveYear = (ano: number) => {
    if (data.parametros.length <= 1) {
      alert('Você precisa de pelo menos um ano configurado.');
      return;
    }
    if (confirm(`Tem certeza que deseja remover as metas de ${ano}? Os dados de fluxo não serão apagados, apenas os parâmetros estratégicos.`)) {
      setData({
        ...data,
        parametros: data.parametros.filter(p => p.ano !== ano)
      });
      if (selectedYear === ano) setSelectedYear(data.parametros[0].ano);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-20">
      <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Configurações Gerais</h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Gestão de Anos */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100 flex flex-col">
          <div className="flex justify-between items-start mb-6">
            <div>
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <CalendarPlus size={20} className="text-blue-600" /> Gestão de Anos
              </h3>
              <p className="text-xs text-slate-400 font-bold uppercase mt-1">Defina metas para novos períodos</p>
            </div>
            <button 
              onClick={() => setShowNewYearModal(true)}
              className="bg-blue-600 text-white p-2 rounded-xl hover:scale-105 transition-all shadow-lg shadow-blue-100"
            >
              <CalendarPlus size={20} />
            </button>
          </div>

          <div className="space-y-3 flex-1">
            {data.parametros.sort((a,b) => b.ano - a.ano).map(p => (
              <div key={p.ano} className={`p-4 rounded-3xl border flex justify-between items-center transition-all ${selectedYear === p.ano ? 'bg-blue-50 border-blue-200' : 'bg-slate-50 border-slate-100'}`}>
                <div>
                  <p className={`text-lg font-black ${selectedYear === p.ano ? 'text-blue-600' : 'text-slate-800'}`}>{p.ano}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase">Meta: R$ {p.metaFaturamento.toLocaleString('pt-BR')}</p>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setSelectedYear(p.ano)}
                    className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase transition-all ${selectedYear === p.ano ? 'bg-blue-600 text-white' : 'bg-white text-slate-400 border border-slate-200 hover:text-blue-600'}`}
                  >
                    Ativar
                  </button>
                  <button onClick={() => handleRemoveYear(p.ano)} className="p-2 text-slate-200 hover:text-red-500 transition-colors">
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Integração */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 text-lg mb-4 flex items-center gap-2">
            <FileSpreadsheet size={20} className="text-emerald-600" /> Integração Google Sheets
          </h3>
          <p className="text-xs text-slate-500 mb-6 leading-relaxed">Conecte sua base de dados externa. O BI priorizará os dados da planilha se a URL for válida.</p>

          <div className="space-y-4">
            <input
              type="text"
              placeholder="https://docs.google.com/spreadsheets/d/..."
              value={sheetUrl}
              onChange={(e) => setSheetUrl(e.target.value)}
              className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20"
            />
            <button 
              onClick={handleSync}
              disabled={isSyncing}
              className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-sm hover:bg-slate-800 transition-all flex items-center justify-center gap-2 shadow-xl"
            >
              {isSyncing ? <RefreshCw className="animate-spin" size={18} /> : <CheckCircle2 size={18} />}
              SINCRONIZAR PLANILHA
            </button>
          </div>
        </div>
      </div>

      {/* Modal Novo Ano */}
      {showNewYearModal && (
        <div className="fixed inset-0 z-[110] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <h3 className="text-xl font-black text-slate-800">Novo Ano Estratégico</h3>
              <button onClick={() => setShowNewYearModal(false)} className="text-slate-400 hover:text-slate-600"><Settings2 /></button>
            </div>

            <div className="p-8 space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ano de Referência</label>
                <input 
                  type="number" 
                  className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl font-black text-lg focus:ring-2 focus:ring-blue-500/20" 
                  value={newYearForm.ano} 
                  onChange={(e) => setNewYearForm({...newYearForm, ano: Number(e.target.value)})}
                />
              </div>

              <div className="space-y-4 pt-4 border-t border-slate-50">
                <div className="flex items-center gap-2 text-blue-600 font-bold text-xs uppercase tracking-widest mb-2">
                  <Target size={14} /> Metas Financeiras
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[9px] font-bold text-slate-400 uppercase">Faturamento Anual</label>
                    <input type="number" className="w-full bg-slate-50 p-3 rounded-xl text-xs font-bold" value={newYearForm.metaFaturamento} onChange={(e) => setNewYearForm({...newYearForm, metaFaturamento: Number(e.target.value)})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-bold text-slate-400 uppercase">Meta Lucro</label>
                    <input type="number" className="w-full bg-slate-50 p-3 rounded-xl text-xs font-bold" value={newYearForm.metaLucro} onChange={(e) => setNewYearForm({...newYearForm, metaLucro: Number(e.target.value)})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-bold text-slate-400 uppercase">Meta Assinaturas</label>
                    <input type="number" className="w-full bg-slate-50 p-3 rounded-xl text-xs font-bold" value={newYearForm.metaAssinaturas} onChange={(e) => setNewYearForm({...newYearForm, metaAssinaturas: Number(e.target.value)})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-bold text-slate-400 uppercase">Meta/Cadeira (Mês)</label>
                    <input type="number" className="w-full bg-slate-50 p-3 rounded-xl text-xs font-bold" value={newYearForm.metaPorCadeira} onChange={(e) => setNewYearForm({...newYearForm, metaPorCadeira: Number(e.target.value)})} />
                  </div>
                </div>
              </div>

              <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100">
                <p className="text-[10px] text-blue-700 font-medium leading-relaxed">
                  * Ao criar um novo ano, o sistema manterá sua lista de profissionais e categorias, mas iniciará a contagem de faturamento e fluxo do zero para o novo período.
                </p>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t border-slate-100 flex gap-4">
              <button onClick={() => setShowNewYearModal(false)} className="flex-1 bg-white border border-slate-200 py-4 rounded-3xl font-bold text-slate-600">Cancelar</button>
              <button onClick={handleCreateNewYear} className="flex-[2] bg-blue-600 text-white py-4 rounded-3xl font-black shadow-lg shadow-blue-100 flex items-center justify-center gap-2">
                <Save size={18} /> INICIAR ANO {newYearForm.ano}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Config;

