import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LineChart, Line } from 'recharts';
import { AppData } from '../types';
import { TrendingUp, DollarSign, Star, Trophy, Crown, ShoppingBag, Scissors, Target, UserMinus, UserCheck, Activity } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const calculations = useMemo(() => {
    const params = data.parametros.find(p => p.ano === year) || data.parametros[0];
    const metaAnual = params?.metaFaturamento || 0;

    const producaoAno = data.producao.filter(p => p.ano === year);
    const receitasAno = data.receitasExtras.filter(r => r.ano === year);

    const faturamentoReal = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0) +
                           receitasAno.reduce((acc, r) => acc + r.pacotes + r.assinaturas + r.geladeira + r.dinheiro + r.cartao + r.pix, 0);

    const totalVendaProdutos = producaoAno.reduce((acc, curr) => acc + (curr.vendasProdutos || 0), 0);
    const totalAtendimentos = producaoAno.reduce((acc, curr) => acc + (curr.quantidadeAtendimentos || 0), 0);
    const ticketMedioProdutos = totalAtendimentos > 0 ? totalVendaProdutos / totalAtendimentos : 0;

    // Métricas de Assinatura
    const totalNovos = receitasAno.reduce((acc, curr) => acc + (curr.novosAssinantes || 0), 0);
    const totalCancelados = receitasAno.reduce((acc, curr) => acc + (curr.cancelamentosAssinantes || 0), 0);
    const churnRate = totalNovos > 0 ? (totalCancelados / (totalNovos + totalCancelados)) * 100 : 0;

    const meses = Array.from({ length: 12 }, (_, i) => {
      const mes = i + 1;
      const pMes = producaoAno.filter(p => p.mes === mes);
      const rMes = receitasAno.find(r => r.mes === mes);
      const totalMes = pMes.reduce((s, c) => s + c.producaoBruta, 0) + 
                       (rMes ? (rMes.pacotes + rMes.assinaturas + rMes.geladeira + rMes.dinheiro + rMes.cartao + rMes.pix) : 0);

      return { 
        name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i], 
        Faturamento: totalMes,
        Assinantes: rMes?.assinaturas || 0
      };
    });

    return { faturamentoReal, metaAnual, churnRate, ticketMedioProdutos, meses, totalNovos };
  }, [data, year]);

  const { faturamentoReal, metaAnual, churnRate, ticketMedioProdutos, meses, totalNovos } = calculations;

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      {/* Top Cards: Saúde do Negócio */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <MetricCard 
          label="Faturamento Real" 
          value={`R$ ${faturamentoReal.toLocaleString('pt-BR')}`} 
          sub={`Meta: R$ ${metaAnual.toLocaleString('pt-BR')}`}
          icon={DollarSign} 
          color="bg-blue-600" 
        />
        <MetricCard 
          label="Saúde da Assinatura" 
          value={`${Math.round(100 - churnRate)}%`} 
          sub="Taxa de Retenção"
          icon={UserCheck} 
          color="bg-emerald-500" 
        />
        <MetricCard 
          label="Churn (Cancelamentos)" 
          value={`${churnRate.toFixed(1)}%`} 
          sub="Média Anual"
          icon={UserMinus} 
          color="bg-red-500" 
        />
        <MetricCard 
          label="Upselling (Produtos)" 
          value={`R$ ${ticketMedioProdutos.toFixed(2)}`} 
          sub="Extra por Cliente"
          icon={ShoppingBag} 
          color="bg-purple-600" 
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Gráfico de Crescimento */}
        <div className="md:col-span-2 bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-8">
            <div>
              <h3 className="font-black text-slate-800 text-xl flex items-center gap-2">
                <Activity size={20} className="text-blue-600" /> Crescimento de Receita
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Visão Mensal de Performance</p>
            </div>
          </div>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={meses}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 'bold'}} />
                <YAxis hide />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)'}}
                  formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`}
                />
                <Bar dataKey="Faturamento" fill="#2563eb" radius={[10, 10, 0, 0]} barSize={35} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Insights Estratégicos IA */}
        <div className="bg-slate-900 p-8 rounded-[40px] text-white flex flex-col justify-between shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
          <div>
            <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-blue-600 rounded-xl"><Target size={20} /></div>
              <h3 className="font-black text-lg">Estratégia BI</h3>
            </div>
            <div className="space-y-4">
              <div className="p-4 bg-white/5 rounded-2xl border border-white/10">
                <p className="text-[10px] font-black text-blue-400 uppercase mb-1">Diagnóstico</p>
                <p className="text-xs font-medium leading-relaxed">
                  {churnRate > 5 ? 'Atenção! Seu cancelamento está alto. Melhore a experiência do assinante.' : 'Excelente retenção! Considere aumentar o valor dos novos planos.'}
                </p>
              </div>
              <div className="p-4 bg-white/5 rounded-2xl border border-white/10">
                <p className="text-[10px] font-black text-purple-400 uppercase mb-1">Oportunidade</p>
                <p className="text-xs font-medium leading-relaxed">
                  Seu Ticket Médio de produtos é R$ {ticketMedioProdutos.toFixed(2)}. Meta ideal: R$ 15,00.
                </p>
              </div>
            </div>
          </div>
          <button className="mt-8 w-full bg-blue-600 py-4 rounded-2xl font-black text-xs hover:bg-blue-500 transition-all uppercase tracking-widest">
            Gerar Relatório IA
          </button>
        </div>
      </div>
    </div>
  );
};

