import React, { useState, useMemo } from 'react';
import { AppData, Profissional, ProfissionalPerfil } from '../types';
import { Plus, Trash2, X, TrendingUp, TrendingDown, Scissors, Star, ShoppingCart, Target, Trophy } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, setData, year }) => {
  const [isAddingProf, setIsAddingProf] = useState(false);
  const [newProf, setNewProf] = useState({ nome: '', cadeira: 1 });
  const [newPerfil, setNewPerfil] = useState<ProfissionalPerfil>({
    experiencia: '',
    perfilComportamental: '',
    especialidade: '',
    objetivo: ''
  });

  const ranking = useMemo(() => {
    const parametros = data.parametros.find(p => p.ano === year) || data.parametros[0];
    return data.profissionais.map(prof => {
      const records = data.producao.filter(p => p.profissionalId === prof.id && p.ano === year);

      const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
      const totalVendas = records.reduce((s, c) => s + (c.vendasProdutos || 0), 0);
      const totalAtendimentos = records.reduce((s, c) => s + (c.quantidadeAtendimentos || 0), 0);

      const conversaoVenda = totalAtendimentos > 0 ? (totalVendas / totalAtendimentos) : 0;
      const ticketMedio = totalAtendimentos > 0 ? (totalProd / totalAtendimentos) : 0;

      const statusVenda = conversaoVenda > 10 ? 'good' : conversaoVenda > 5 ? 'neutral' : 'bad';

      return {
        ...prof,
        totalProd,
        totalVendas,
        totalAtendimentos,
        conversaoVenda,
        ticketMedio,
        statusVenda
      };
    }).sort((a, b) => b.totalProd - a.totalProd);
  }, [data.profissionais, data.producao, year, data.parametros]);

  const handleAddProf = () => {
    if (!newProf.nome) return;
    const nProf: Profissional = {
      id: Math.random().toString(36).substr(2, 9),
      nome: newProf.nome,
      cadeira: newProf.cadeira,
      comissao: 50,
      ativo: true,
      perfil: newPerfil
    };
    setData({ ...data, profissionais: [...data.profissionais, nProf] });
    setIsAddingProf(false);
    setNewProf({ nome: '', cadeira: 1 });
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Equipe & Performance</h2>
          <p className="text-sm text-slate-500 font-medium">Upselling e Conversão Técnica</p>
        </div>
        <button onClick={() => setIsAddingProf(true)} className="bg-blue-600 text-white flex items-center gap-2 px-6 py-3 rounded-2xl shadow-xl shadow-blue-100 font-black text-xs uppercase tracking-widest hover:scale-105 transition-all">
          <Plus size={18} /> Novo Barbeiro
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {ranking.map((prof, idx) => (
          <div key={prof.id} className="bg-white rounded-[40px] p-8 border border-slate-50 shadow-sm relative overflow-hidden group hover:border-blue-100 transition-all">
            <div className="absolute top-0 right-0 p-6 text-slate-50 group-hover:text-blue-50 transition-colors">
              <Trophy size={60} />
            </div>

            <div className="relative z-10">
              <div className="flex items-center gap-4 mb-6">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-white ${idx === 0 ? 'bg-amber-400' : 'bg-slate-800'}`}>
                  {idx + 1}º
                </div>
                <div>
                  <h3 className="font-black text-slate-800 text-lg">{prof.nome}</h3>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Cadeira {prof.cadeira}</p>
                </div>
              </div>

              <div className="space-y-4">
                <div className="p-4 bg-slate-50 rounded-3xl border border-slate-100">
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Produção Bruta</p>
                  <p className="text-xl font-black text-slate-800">R$ {prof.totalProd.toLocaleString('pt-BR')}</p>
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="p-4 bg-blue-50/50 rounded-3xl border border-blue-100/30">
                    <p className="text-[9px] font-black text-blue-600 uppercase mb-1 flex items-center gap-1">
                      <ShoppingCart size={10} /> Conversão
                    </p>
                    <p className="text-sm font-black text-blue-900">R$ {prof.conversaoVenda.toFixed(2)}</p>
                  </div>
                  <div className="p-4 bg-emerald-50/50 rounded-3xl border border-emerald-100/30">
                    <p className="text-[9px] font-black text-emerald-600 uppercase mb-1 flex items-center gap-1">
                      <Target size={10} /> Atendidos
                    </p>
                    <p className="text-sm font-black text-emerald-900">{prof.totalAtendimentos}</p>
                  </div>
                </div>

                <div className="pt-2">
                  <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase mb-2">
                    <span>Performance de Upselling</span>
                    <span className={prof.statusVenda === 'good' ? 'text-emerald-500' : 'text-amber-500'}>
                      {prof.statusVenda === 'good' ? 'Elite' : 'Pode Melhorar'}
                    </span>
                  </div>
                  <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ${prof.statusVenda === 'good' ? 'bg-emerald-500' : 'bg-blue-600'}`}
                      style={{ width: `${Math.min((prof.conversaoVenda / 20) * 100, 100)}%` }}
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modal Novo Profissional (Simplificado) */}
      {isAddingProf && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] p-8 shadow-2xl animate-in zoom-in">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800">Novo Profissional</h3>
              <button onClick={() => setIsAddingProf(false)} className="text-slate-400"><X /></button>
            </div>
            <div className="space-y-4">
              <input 
                type="text" 
                placeholder="Nome do Barbeiro" 
                className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold"
                value={newProf.nome}
                onChange={(e) => setNewProf({...newProf, nome: e.target.value})}
              />
              <input 
                type="number" 
                placeholder="Número da Cadeira" 
                className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold"
                value={newProf.cadeira}
                onChange={(e) => setNewProf({...newProf, cadeira: Number(e.target.value)})}
              />
              <button onClick={handleAddProf} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-lg">CADASTRAR</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Professionals;

import React, { useState, useEffect } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal } from '../types';
import { PlusCircle, X, Settings2, Save, Edit2, Eye, TrendingUp, DollarSign, Wallet, Users, Target, UserMinus, ShoppingCart } from 'lucide-react';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showSummaryModal, setShowSummaryModal] = useState(false);
  const [selectedMonthSummary, setSelectedMonthSummary] = useState<any>(null);

  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, 
          nome: prof.nome, 
          bruta: p?.producaoBruta || 0, 
          repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0,
          vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0,
        cartao: extra?.cartao || 0,
        pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0,
        pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0,
        cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods,
        gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;

    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  });

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year,
      mes: formData.mes,
      dinheiro: formData.dinheiro,
      cartao: formData.cartao,
      pix: formData.pix,
      assinaturas: formData.assinaturas,
      pacotes: formData.pacotes,
      geladeira: 0,
      outras: 0,
      novosAssinantes: formData.novosAssinantes,
      cancelamentosAssinantes: formData.cancelamentosAssinantes
    };

    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year,
      mes: formData.mes,
      profissionalId: p.id,
      producaoBruta: p.bruta,
      repasseProfissional: p.repasse,
      repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos,
      quantidadeAtendimentos: p.quantidadeAtendimentos
    }));

    const newGastos: GastoMensal[] = formData.gastos.map(g => ({
      ano: year,
      mes: formData.mes,
      categoria: g.categoria,
      valor: g.valor
    }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });

    setShowModal(false);
    alert('Fechamento estratégico salvo!');
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-slate-800">Fluxo Mensal</h2>
          <p className="text-xs text-slate-400">Detalhamento de crescimento e churn</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase shadow-lg shadow-blue-100 flex items-center gap-2">
          <PlusCircle size={18} /> Novo Lançamento
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm overflow-hidden border border-slate-50">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-6 py-5">Mês</th>
                <th className="px-6 py-5 text-right">Rec. Bruta</th>
                <th className="px-6 py-5 text-right">Repasses</th>
                <th className="px-6 py-5 text-right">Resultado</th>
                <th className="px-6 py-5 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50 font-medium">
              {matrix.map((m) => (
                <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                  <td className="px-6 py-5 font-bold text-slate-800">{m.nome}</td>
                  <td className="px-6 py-5 text-right text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                  <td className="px-6 py-5 text-right text-amber-600">R$ {m.repasse.toLocaleString('pt-BR')}</td>
                  <td className={`px-6 py-5 text-right font-black ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                    R$ {m.liquido.toLocaleString('pt-BR')}
                  </td>
                  <td className="px-6 py-5 text-center">
                    <button onClick={() => { setFormData(prev => ({ ...prev, mes: m.mes })); setShowModal(true); }} className="p-2 text-slate-300 hover:text-blue-600 transition-all">
                      <Edit2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal Lançamento Detalhado */}
      {showModal && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-white sticky top-0 z-10">
              <div>
                <h3 className="text-xl font-black text-slate-800">Fechamento do Mês</h3>
                <p className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">Atualize métricas de retenção e upselling</p>
              </div>
              <button onClick={() => setShowModal(false)} className="bg-slate-50 p-3 rounded-full text-slate-400 hover:text-slate-600"><X /></button>
            </div>

            <div className="p-8 overflow-y-auto space-y-8 flex-1">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mês Referência</label>
                <select 
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-blue-600"
                  value={formData.mes}
                  onChange={(e) => setFormData({...formData, mes: Number(e.target.value)})}
                >
                  {meses.map((m, i) => <option key={m} value={i+1}>{m}</option>)}
                </select>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2">
                  <UserCheck className="text-emerald-500" size={18} /> Saúde da Assinatura
                </h4>
                <div className="grid grid-cols-2 gap-4">
                  <Input label="Novos Assinantes" value={formData.novosAssinantes} onChange={(v: number) => setFormData({...formData, novosAssinantes: v})} icon={TrendingUp} />
                  <Input label="Cancelamentos (Churn)" value={formData.cancelamentosAssinantes} onChange={(v: number) => setFormData({...formData, cancelamentosAssinantes: v})} icon={UserMinus} />
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2">
                  <ShoppingCart className="text-purple-500" size={18} /> Performance da Equipe
                </h4>
                <div className="space-y-4">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-6 bg-slate-50 rounded-[32px] border border-slate-100 space-y-4">
                      <div className="flex justify-between items-center">
                        <span className="text-sm font-black text-slate-800">{p.nome}</span>
                        <div className="px-3 py-1 bg-white border border-slate-200 rounded-full text-[10px] font-black text-slate-400 uppercase tracking-widest">Cadeira {idx+1}</div>
                      </div>
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                        <MiniInput label="Bruto" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse" value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Venda Prod." value={p.vendasProdutos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].vendasProdutos = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Atendim." value={p.quantidadeAtendimentos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].quantidadeAtendimentos = v; setFormData({...formData, producoes: n}); }} />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t border-slate-100 flex gap-4">
              <button onClick={() => setShowModal(false)} className="flex-1 bg-white text-slate-600 py-4 rounded-3xl font-bold border border-slate-200">Cancelar</button>
              <button onClick={handleSaveClosing} className="flex-[2] bg-blue-600 text-white py-4 rounded-3xl font-black shadow-lg shadow-blue-200 flex items-center justify-center gap-2">
                <Save size={18} /> Salvar Inteligência
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const Input = ({ label, value, onChange, icon: Icon }: any) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1">
      <Icon size={12} /> {label}
    </label>
    <input type="number" value={value === 0 ? '' : value} onChange={(e) => onChange(Number(e.target.value))} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-800 focus:ring-2 focus:ring-blue-500/10 outline-none" />
  </div>
);

const MiniInput = ({ label, value, onChange }: any) => (
  <div>
    <label className="text-[8px] font-black text-slate-400 uppercase block mb-1">{label}</label>
    <input type="number" value={value === 0 ? '' : value} onChange={(e) => onChange(Number(e.target.value))} className="w-full p-2 bg-white border border-slate-200 rounded-xl text-xs font-bold" />
  </div>
);

export default CashFlow;

import React, { useState } from 'react';
import { AppData, MeetingNote } from '../types';
import { GoogleGenAI } from "@google/genai";
import { MessageSquare, Plus, BrainCircuit, Trash2, Calendar, Sparkles, UserCircle, ShoppingCart } from 'lucide-react';

interface MeetingsProps {
  data: AppData;
  setData: (data: AppData) => void;
}

const Meetings: React.FC<MeetingsProps> = ({ data, setData }) => {
  const [selectedProfId, setSelectedProfId] = useState(data.profissionais[0]?.id || '');
  const [newNote, setNewNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiScript, setAiScript] = useState('');

  const selectedProf = data.profissionais.find(p => p.id === selectedProfId);
  const notes = data.meetingNotes?.filter(n => n.profissionalId === selectedProfId) || [];

  // Dados de Performance para IA
  const perfData = data.producao.filter(p => p.profissionalId === selectedProfId).slice(-3); // Últimos 3 meses
  const mediaVenda = perfData.reduce((s,c) => s + (c.vendasProdutos || 0), 0) / (perfData.length || 1);
  const mediaAtend = perfData.reduce((s,c) => s + (c.quantidadeAtendimentos || 0), 0) / (perfData.length || 1);
  const conversao = mediaAtend > 0 ? mediaVenda / mediaAtend : 0;

  const handleAddNote = () => {
    if (!newNote) return;
    const note: MeetingNote = {
      id: Math.random().toString(36).substr(2, 9),
      profissionalId: selectedProfId,
      data: new Date().toISOString(),
      texto: newNote
    };
    setData({ ...data, meetingNotes: [...(data.meetingNotes || []), note] });
    setNewNote('');
  };

  const handleGenerateScript = async () => {
    setIsGenerating(true);
    setAiScript('');

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      Você é um mentor sênior de barbearias de alto luxo. Analise o perfil do barbeiro "${selectedProf?.nome}".

      PERFORMANCE RECENTE:
      - Média de Atendimentos: ${mediaAtend.toFixed(0)} / mês.
      - Média de Venda de Produtos (Upselling): R$ ${mediaVenda.toFixed(2)} / mês.
      - Conversão por Cliente: R$ ${conversao.toFixed(2)}. (Meta ideal é acima de R$ 15,00).

      NOTAS COMPORTAMENTAIS:
      ${notes.map(n => `- ${n.texto}`).join('\n')}

      CRIE UM ROTEIRO DE REUNIÃO MENSAL:
      1. Use uma linguagem firme, inspiradora e estratégica.
      2. COBRE o resultado de Upselling (venda de produtos) caso a conversão esteja abaixo de R$ 15,00.
      3. Use o contexto comportamental das notas para dar um feedback "na veia".
      4. Termine com um desafio de meta de vendas para o próximo mês.

      O tom deve ser de "dono de negócio" falando com seu "braço direito".
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiScript(response.text || "Erro ao processar roteiro.");
    } catch (error) {
      setAiScript("Falha na conexão com a IA estratégica.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-24">
