import { GoogleGenAI } from "@google/genai";
import { Transaction, Profissional } from "../types";

// Fix: Updated Collaborator type to Profissional as it is the correct exported member from types.ts
export const getBusinessInsights = async (transactions: Transaction[], collaborators: Profissional[]) => {
  // Fix: Initialized GoogleGenAI using the correct named parameter and direct process.env.API_KEY access
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const summary = transactions.reduce((acc, curr) => {
    if (curr.type === 'INCOME') acc.totalIncome += curr.amount;
    else acc.totalExpense += curr.amount;
    return acc;
  }, { totalIncome: 0, totalExpense: 0 });

  const prompt = `
    Como um consultor especialista em Barbearias, analise os seguintes dados financeiros anuais e forneça insights estratégicos curtos:

    Total de Entradas: R$ ${summary.totalIncome}
    Total de Saídas: R$ ${summary.totalExpense}
    Número de Colaboradores: ${collaborators.length}
    Transações: ${JSON.stringify(transactions.slice(-10))} (amostra das últimas 10)

    Por favor, responda em Português do Brasil com:
    1. Uma análise do lucro líquido.
    2. Sugestão para reduzir custos ou aumentar ticket médio.
    3. Um comentário motivacional para a equipe.
    Use um tom profissional mas acolhedor de 'Barber Shop'.
  `;

  try {
    // Fix: Using generateContent with correct parameter structure and recommended model
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    // Fix: Accessing text as a property on GenerateContentResponse as per SDK guidelines
    return response.text;
  } catch (error) {
    console.error("Erro ao obter insights da IA:", error);
    return "Não foi possível carregar os insights no momento. Tente novamente mais tarde.";
  }
};

import React, { useState } from 'react';
import { TransactionType, Profissional } from '../types';
import { CATEGORIES } from '../constants';

interface TransactionFormProps {
  // Fix: Updated Collaborator type to Profissional as it is the correct exported member from types.ts
  collaborators: Profissional[];
  onAdd: (transaction: {
    description: string;
    amount: number;
    date: string;
    type: TransactionType;
    collaboratorId?: string;
    category: string;
  }) => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ collaborators, onAdd }) => {
  const [type, setType] = useState<TransactionType>(TransactionType.INCOME);
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [collaboratorId, setCollaboratorId] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    onAdd({
      description,
      amount: parseFloat(amount),
      date,
      type,
      category,
      collaboratorId: type === TransactionType.INCOME ? collaboratorId : undefined
    });

    setDescription('');
    setAmount('');
