import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { AppData } from '../types';
import { TrendingUp, DollarSign, Star, Trophy, Crown, ArrowDownCircle, Wallet, UserCheck } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const calculations = useMemo(() => {
    const producaoAno = data.producao.filter(p => p.ano === year);
    const receitasAno = data.receitasExtras.filter(r => r.ano === year);
    const gastosAno = data.gastos.filter(g => g.ano === year);

    const faturamentoServicos = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0);
    const faturamentoExtra = receitasAno.reduce((acc, r) => acc + r.pacotes + r.geladeira + r.dinheiro + r.cartao + r.pix, 0);
    const faturamentoAssinaturas = receitasAno.reduce((acc, r) => acc + r.assinaturas, 0);

    const faturamentoTotal = faturamentoServicos + faturamentoExtra + faturamentoAssinaturas;

    const totalGastos = gastosAno.reduce((acc, curr) => acc + curr.valor, 0);
    const totalRepasses = producaoAno.reduce((acc, curr) => acc + curr.repasseProfissional + curr.repasseAssinatura, 0);
    const saidaTotal = totalGastos + totalRepasses;

    const saldoFinal = faturamentoTotal - saidaTotal;

    const meses = Array.from({ length: 12 }, (_, i) => {
      const mes = i + 1;
      const pMes = producaoAno.filter(p => p.mes === mes);
      const rMes = receitasAno.find(r => r.mes === mes);
      const gMes = gastosAno.filter(g => g.mes === mes).reduce((s, c) => s + c.valor, 0);
      const repMes = pMes.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);

      const totalMes = pMes.reduce((s, c) => s + c.producaoBruta, 0) + 
                       (rMes ? (rMes.pacotes + rMes.assinaturas + rMes.geladeira + rMes.dinheiro + rMes.cartao + rMes.pix) : 0);

      return { 
        name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i], 
        Faturamento: totalMes,
        Lucro: totalMes - repMes - gMes
      };
    });

    const melhorMes = [...meses].sort((a, b) => b.Lucro - a.Lucro)[0];

    const rankingBarbeiros = data.profissionais.map(prof => ({
      nome: prof.nome,
      total: data.producao.filter(p => p.ano === year && p.profissionalId === prof.id).reduce((s, c) => s + c.producaoBruta, 0)
    })).sort((a, b) => b.total - a.total);

    return { faturamentoTotal, faturamentoAssinaturas, saidaTotal, saldoFinal, melhorMes, meses, rankingBarbeiros };
  }, [data, year]);

  const { faturamentoTotal, faturamentoAssinaturas, saidaTotal, saldoFinal, melhorMes, meses, rankingBarbeiros } = calculations;

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      {/* Banner Principal Faturamento */}
      <div className="bg-slate-900 rounded-[40px] p-8 text-white relative overflow-hidden shadow-2xl shadow-blue-200">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/20 rounded-full -mr-20 -mt-20 blur-3xl"></div>
        <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="text-center md:text-left">
            <p className="text-blue-400 text-xs font-black uppercase tracking-[0.2em] mb-2">Faturamento Consolidado {year}</p>
            <h1 className="text-5xl md:text-6xl font-black tracking-tighter">
              R$ {faturamentoTotal.toLocaleString('pt-BR')}
            </h1>
          </div>
          <div className="flex gap-4">
            <div className="bg-white/10 backdrop-blur-md p-4 rounded-3xl border border-white/10 text-center min-w-[140px]">
              <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Mês Destaque</p>
              <div className="flex items-center justify-center gap-2">
                <Crown size={16} className="text-amber-400" />
                <span className="font-black text-lg">{melhorMes?.name}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Grid de Métricas Principais */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <MetricCard 
          label="Entrada de Assinaturas" 
          value={`R$ ${faturamentoAssinaturas.toLocaleString('pt-BR')}`} 
          icon={UserCheck} 
          color="text-emerald-500" 
          bg="bg-emerald-50" 
        />
        <MetricCard 
          label="Saída Total" 
          value={`R$ ${saidaTotal.toLocaleString('pt-BR')}`} 
          icon={ArrowDownCircle} 
          color="text-red-500" 
          bg="bg-red-50" 
        />
        <MetricCard 
          label="Saldo em Caixa" 
          value={`R$ ${saldoFinal.toLocaleString('pt-BR')}`} 
          icon={Wallet} 
          color="text-blue-600" 
          bg="bg-blue-50" 
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Gráfico de Faturamento */}
        <div className="md:col-span-2 bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 text-xl mb-8 flex items-center gap-2">
            <TrendingUp size={20} className="text-blue-600" /> Fluxo de Receita
          </h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={meses}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 'bold'}} />
                <YAxis hide />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)'}}
                  formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`}
                />
                <Bar dataKey="Faturamento" fill="#2563eb" radius={[10, 10, 0, 0]} barSize={35} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Ranking de Produção */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 text-xl mb-6 flex items-center gap-2">
            <Trophy size={20} className="text-amber-500" /> Top Barbeiros
          </h3>
          <div className="space-y-6">
            {rankingBarbeiros.slice(0, 5).map((prof, idx) => (
              <div key={prof.nome} className="group">
                <div className="flex justify-between items-end mb-2">
                  <div className="flex items-center gap-3">
                    <span className={`w-6 h-6 rounded-lg flex items-center justify-center text-[10px] font-black ${
                      idx === 0 ? 'bg-amber-400 text-white' : 'bg-slate-100 text-slate-400'
                    }`}>
                      {idx + 1}º
                    </span>
                    <span className="text-sm font-bold text-slate-700">{prof.nome}</span>
                  </div>
                  <span className="text-xs font-black text-slate-900">R$ {prof.total.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</span>
                </div>
                <div className="w-full h-1.5 bg-slate-50 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-blue-600 transition-all duration-1000" 
                    style={{ width: `${rankingBarbeiros[0].total > 0 ? (prof.total / rankingBarbeiros[0].total) * 100 : 0}%` }}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

const MetricCard = ({ label, value, icon: Icon, color, bg }: any) => (
  <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center gap-4 group hover:scale-[1.02] transition-all">
    <div className={`w-12 h-12 ${bg} ${color} rounded-2xl flex items-center justify-center shadow-sm`}>
      <Icon size={24} />
    </div>
    <div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</p>
      <h3 className="text-xl font-black text-slate-800">{value}</h3>
    </div>
  </div>
);

export default Dashboard;

