import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { AppData } from '../types';
import { TrendingUp, DollarSign, Star, Trophy, Crown, ArrowDownCircle, Wallet, UserCheck, Target, Scissors } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const calculations = useMemo(() => {
    const params = data.parametros.find(p => p.ano === year) || data.parametros[0];
    const metaAnual = params?.metaFaturamento || 0;
    const metaProducao = params?.metaPorCadeira * data.profissionais.length * 12 || metaAnual * 0.7;

    const producaoAno = data.producao.filter(p => p.ano === year);
    const receitasAno = data.receitasExtras.filter(r => r.ano === year);
    const gastosAno = data.gastos.filter(g => g.ano === year);

    const faturamentoServicos = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0);
    const faturamentoExtra = receitasAno.reduce((acc, r) => acc + r.pacotes + r.geladeira + r.dinheiro + r.cartao + r.pix, 0);
    const faturamentoAssinaturas = receitasAno.reduce((acc, r) => acc + r.assinaturas, 0);

    const faturamentoTotal = faturamentoServicos + faturamentoExtra + faturamentoAssinaturas;
    const totalGastos = gastosAno.reduce((acc, curr) => acc + curr.valor, 0);
    const totalRepasses = producaoAno.reduce((acc, curr) => acc + curr.repasseProfissional + curr.repasseAssinatura, 0);
    const saidaTotal = totalGastos + totalRepasses;
    const saldoFinal = faturamentoTotal - saidaTotal;

    const meses = Array.from({ length: 12 }, (_, i) => {
      const mes = i + 1;
      const pMes = producaoAno.filter(p => p.mes === mes);
      const rMes = receitasAno.find(r => r.mes === mes);
      const totalMes = pMes.reduce((s, c) => s + c.producaoBruta, 0) + 
                       (rMes ? (rMes.pacotes + rMes.assinaturas + rMes.geladeira + rMes.dinheiro + rMes.cartao + rMes.pix) : 0);
      const repMes = pMes.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
      const gMes = gastosAno.filter(g => g.mes === mes).reduce((s, c) => s + c.valor, 0);
      return { 
        name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i], 
        Faturamento: totalMes,
        Lucro: totalMes - repMes - gMes
      };
    });

    const melhorMes = [...meses].sort((a, b) => b.Lucro - a.Lucro)[0];

    return { 
      faturamentoTotal, faturamentoAssinaturas, saidaTotal, saldoFinal, 
      melhorMes, metaAnual, metaProducao, faturamentoServicos 
    };
  }, [data, year]);

  const { faturamentoTotal, faturamentoAssinaturas, saidaTotal, saldoFinal, melhorMes, metaAnual, metaProducao, faturamentoServicos } = calculations;

  const dataMetaAnual = [
    { name: 'Realizado', valor: faturamentoTotal, fill: '#2563eb' },
    { name: 'Meta', valor: Math.max(0, metaAnual - faturamentoTotal), fill: '#f1f5f9' }
  ];

  const dataMetaProducao = [
    { name: 'Produção', valor: faturamentoServicos, fill: '#8b5cf6' },
    { name: 'Meta', valor: Math.max(0, metaProducao - faturamentoServicos), fill: '#f1f5f9' }
  ];

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      {/* Cards de Topo Restaurados */}
      <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
        <MetricCard label="Faturamento" value={`R$ ${faturamentoTotal.toLocaleString('pt-BR')}`} icon={DollarSign} color="text-blue-600" bg="bg-blue-50" />
        <MetricCard label="Assinaturas" value={`R$ ${faturamentoAssinaturas.toLocaleString('pt-BR')}`} icon={UserCheck} color="text-emerald-500" bg="bg-emerald-50" />
        <MetricCard label="Saídas" value={`R$ ${saidaTotal.toLocaleString('pt-BR')}`} icon={ArrowDownCircle} color="text-red-500" bg="bg-red-50" />
        <MetricCard label="Saldo Total" value={`R$ ${saldoFinal.toLocaleString('pt-BR')}`} icon={Wallet} color="text-slate-800" bg="bg-slate-100" />
        <MetricCard label="Mês Destaque" value={melhorMes?.name} icon={Crown} color="text-amber-500" bg="bg-amber-50" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Dashboard 1: Meta x Realidade do Ano */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100 relative overflow-hidden">
          <div className="flex justify-between items-start mb-8">
            <div>
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Target size={20} className="text-blue-600" /> Meta Anual do Negócio
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Faturamento Global vs Objetivo {year}</p>
            </div>
            <div className="text-right">
              <p className="text-2xl font-black text-blue-600">{Math.round((faturamentoTotal / metaAnual) * 100)}%</p>
              <p className="text-[8px] font-black text-slate-400 uppercase">Concluído</p>
            </div>
          </div>

          <div className="flex items-center justify-center h-64 relative">
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={dataMetaAnual} innerRadius={80} outerRadius={100} paddingAngle={0} dataKey="valor" startAngle={90} endAngle={450}>
                    {dataMetaAnual.map((entry, index) => <Cell key={index} fill={entry.fill} cornerRadius={10} />)}
                  </Pie>
                </PieChart>
             </ResponsiveContainer>
             <div className="absolute inset-0 flex flex-col items-center justify-center">
                <p className="text-[10px] font-black text-slate-400 uppercase">Faltam</p>
                <p className="text-sm font-black text-slate-800">R$ {Math.max(0, metaAnual - faturamentoTotal).toLocaleString('pt-BR')}</p>
             </div>
          </div>
          <div className="grid grid-cols-2 gap-4 mt-4">
             <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <p className="text-[8px] font-black text-slate-400 uppercase">Meta {year}</p>
                <p className="text-sm font-black">R$ {metaAnual.toLocaleString('pt-BR')}</p>
             </div>
             <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100 text-blue-900">
                <p className="text-[8px] font-black text-blue-400 uppercase">Realizado</p>
                <p className="text-sm font-black">R$ {faturamentoTotal.toLocaleString('pt-BR')}</p>
             </div>
          </div>
        </div>

        {/* Dashboard 2: Meta Operacional x Produção */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100 relative overflow-hidden">
          <div className="flex justify-between items-start mb-8">
            <div>
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Scissors size={20} className="text-purple-600" /> Produção x Meta Operacional
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Eficiência das Cadeiras em {year}</p>
            </div>
            <div className="text-right">
              <p className="text-2xl font-black text-purple-600">{Math.round((faturamentoServicos / metaProducao) * 100)}%</p>
              <p className="text-[8px] font-black text-slate-400 uppercase">Eficiência</p>
            </div>
          </div>

          <div className="flex items-center justify-center h-64 relative">
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={dataMetaProducao} innerRadius={80} outerRadius={100} paddingAngle={0} dataKey="valor" startAngle={90} endAngle={450}>
                    {dataMetaProducao.map((entry, index) => <Cell key={index} fill={entry.fill} cornerRadius={10} />)}
                  </Pie>
                </PieChart>
             </ResponsiveContainer>
             <div className="absolute inset-0 flex flex-col items-center justify-center">
                <p className="text-[10px] font-black text-slate-400 uppercase">Realizado</p>
                <p className="text-sm font-black text-slate-800">R$ {faturamentoServicos.toLocaleString('pt-BR')}</p>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-4 mt-4">
             <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <p className="text-[8px] font-black text-slate-400 uppercase">Objetivo Cadeiras</p>
                <p className="text-sm font-black">R$ {metaProducao.toLocaleString('pt-BR')}</p>
             </div>
             <div className="p-4 bg-purple-50 rounded-2xl border border-purple-100 text-purple-900">
                <p className="text-[8px] font-black text-purple-400 uppercase">Produção Real</p>
                <p className="text-sm font-black">R$ {faturamentoServicos.toLocaleString('pt-BR')}</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const MetricCard = ({ label, value, icon: Icon, color, bg }: any) => (
  <div className="bg-white p-5 rounded-[32px] border border-slate-100 shadow-sm flex flex-col gap-2 group hover:scale-[1.02] transition-all">
    <div className={`w-10 h-10 ${bg} ${color} rounded-xl flex items-center justify-center mb-1`}>
      <Icon size={20} />
    </div>
    <div>
      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{label}</p>
      <h3 className="text-sm font-black text-slate-800 truncate">{value}</h3>
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal } from '../types';
import { PlusCircle, X, Settings2, Save, Edit2, Eye, TrendingUp, DollarSign, Wallet, Users, Target, UserMinus, ShoppingCart, UserCheck, Plus, ArrowUpRight, ArrowDownRight, PieChart as PieChartIcon, Trophy } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);
  const [newCategory, setNewCategory] = useState('');

  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, 
          nome: prof.nome, 
          bruta: p?.producaoBruta || 0, 
          repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0,
          vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0,
        cartao: extra?.cartao || 0,
        pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0,
        pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0,
        cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods,
        gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;

    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const handleAddCategory = () => {
    if (!newCategory || data.categoriasGastos.includes(newCategory)) return;
    const updatedCats = [...data.categoriasGastos, newCategory];
    setData({ ...data, categoriasGastos: updatedCats });
    setFormData({
      ...formData,
      gastos: [...formData.gastos, { categoria: newCategory, valor: 0 }]
    });
    setNewCategory('');
  };

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };

    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));

    const newGastos: GastoMensal[] = formData.gastos.map(g => ({
      ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor
    }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });

    setShowModal(false);
  };

  const monthDetailData = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];
    const expenseData = m.gastosList.map(g => ({ name: g.categoria, value: g.valor }));
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const profRanking = data.profissionais.map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const bruta = p?.producaoBruta || 0;
      const recServicos = p ? (p.producaoBruta - p.repasseProfissional - p.repasseAssinatura) : 0;
      const recAssinaturas = p?.repasseAssinatura || 0;
      return {
        nome: prof.nome,
        bruta,
        recServicos,
        recAssinaturas,
        total: recServicos + recAssinaturas
      };
    }).sort((a, b) => b.total - a.total);

    return { ...m, expenseData, COLORS, profRanking };
  }, [selectedMonth, matrix, data.profissionais]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-slate-800">Fluxo Estratégico</h2>
          <p className="text-xs text-slate-400">Clique em "Ver Detalhes" para inteligência do mês</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase shadow-lg shadow-blue-100 flex items-center gap-2">
          <PlusCircle size={18} /> Fechamento do Mês
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-50 overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
            <tr>
              <th className="px-6 py-5">Mês</th>
              <th className="px-6 py-5 text-right">Rec. Bruta</th>
              <th className="px-6 py-5 text-right">Saídas/Repasses</th>
              <th className="px-6 py-5 text-right">Líquido</th>
              <th className="px-6 py-5 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((m) => (
              <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                <td className="px-6 py-5 font-bold text-slate-800">{m.nome}</td>
                <td className="px-6 py-5 text-right font-bold text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                <td className="px-6 py-5 text-right text-red-500 font-medium">R$ {(m.repasse + m.gastosTotal).toLocaleString('pt-BR')}</td>
                <td className={`px-6 py-5 text-right font-black ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                  R$ {m.liquido.toLocaleString('pt-BR')}
                </td>
                <td className="px-6 py-5 text-center flex justify-center gap-2">
                  <button onClick={() => { setSelectedMonth(m.mes); setShowDetailModal(true); }} className="p-2 bg-slate-100 text-slate-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all">
                    <Eye size={16} />
                  </button>
                  <button onClick={() => { setFormData(prev => ({ ...prev, mes: m.mes })); setShowModal(true); }} className="p-2 bg-slate-100 text-slate-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all">
                    <Edit2 size={16} />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modal Fechamento */}
      {showModal && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-white sticky top-0 z-10">
              <h3 className="text-xl font-black text-slate-800">Fechamento Mensal</h3>
              <button onClick={() => setShowModal(false)} className="bg-slate-50 p-3 rounded-full text-slate-400 hover:text-slate-600"><X /></button>
            </div>

            <div className="p-8 overflow-y-auto space-y-8 flex-1">
              <div className="grid grid-cols-2 gap-4">
                <Input label="Mês" type="select" value={formData.mes} onChange={(v: number) => setFormData({...formData, mes: v})} options={meses.map((m, i) => ({ label: m, value: i+1 }))} />
                <Input label="Entrada Assinaturas" value={formData.assinaturas} onChange={(v: number) => setFormData({...formData, assinaturas: v})} />
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2 text-red-500">
                  <ArrowDownRight size={18} /> Saídas e Gastos
                </h4>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  {formData.gastos.map((g, idx) => (
                    <MiniInput key={g.categoria} label={g.categoria} value={g.valor} onChange={(v: number) => { let n = [...formData.gastos]; n[idx].valor = v; setFormData({...formData, gastos: n}); }} />
                  ))}
                </div>
                <div className="flex gap-2">
                  <input type="text" placeholder="Nova Categoria..." className="flex-1 p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold" value={newCategory} onChange={(e) => setNewCategory(e.target.value)} />
                  <button onClick={handleAddCategory} className="bg-slate-900 text-white p-3 rounded-xl"><Plus size={16} /></button>
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2 text-blue-600">
                  <Scissors size={18} /> Produção dos Barbeiros
                </h4>
                <div className="space-y-3">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-5 bg-slate-50 rounded-[28px] border border-slate-100 grid grid-cols-3 gap-3">
                      <span className="col-span-3 text-[10px] font-black text-slate-400 uppercase">{p.nome}</span>
                      <MiniInput label="Bruto" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                      <MiniInput label="Repasse" value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                      <MiniInput label="Assinatura" value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t border-slate-100 flex gap-4">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-4 rounded-3xl font-black shadow-lg flex items-center justify-center gap-2">
                <Save size={18} /> SALVAR FECHAMENTO
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Detalhes do Mês */}
      {showDetailModal && monthDetailData && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[40px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in slide-in-from-bottom-8">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-900 text-white">
              <div>
                <h3 className="text-2xl font-black">Detalhamento: {monthDetailData.nome} {year}</h3>
                <p className="text-[10px] font-bold text-blue-400 uppercase tracking-widest">Inteligência Estratégica Mensal</p>
              </div>
              <button onClick={() => setShowDetailModal(false)} className="bg-white/10 p-3 rounded-full text-white/50 hover:text-white"><X /></button>
            </div>

            <div className="p-8 overflow-y-auto space-y-8 flex-1">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <SummaryCard label="Rec. Bruta" value={`R$ ${monthDetailData.bruta.toLocaleString('pt-BR')}`} icon={ArrowUpRight} color="text-blue-600" />
                <SummaryCard label="Saídas Totais" value={`R$ ${(monthDetailData.repasse + monthDetailData.gastosTotal).toLocaleString('pt-BR')}`} icon={ArrowDownRight} color="text-red-500" />
                <SummaryCard label="Novos Assinantes" value={`+${monthDetailData.extra?.novosAssinantes || 0}`} icon={UserCheck} color="text-emerald-500" />
                <SummaryCard label="Churn (Saídas)" value={`-${monthDetailData.extra?.cancelamentosAssinantes || 0}`} icon={UserMinus} color="text-amber-500" />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <h4 className="font-black text-slate-800 mb-6 flex items-center gap-2">
                    <PieChartIcon size={18} className="text-red-500" /> Ranking de Gastos
                  </h4>
                  <div className="h-48">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={monthDetailData.expenseData} innerRadius={50} outerRadius={70} paddingAngle={5} dataKey="value">
                          {monthDetailData.expenseData.map((entry: any, index: number) => (
                            <Cell key={index} fill={monthDetailData.COLORS[index % monthDetailData.COLORS.length]} />
                          ))}
                        </Pie>
                        <Tooltip />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="mt-4 space-y-2">
                    {monthDetailData.expenseData.sort((a:any,b:any)=>b.value-a.value).slice(0,3).map((g:any, idx:number)=>(
                       <div key={g.name} className="flex justify-between text-[10px] font-black uppercase">
                          <span className="text-slate-400">{g.name}</span>
                          <span className="text-slate-800">R$ {g.value.toLocaleString('pt-BR')}</span>
                       </div>
                    ))}
                  </div>
                </div>

                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2">
                    <Trophy size={18} className="text-amber-500" /> Destaque do Mês
                  </h4>
                  <div className="flex items-center gap-4 mb-6">
                    <div className="w-16 h-16 bg-amber-400 rounded-3xl flex items-center justify-center text-white shadow-lg">
                      <Star size={32} />
                    </div>
                    <div>
                      <p className="text-lg font-black text-slate-800">{monthDetailData.profRanking[0].nome}</p>
                      <p className="text-[10px] font-black text-slate-400 uppercase">Campeão de Faturamento da Casa</p>
                    </div>
                  </div>
                  <p className="text-xs text-slate-500 leading-relaxed italic">
                    "Este barbeiro gerou R$ {monthDetailData.profRanking[0].total.toLocaleString('pt-BR')} de lucro líquido para a casa este mês."
                  </p>
                </div>
              </div>

              <div className="bg-white rounded-[32px] border border-slate-100 overflow-hidden">
                <div className="p-6 border-b border-slate-50">
                  <h4 className="font-black text-slate-800">Ranking Profissional do Mês</h4>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-left text-xs">
                    <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                      <tr>
                        <th className="px-6 py-4">Barbeiro</th>
                        <th className="px-6 py-4 text-right">Produção Bruta</th>
                        <th className="px-6 py-4 text-right">Rec. Serviços (Casa)</th>
                        <th className="px-6 py-4 text-right">Rec. Assinaturas</th>
                        <th className="px-6 py-4 text-right font-black text-blue-600">Total Casa</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 font-bold">
                      {monthDetailData.profRanking.map((p: any) => (
                        <tr key={p.nome}>
                          <td className="px-6 py-4 text-slate-800">{p.nome}</td>
                          <td className="px-6 py-4 text-right text-slate-500">R$ {p.bruta.toLocaleString('pt-BR')}</td>
                          <td className="px-6 py-4 text-right text-slate-500">R$ {p.recServicos.toLocaleString('pt-BR')}</td>
                          <td className="px-6 py-4 text-right text-emerald-600">R$ {p.recAssinaturas.toLocaleString('pt-BR')}</td>
                          <td className="px-6 py-4 text-right font-black text-blue-600">R$ {p.total.toLocaleString('pt-BR')}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const Input = ({ label, value, onChange, type = 'number', options = [] }: any) => (
  <div className="space-y-1">
    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</label>
    {type === 'select' ? (
      <select className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-sm" value={value} onChange={(e) => onChange(Number(e.target.value))}>
        {options.map((o:any) => <option key={o.value} value={o.value}>{o.label}</option>)}
      </select>
    ) : (
      <input type="number" value={value === 0 ? '' : value} onChange={(e) => onChange(Number(e.target.value))} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-800" />
    )}
  </div>
);

const MiniInput = ({ label, value, onChange }: any) => (
  <div>
    <label className="text-[8px] font-black text-slate-400 uppercase block mb-1 truncate">{label}</label>
    <input type="number" value={value === 0 ? '' : value} onChange={(e) => onChange(Number(e.target.value))} className="w-full p-2 bg-white border border-slate-200 rounded-xl text-xs font-bold" />
  </div>
);

const SummaryCard = ({ label, value, icon: Icon, color }: any) => (
  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
    <div className={`w-8 h-8 rounded-lg ${color.replace('text', 'bg').replace('-600', '-100')} ${color} flex items-center justify-center mb-2`}>
      <Icon size={16} />
    </div>
    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{label}</p>
    <p className={`text-sm font-black ${color}`}>{value}</p>
  </div>
);

export default CashFlow;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal } from '../types';
// Added Scissors and Star to the import list to fix "Cannot find name" errors
import { PlusCircle, X, Settings2, Save, Edit2, Eye, TrendingUp, DollarSign, Wallet, Users, Target, UserMinus, ShoppingCart, UserCheck, Plus, ArrowUpRight, ArrowDownRight, PieChart as PieChartIcon, Trophy, Scissors, Star } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);
  const [newCategory, setNewCategory] = useState('');

  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, 
          nome: prof.nome, 
          bruta: p?.producaoBruta || 0, 
          repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0,
          vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0,
        cartao: extra?.cartao || 0,
        pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0,
        pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0,
        cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods,
        gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;

    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const handleAddCategory = () => {
    if (!newCategory || data.categoriasGastos.includes(newCategory)) return;
    const updatedCats = [...data.categoriasGastos, newCategory];
    setData({ ...data, categoriasGastos: updatedCats });
    setFormData({
      ...formData,
      gastos: [...formData.gastos, { categoria: newCategory, valor: 0 }]
    });
    setNewCategory('');
  };

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };

    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));

    const newGastos: GastoMensal[] = formData.gastos.map(g => ({
      ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor
    }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });

    setShowModal(false);
  };

  const monthDetailData = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];
    const expenseData = m.gastosList.map(g => ({ name: g.categoria, value: g.valor }));
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const profRanking = data.profissionais.map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const bruta = p?.producaoBruta || 0;
      const recServicos = p ? (p.producaoBruta - p.repasseProfissional - p.repasseAssinatura) : 0;
      const recAssinaturas = p?.repasseAssinatura || 0;
      return {
        nome: prof.nome,
        bruta,
        recServicos,
        recAssinaturas,
        total: recServicos + recAssinaturas
      };
    }).sort((a, b) => b.total - a.total);

    return { ...m, expenseData, COLORS, profRanking };
  }, [selectedMonth, matrix, data.profissionais]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-slate-800">Fluxo Estratégico</h2>
          <p className="text-xs text-slate-400">Clique em "Ver Detalhes" para inteligência do mês</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase shadow-lg shadow-blue-100 flex items-center gap-2">
          <PlusCircle size={18} /> Fechamento do Mês
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-50 overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
            <tr>
              <th className="px-6 py-5">Mês</th>
              <th className="px-6 py-5 text-right">Rec. Bruta</th>
              <th className="px-6 py-5 text-right">Saídas/Repasses</th>
              <th className="px-6 py-5 text-right">Líquido</th>
              <th className="px-6 py-5 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((m) => (
              <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                <td className="px-6 py-5 font-bold text-slate-800">{m.nome}</td>
                <td className="px-6 py-5 text-right font-bold text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                <td className="px-6 py-5 text-right text-red-500 font-medium">R$ {(m.repasse + m.gastosTotal).toLocaleString('pt-BR')}</td>
                <td className={`px-6 py-5 text-right font-black ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                  R$ {m.liquido.toLocaleString('pt-BR')}
                </td>
                <td className="px-6 py-5 text-center flex justify-center gap-2">
                  <button onClick={() => { setSelectedMonth(m.mes); setShowDetailModal(true); }} className="p-2 bg-slate-100 text-slate-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all">
                    <Eye size={16} />
                  </button>
                  <button onClick={() => { setFormData(prev => ({ ...prev, mes: m.mes })); setShowModal(true); }} className="p-2 bg-slate-100 text-slate-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all">
                    <Edit2 size={16} />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modal Fechamento */}
      {showModal && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-white sticky top-0 z-10">
              <h3 className="text-xl font-black text-slate-800">Fechamento Mensal</h3>
              <button onClick={() => setShowModal(false)} className="bg-slate-50 p-3 rounded-full text-slate-400 hover:text-slate-600"><X /></button>
            </div>

            <div className="p-8 overflow-y-auto space-y-8 flex-1">
              <div className="grid grid-cols-2 gap-4">
                <Input label="Mês" type="select" value={formData.mes} onChange={(v: number) => setFormData({...formData, mes: v})} options={meses.map((m, i) => ({ label: m, value: i+1 }))} />
                <Input label="Entrada Assinaturas" value={formData.assinaturas} onChange={(v: number) => setFormData({...formData, assinaturas: v})} />
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2 text-red-500">
                  <ArrowDownRight size={18} /> Saídas e Gastos
                </h4>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  {formData.gastos.map((g, idx) => (
                    <MiniInput key={g.categoria} label={g.categoria} value={g.valor} onChange={(v: number) => { let n = [...formData.gastos]; n[idx].valor = v; setFormData({...formData, gastos: n}); }} />
                  ))}
                </div>
                <div className="flex gap-2">
                  <input type="text" placeholder="Nova Categoria..." className="flex-1 p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold" value={newCategory} onChange={(e) => setNewCategory(e.target.value)} />
                  <button onClick={handleAddCategory} className="bg-slate-900 text-white p-3 rounded-xl"><Plus size={16} /></button>
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2 text-blue-600">
                  <Scissors size={18} /> Produção dos Barbeiros
                </h4>
                <div className="space-y-3">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-5 bg-slate-50 rounded-[28px] border border-slate-100 grid grid-cols-3 gap-3">
                      <span className="col-span-3 text-[10px] font-black text-slate-400 uppercase">{p.nome}</span>
                      <MiniInput label="Bruto" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                      <MiniInput label="Repasse" value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                      <MiniInput label="Assinatura" value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t border-slate-100 flex gap-4">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-4 rounded-3xl font-black shadow-lg flex items-center justify-center gap-2">
                <Save size={18} /> SALVAR FECHAMENTO
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Detalhes do Mês */}
      {showDetailModal && monthDetailData && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[40px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in slide-in-from-bottom-8">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-900 text-white">
              <div>
                <h3 className="text-2xl font-black">Detalhamento: {monthDetailData.nome} {year}</h3>
                <p className="text-[10px] font-bold text-blue-400 uppercase tracking-widest">Inteligência Estratégica Mensal</p>
              </div>
              <button onClick={() => setShowDetailModal(false)} className="bg-white/10 p-3 rounded-full text-white/50 hover:text-white"><X /></button>
            </div>

            <div className="p-8 overflow-y-auto space-y-8 flex-1">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <SummaryCard label="Rec. Bruta" value={`R$ ${monthDetailData.bruta.toLocaleString('pt-BR')}`} icon={ArrowUpRight} color="text-blue-600" />
                <SummaryCard label="Saídas Totais" value={`R$ ${(monthDetailData.repasse + monthDetailData.gastosTotal).toLocaleString('pt-BR')}`} icon={ArrowDownRight} color="text-red-500" />
                <SummaryCard label="Novos Assinantes" value={`+${monthDetailData.extra?.novosAssinantes || 0}`} icon={UserCheck} color="text-emerald-500" />
                <SummaryCard label="Churn (Saídas)" value={`-${monthDetailData.extra?.cancelamentosAssinantes || 0}`} icon={UserMinus} color="text-amber-500" />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <h4 className="font-black text-slate-800 mb-6 flex items-center gap-2">
                    <PieChartIcon size={18} className="text-red-500" /> Ranking de Gastos
                  </h4>
                  <div className="h-48">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={monthDetailData.expenseData} innerRadius={50} outerRadius={70} paddingAngle={5} dataKey="value">
                          {monthDetailData.expenseData.map((entry: any, index: number) => (
                            <Cell key={index} fill={monthDetailData.COLORS[index % monthDetailData.COLORS.length]} />
                          ))}
                        </Pie>
                        <Tooltip />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="mt-4 space-y-2">
                    {monthDetailData.expenseData.sort((a:any,b:any)=>b.value-a.value).slice(0,3).map((g:any, idx:number)=>(
                       <div key={g.name} className="flex justify-between text-[10px] font-black uppercase">
                          <span className="text-slate-400">{g.name}</span>
                          <span className="text-slate-800">R$ {g.value.toLocaleString('pt-BR')}</span>
                       </div>
                    ))}
                  </div>
                </div>

                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2">
                    <Trophy size={18} className="text-amber-500" /> Destaque do Mês
                  </h4>
                  <div className="flex items-center gap-4 mb-6">
                    <div className="w-16 h-16 bg-amber-400 rounded-3xl flex items-center justify-center text-white shadow-lg">
                      <Star size={32} />
                    </div>
                    <div>
                      <p className="text-lg font-black text-slate-800">{monthDetailData.profRanking[0].nome}</p>
                      <p className="text-[10px] font-black text-slate-400 uppercase">Campeão de Faturamento da Casa</p>
                    </div>
