import React, { useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { AppData } from '../types';
import { DollarSign, Crown, ArrowDownCircle, Wallet, UserCheck, Target, Scissors } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const calculations = useMemo(() => {
    const params = data.parametros.find(p => p.ano === year) || data.parametros[0];
    const metaAnual = params?.metaFaturamento || 0;
    // Meta de produção baseada na meta por cadeira * número de cadeiras * 12 meses
    const metaProducao = (params?.metaPorCadeira || 0) * data.profissionais.length * 12;

    const producaoAno = data.producao.filter(p => p.ano === year);
    const receitasAno = data.receitasExtras.filter(r => r.ano === year);
    const gastosAno = data.gastos.filter(g => g.ano === year);

    const faturamentoServicos = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0);
    const faturamentoAssinaturas = receitasAno.reduce((acc, r) => acc + r.assinaturas, 0);
    const faturamentoOutros = receitasAno.reduce((acc, r) => acc + r.pacotes + r.geladeira + r.dinheiro + r.cartao + r.pix, 0);

    const faturamentoTotal = faturamentoServicos + faturamentoOutros + faturamentoAssinaturas;
    const totalGastos = gastosAno.reduce((acc, curr) => acc + curr.valor, 0);
    const totalRepasses = producaoAno.reduce((acc, curr) => acc + curr.repasseProfissional + curr.repasseAssinatura, 0);
    const saidaTotal = totalGastos + totalRepasses;
    const saldoFinal = faturamentoTotal - saidaTotal;

    const meses = Array.from({ length: 12 }, (_, i) => {
      const mes = i + 1;
      const pMes = producaoAno.filter(p => p.mes === mes);
      const rMes = receitasAno.find(r => r.mes === mes);
      const totalMes = pMes.reduce((s, c) => s + c.producaoBruta, 0) + 
                       (rMes ? (rMes.pacotes + rMes.assinaturas + rMes.geladeira + rMes.dinheiro + rMes.cartao + rMes.pix) : 0);
      const repMes = pMes.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
      const gMes = gastosAno.filter(g => g.mes === mes).reduce((s, c) => s + c.valor, 0);
      return { 
        name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i], 
        Faturamento: totalMes,
        Lucro: totalMes - repMes - gMes
      };
    });

    const melhorMes = [...meses].sort((a, b) => b.Lucro - a.Lucro)[0];

    return { 
      faturamentoTotal, faturamentoAssinaturas, saidaTotal, saldoFinal, 
      melhorMes, metaAnual, metaProducao, faturamentoServicos 
    };
  }, [data, year]);

  const { faturamentoTotal, faturamentoAssinaturas, saidaTotal, saldoFinal, melhorMes, metaAnual, metaProducao, faturamentoServicos } = calculations;

  const dataMetaAnual = [
    { name: 'Realizado', value: faturamentoTotal, fill: '#2563eb' },
    { name: 'Meta Restante', value: Math.max(0, metaAnual - faturamentoTotal), fill: '#f1f5f9' }
  ];

  const dataMetaProducao = [
    { name: 'Produção', value: faturamentoServicos, fill: '#8b5cf6' },
    { name: 'Meta Restante', value: Math.max(0, metaProducao - faturamentoServicos), fill: '#f1f5f9' }
  ];

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      {/* Cards de Topo Restaurados */}
      <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
        <MetricCard label="Faturamento" value={`R$ ${faturamentoTotal.toLocaleString('pt-BR')}`} icon={DollarSign} color="text-blue-600" bg="bg-blue-50" />
        <MetricCard label="Assinaturas" value={`R$ ${faturamentoAssinaturas.toLocaleString('pt-BR')}`} icon={UserCheck} color="text-emerald-500" bg="bg-emerald-50" />
        <MetricCard label="Saída Total" value={`R$ ${saidaTotal.toLocaleString('pt-BR')}`} icon={ArrowDownCircle} color="text-red-500" bg="bg-red-50" />
        <MetricCard label="Saldo Final" value={`R$ ${saldoFinal.toLocaleString('pt-BR')}`} icon={Wallet} color="text-slate-800" bg="bg-slate-100" />
        <MetricCard label="Mês Destaque" value={melhorMes?.name} icon={Crown} color="text-amber-500" bg="bg-amber-50" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Dashboard 1: Meta x Realidade do Ano */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <div className="flex justify-between items-start mb-4">
            <div>
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Target size={20} className="text-blue-600" /> Meta x Realidade Anual
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Faturamento Global vs Objetivo {year}</p>
            </div>
            <div className="text-right">
              <p className="text-2xl font-black text-blue-600">
                {metaAnual > 0 ? Math.round((faturamentoTotal / metaAnual) * 100) : 0}%
              </p>
              <p className="text-[8px] font-black text-slate-400 uppercase">Atingido</p>
            </div>
          </div>

          <div className="h-64 relative flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={dataMetaAnual}
                  innerRadius={70}
                  outerRadius={90}
                  paddingAngle={0}
                  dataKey="value"
                  startAngle={90}
                  endAngle={450}
                >
                  {dataMetaAnual.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.fill} cornerRadius={10} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`} />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
              <p className="text-[10px] font-black text-slate-400 uppercase">Realizado</p>
              <p className="text-lg font-black text-slate-800">R$ {faturamentoTotal.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 mt-6">
            <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <p className="text-[8px] font-black text-slate-400 uppercase">Meta {year}</p>
              <p className="text-sm font-black">R$ {metaAnual.toLocaleString('pt-BR')}</p>
            </div>
            <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100 text-blue-900">
              <p className="text-[8px] font-black text-blue-400 uppercase">Faltam</p>
              <p className="text-sm font-black">R$ {Math.max(0, metaAnual - faturamentoTotal).toLocaleString('pt-BR')}</p>
            </div>
          </div>
        </div>

        {/* Dashboard 2: Meta Estipulada x Realidade de Produção */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <div className="flex justify-between items-start mb-4">
            <div>
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Scissors size={20} className="text-purple-600" /> Meta x Realidade Produção
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Produção Bruta das Cadeiras em {year}</p>
            </div>
            <div className="text-right">
              <p className="text-2xl font-black text-purple-600">
                {metaProducao > 0 ? Math.round((faturamentoServicos / metaProducao) * 100) : 0}%
              </p>
              <p className="text-[8px] font-black text-slate-400 uppercase">Eficiência</p>
            </div>
          </div>

          <div className="h-64 relative flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={dataMetaProducao}
                  innerRadius={70}
                  outerRadius={90}
                  paddingAngle={0}
                  dataKey="value"
                  startAngle={90}
                  endAngle={450}
                >
                  {dataMetaProducao.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.fill} cornerRadius={10} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`} />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
              <p className="text-[10px] font-black text-slate-400 uppercase">Produção</p>
              <p className="text-lg font-black text-slate-800">R$ {faturamentoServicos.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 mt-6">
            <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <p className="text-[8px] font-black text-slate-400 uppercase">Meta Operacional</p>
              <p className="text-sm font-black">R$ {metaProducao.toLocaleString('pt-BR')}</p>
            </div>
            <div className="p-4 bg-purple-50 rounded-2xl border border-purple-100 text-purple-900">
              <p className="text-[8px] font-black text-purple-400 uppercase">Faltam</p>
              <p className="text-sm font-black">R$ {Math.max(0, metaProducao - faturamentoServicos).toLocaleString('pt-BR')}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const MetricCard = ({ label, value, icon: Icon, color, bg }: any) => (
