export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal } from '../types';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, DollarSign, UserMinus, UserCheck, Plus, ArrowUpRight, ArrowDownRight, PieChart as PieChartIcon, Trophy, Scissors, Star, LayoutDashboard } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);
  const [newCategory, setNewCategory] = useState('');

  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, 
          nome: prof.nome, 
          bruta: p?.producaoBruta || 0, 
          repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0,
          vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0,
        cartao: extra?.cartao || 0,
        pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0,
        pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0,
        cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods,
        gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;

    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const handleAddCategory = () => {
    if (!newCategory || data.categoriasGastos.includes(newCategory)) return;
    const updatedCats = [...data.categoriasGastos, newCategory];
    setData({ ...data, categoriasGastos: updatedCats });
    setFormData({
      ...formData,
      gastos: [...formData.gastos, { categoria: newCategory, valor: 0 }]
    });
    setNewCategory('');
  };

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };

    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));

    const newGastos: GastoMensal[] = formData.gastos.map(g => ({
      ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor
    }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });

    setShowModal(false);
  };

  const monthDetailData = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];

    // Create new copies to avoid "read only" errors when sorting
    const expenseData = [...m.gastosList].map(g => ({ name: g.categoria, value: g.valor }));
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const profRanking = [...data.profissionais].map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const bruta = p?.producaoBruta || 0;
      // House keep = Total Gross - Professional Cut (Services + Subscriptions)
      const recServicos = p ? (p.producaoBruta - p.repasseProfissional - p.repasseAssinatura) : 0;
      const recAssinaturas = p?.repasseAssinatura || 0;
      return {
        nome: prof.nome,
        bruta,
        recServicos,
        recAssinaturas,
        totalCasa: recServicos + recAssinaturas
      };
    }).sort((a, b) => b.totalCasa - a.totalCasa);

    return { ...m, expenseData, COLORS, profRanking };
  }, [selectedMonth, matrix, data.profissionais]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-slate-800">Fluxo Mensal</h2>
          <p className="text-xs text-slate-400">Gerencie fechamentos e veja detalhes inteligentes</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase shadow-lg shadow-blue-100 flex items-center gap-2">
          <PlusCircle size={18} /> Fechamento do Mês
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-50 overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
            <tr>
              <th className="px-6 py-5">Mês</th>
              <th className="px-6 py-5 text-right">Rec. Bruta</th>
              <th className="px-6 py-5 text-right">Saídas</th>
              <th className="px-6 py-5 text-right">Líquido</th>
              <th className="px-6 py-5 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((m) => (
              <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                <td className="px-6 py-5 font-bold text-slate-800">{m.nome}</td>
                <td className="px-6 py-5 text-right font-bold text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                <td className="px-6 py-5 text-right text-red-500 font-medium">R$ {(m.repasse + m.gastosTotal).toLocaleString('pt-BR')}</td>
                <td className={`px-6 py-5 text-right font-black ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                  R$ {m.liquido.toLocaleString('pt-BR')}
                </td>
                <td className="px-6 py-5 text-center flex justify-center gap-2">
                  <button onClick={() => { setSelectedMonth(m.mes); setShowDetailModal(true); }} className="p-2 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-xl transition-all" title="Ver Detalhes">
                    <Eye size={16} />
                  </button>
