import React, { useState, useEffect } from 'react';
import { MOCK_DATA } from './constants';
import { AppData } from './types';
import Dashboard from './components/Dashboard';
import Professionals from './components/Professionals';
import CashFlow from './components/CashFlow';
import Expenses from './components/Expenses';
import Config from './components/Config';
import Meetings from './components/Meetings';
import Subscriptions from './components/Subscriptions';
import Navigation from './components/Navigation';
import { Save } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('barber_bi_data');
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        return MOCK_DATA;
      }
    }
    return MOCK_DATA;
  });

  const [lastSaved, setLastSaved] = useState<string>('');

  // Salvar automaticamente sempre que os dados mudarem
  useEffect(() => {
    localStorage.setItem('barber_bi_data', JSON.stringify(data));
    setLastSaved(new Date().toLocaleTimeString());
  }, [data]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard data={data} year={selectedYear} />;
      case 'professionals': return <Professionals data={data} setData={setData} year={selectedYear} />;
      case 'fluxo': return <CashFlow data={data} setData={setData} year={selectedYear} />;
      case 'assinaturas': return <Subscriptions data={data} year={selectedYear} />;
      case 'reuniao': return <Meetings data={data} setData={setData} />;
      case 'gastos': return <Expenses data={data} year={selectedYear} />;
      case 'config': return <Config data={data} setData={setData} selectedYear={selectedYear} setSelectedYear={setSelectedYear} />;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col pb-24 md:pb-0 md:pl-0 bg-slate-50">
      <header className="bg-white/80 backdrop-blur-md sticky top-0 z-50 px-6 py-4 flex justify-between items-center border-b border-slate-100">
        <div className="flex items-center gap-4">
          <div>
            <h2 className="text-lg font-extrabold text-slate-800">BarberPro BI</h2>
            <div className="flex items-center gap-2">
              <span className="text-[10px] text-blue-600 font-bold uppercase tracking-widest">Ano: {selectedYear}</span>
              <span className="text-[8px] text-slate-300">•</span>
              <div className="flex items-center gap-1 text-[9px] text-emerald-500 font-bold uppercase">
                <Save size={10} />
                Salvo {lastSaved}
              </div>
            </div>
          </div>
        </div>
        <div className="bg-slate-900 text-white px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-tighter shadow-lg shadow-slate-200">
          Modo Local Ativo
        </div>
      </header>

      <main className="flex-1 p-6 max-w-5xl mx-auto w-full">
        {renderContent()}
      </main>

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { AppData, ParametrosAnuais } from '../types';
import { FileSpreadsheet, RefreshCw, CheckCircle2, CalendarPlus, Settings2, Save, Trash2, Target, Download, Upload, ShieldCheck, Database } from 'lucide-react';

interface ConfigProps {
  data: AppData;
  setData: (data: AppData) => void;
  selectedYear: number;
  setSelectedYear: (year: number) => void;
}

const Config: React.FC<ConfigProps> = ({ data, setData, selectedYear, setSelectedYear }) => {
  const [sheetUrl, setSheetUrl] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [showNewYearModal, setShowNewYearModal] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [newYearForm, setNewYearForm] = useState<ParametrosAnuais>({
    ano: new Date().getFullYear() + 1,
    metaFaturamento: 0,
    metaLucro: 0,
    metaAssinaturas: 0,
    metaGeladeira: 0,
    metaGastos: 0,
    metaPorCadeira: 5000
  });

  const handleSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      setIsSyncing(false);
      alert('Sincronização concluída!');
    }, 1500);
  };

  const exportBackup = () => {
    const dataStr = JSON.stringify(data, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const exportFileDefaultName = `backup_barber_bi_${new Date().toISOString().split('T')[0]}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const importBackup = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        if (json.profissionais && json.producao) {
          if (confirm('Atenção: Isso substituirá todos os seus dados atuais. Deseja continuar?')) {
            setData(json);
            alert('Backup restaurado com sucesso!');
          }
        } else {
          alert('Arquivo de backup inválido.');
        }
      } catch (err) {
        alert('Erro ao ler o arquivo.');
      }
    };
    reader.readAsText(file);
  };

  const handleCreateNewYear = () => {
    if (data.parametros.some(p => p.ano === newYearForm.ano)) {
      alert('Este ano já está configurado!');
      return;
    }
    setData({ ...data, parametros: [...data.parametros, newYearForm] });
    setSelectedYear(newYearForm.ano);
    setShowNewYearModal(false);
  };

  const handleRemoveYear = (ano: number) => {
    if (data.parametros.length <= 1) return;
    if (confirm(`Remover metas de ${ano}?`)) {
      setData({ ...data, parametros: data.parametros.filter(p => p.ano !== ano) });
      if (selectedYear === ano) setSelectedYear(data.parametros[0].ano);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-20">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Ajustes & Sistema</h2>
        <p className="text-sm text-slate-500 font-medium">Configurações de rede e segurança de dados</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Backup Offline */}
        <div className="bg-slate-900 p-8 rounded-[40px] shadow-2xl text-white relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
          <div className="relative z-10">
            <h3 className="font-black text-lg mb-4 flex items-center gap-2">
              <ShieldCheck size={20} className="text-emerald-400" /> Backup Local (Segurança)
            </h3>
            <p className="text-xs text-slate-400 mb-8 leading-relaxed">
              Como você está usando o sistema offline, é importante baixar um backup semanalmente para garantir que não perca dados caso limpe o cache do navegador.
            </p>

            <div className="space-y-3">
              <button 
                onClick={exportBackup}
                className="w-full bg-white/10 hover:bg-white/20 border border-white/10 p-4 rounded-2xl flex items-center justify-between group transition-all"
              >
                <div className="flex items-center gap-3">
                  <Download size={18} className="text-blue-400" />
                  <span className="text-xs font-black uppercase">Exportar Backup (.json)</span>
                </div>
              </button>

              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full bg-white/10 hover:bg-white/20 border border-white/10 p-4 rounded-2xl flex items-center justify-between group transition-all"
              >
                <div className="flex items-center gap-3">
                  <Upload size={18} className="text-emerald-400" />
                  <span className="text-xs font-black uppercase">Restaurar de Arquivo</span>
                </div>
              </button>
              <input type="file" ref={fileInputRef} onChange={importBackup} className="hidden" accept=".json" />
            </div>
          </div>
        </div>

        {/* Gestão de Anos */}
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100 flex flex-col">
          <div className="flex justify-between items-start mb-6">
            <div>
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <CalendarPlus size={20} className="text-blue-600" /> Planejamento Anual
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Metas e Objetivos</p>
            </div>
            <button onClick={() => setShowNewYearModal(true)} className="bg-blue-600 text-white p-2 rounded-xl shadow-lg shadow-blue-100">
              <Plus size={20} />
            </button>
          </div>

          <div className="space-y-3">
            {data.parametros.sort((a,b) => b.ano - a.ano).map(p => (
              <div key={p.ano} className={`p-4 rounded-3xl border flex justify-between items-center ${selectedYear === p.ano ? 'bg-blue-50 border-blue-100' : 'bg-slate-50 border-slate-100'}`}>
                <span className={`font-black ${selectedYear === p.ano ? 'text-blue-600' : 'text-slate-800'}`}>{p.ano}</span>
                <div className="flex gap-2">
                  <button onClick={() => setSelectedYear(p.ano)} className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase ${selectedYear === p.ano ? 'bg-blue-600 text-white' : 'bg-white border text-slate-400'}`}>Ativar</button>
                  <button onClick={() => handleRemoveYear(p.ano)} className="text-slate-200 hover:text-red-500"><Trash2 size={16} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Modal Novo Ano */}
      {showNewYearModal && (
        <div className="fixed inset-0 z-[110] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <h3 className="text-xl font-black text-slate-800">Novo Ciclo</h3>
              <button onClick={() => setShowNewYearModal(false)} className="text-slate-400 hover:text-slate-600"><X /></button>
            </div>

            <div className="p-8 space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ano</label>
                <input type="number" className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl font-black text-lg" value={newYearForm.ano} onChange={(e) => setNewYearForm({...newYearForm, ano: Number(e.target.value)})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-400 uppercase">Faturamento Alvo</label>
                  <input type="number" className="w-full bg-slate-50 p-3 rounded-xl text-xs font-bold" value={newYearForm.metaFaturamento} onChange={(e) => setNewYearForm({...newYearForm, metaFaturamento: Number(e.target.value)})} />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-400 uppercase">Meta/Cadeira</label>
                  <input type="number" className="w-full bg-slate-50 p-3 rounded-xl text-xs font-bold" value={newYearForm.metaPorCadeira} onChange={(e) => setNewYearForm({...newYearForm, metaPorCadeira: Number(e.target.value)})} />
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t border-slate-100 flex gap-4">
              <button onClick={() => setShowNewYearModal(false)} className="flex-1 bg-white border border-slate-200 py-4 rounded-3xl font-bold text-slate-600">Cancelar</button>
              <button onClick={handleCreateNewYear} className="flex-[2] bg-blue-600 text-white py-4 rounded-3xl font-black shadow-lg">INICIAR ANO</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Config;

