      const records = data.producao.filter(p => p.profissionalId === prof.id && p.ano === year);
      const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
      const totalVendas = records.reduce((s, c) => s + (c.vendasProdutos || 0), 0);
      const totalAtendimentos = records.reduce((s, c) => s + (c.quantidadeAtendimentos || 0), 0);
      const conversaoVenda = totalAtendimentos > 0 ? (totalVendas / totalAtendimentos) : 0;
      return { ...prof, totalProd, totalVendas, totalAtendimentos, conversaoVenda };
    }).sort((a, b) => b.totalProd - a.totalProd);
  }, [data.profissionais, data.producao, year]);

  const handleAddProf = () => {
    if (!newProf.nome) return;
    const nProf: Profissional = {
      id: Math.random().toString(36).substr(2, 9),
      nome: newProf.nome,
      cadeira: newProf.cadeira,
      comissao: 50,
      ativo: true,
      perfil: newPerfil
    };
    setData({ ...data, profissionais: [...data.profissionais, nProf] });
    setIsAddingProf(false);
    setNewProf({ nome: '', cadeira: 1 });
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Equipe & Performance</h2>
        </div>
        <button onClick={() => setIsAddingProf(true)} className="bg-blue-600 text-white flex items-center gap-2 px-6 py-3 rounded-2xl shadow-xl shadow-blue-100 font-black text-xs uppercase tracking-widest hover:scale-105 transition-all">
          <Plus size={18} /> Novo Barbeiro
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {ranking.map((prof, idx) => (
          <div key={prof.id} className="bg-white rounded-[40px] p-8 border border-slate-50 shadow-sm relative overflow-hidden group hover:border-blue-100 transition-all">
            <div className="flex items-center gap-4 mb-6">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-white ${idx === 0 ? 'bg-amber-400' : 'bg-slate-800'}`}>
                {idx + 1}º
              </div>
              <div>
                <h3 className="font-black text-slate-800 text-lg">{prof.nome}</h3>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Cadeira {prof.cadeira}</p>
              </div>
            </div>
            <div className="space-y-4">
              <div className="p-4 bg-slate-50 rounded-3xl border border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Produção Bruta</p>
                <p className="text-xl font-black text-slate-800">R$ {prof.totalProd.toLocaleString('pt-BR')}</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      {isAddingProf && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] p-8 shadow-2xl animate-in zoom-in">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800">Novo Profissional</h3>
              <button onClick={() => setIsAddingProf(false)} className="text-slate-400"><X /></button>
            </div>
            <div className="space-y-4">
              <input type="text" placeholder="Nome do Barbeiro" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" value={newProf.nome} onChange={(e) => setNewProf({...newProf, nome: e.target.value})} />
              <button onClick={handleAddProf} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-lg">CADASTRAR</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Professionals;

import React, { useState } from 'react';
import { AppData, MeetingNote } from '../types.ts';
import { GoogleGenAI } from "@google/genai";
import { MessageSquare, Plus, BrainCircuit, Trash2, Calendar, Sparkles, UserCircle, ShoppingCart } from 'lucide-react';

interface MeetingsProps {
  data: AppData;
  setData: (data: AppData) => void;
}

const Meetings: React.FC<MeetingsProps> = ({ data, setData }) => {
  const [selectedProfId, setSelectedProfId] = useState(data.profissionais[0]?.id || '');
  const [newNote, setNewNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiScript, setAiScript] = useState('');

  const selectedProf = data.profissionais.find(p => p.id === selectedProfId);
  const notes = data.meetingNotes?.filter(n => n.profissionalId === selectedProfId) || [];

  const perfData = data.producao.filter(p => p.profissionalId === selectedProfId).slice(-3);
  const mediaVenda = perfData.reduce((s,c) => s + (c.vendasProdutos || 0), 0) / (perfData.length || 1);
  const mediaAtend = perfData.reduce((s,c) => s + (c.quantidadeAtendimentos || 0), 0) / (perfData.length || 1);
  const conversao = mediaAtend > 0 ? mediaVenda / mediaAtend : 0;

  const handleAddNote = () => {
    if (!newNote) return;
    const note: MeetingNote = {
      id: Math.random().toString(36).substr(2, 9),
      profissionalId: selectedProfId,
      data: new Date().toISOString(),
      texto: newNote
    };
    setData({ ...data, meetingNotes: [...(data.meetingNotes || []), note] });
    setNewNote('');
  };

  const handleGenerateScript = async () => {
    const apiKey = (window as any).process?.env?.API_KEY || '';
    if (!apiKey) {
      setAiScript("Chave de API não configurada.");
      return;
    }

    setIsGenerating(true);
    setAiScript('');

    const ai = new GoogleGenAI({ apiKey });

    const prompt = `Analise o barbeiro ${selectedProf?.nome} com conversão de R$ ${conversao.toFixed(2)}. Gere um feedback curto de gestão.`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiScript(response.text || "Erro ao processar.");
    } catch (error) {
      setAiScript("Erro na IA.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-24">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Mentoria Estratégica</h2>
      </header>

      <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide">
        {data.profissionais.map(p => (
          <button
            key={p.id}
            onClick={() => { setSelectedProfId(p.id); setAiScript(''); }}
            className={`px-6 py-3 rounded-2xl text-xs font-black whitespace-nowrap border ${
              selectedProfId === p.id ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-100 text-slate-400'
            }`}
          >
            {p.nome}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[40px] border border-slate-50">
          <textarea className="w-full bg-slate-50 border rounded-[32px] p-6 text-sm min-h-[120px]" placeholder="Nova nota..." value={newNote} onChange={(e) => setNewNote(e.target.value)} />
          <button onClick={handleAddNote} className="w-full mt-4 bg-slate-900 text-white py-4 rounded-2xl font-black text-sm">SALVAR NOTA</button>
        </div>

        <div className="bg-slate-900 p-8 rounded-[40px] text-white">
          <button onClick={handleGenerateScript} disabled={isGenerating} className="w-full bg-blue-600 text-white py-5 rounded-3xl font-black text-sm flex items-center justify-center gap-2">
            {isGenerating ? 'ANALISANDO...' : 'GERAR FEEDBACK IA'}
          </button>
          {aiScript && <div className="mt-6 p-6 bg-white/5 rounded-2xl text-sm italic">{aiScript}</div>}
        </div>
      </div>
    </div>
  );
};

export default Meetings;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal } from '../types.ts';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, DollarSign, UserMinus, UserCheck, Plus, ArrowUpRight, ArrowDownRight, PieChart as PieChartIcon, Trophy, Scissors, Star, LayoutDashboard } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);
  const [newCategory, setNewCategory] = useState('');

  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, 
          nome: prof.nome, 
          bruta: p?.producaoBruta || 0, 
          repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0,
          vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0,
        cartao: extra?.cartao || 0,
        pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0,
        pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0,
        cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods,
        gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;

    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const handleAddCategory = () => {
    if (!newCategory || data.categoriasGastos.includes(newCategory)) return;
    const updatedCats = [...data.categoriasGastos, newCategory];
    setData({ ...data, categoriasGastos: updatedCats });
    setFormData({
      ...formData,
      gastos: [...formData.gastos, { categoria: newCategory, valor: 0 }]
    });
    setNewCategory('');
  };

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };

    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));

    const newGastos: GastoMensal[] = formData.gastos.map(g => ({
      ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor
    }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });

    setShowModal(false);
  };

  const monthDetailData = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];

    const expenseData = [...m.gastosList].map(g => ({ name: g.categoria, value: g.valor }));
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const profRanking = [...data.profissionais].map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const bruta = p?.producaoBruta || 0;
      const recServicos = p ? (p.producaoBruta - p.repasseProfissional - p.repasseAssinatura) : 0;
      const recAssinaturas = p?.repasseAssinatura || 0;
      return {
        nome: prof.nome,
        bruta,
        recServicos,
        recAssinaturas,
        totalCasa: recServicos + recAssinaturas
      };
    }).sort((a, b) => b.totalCasa - a.totalCasa);

    return { ...m, expenseData, COLORS, profRanking };
  }, [selectedMonth, matrix, data.profissionais]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-slate-800">Fluxo Mensal</h2>
          <p className="text-xs text-slate-400">Gerencie fechamentos e veja detalhes inteligentes</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase shadow-lg shadow-blue-100 flex items-center gap-2">
          <PlusCircle size={18} /> Fechamento do Mês
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-50 overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
            <tr>
              <th className="px-6 py-5">Mês</th>
              <th className="px-6 py-5 text-right">Rec. Bruta</th>
              <th className="px-6 py-5 text-right">Saídas</th>
              <th className="px-6 py-5 text-right">Líquido</th>
              <th className="px-6 py-5 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((m) => (
              <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                <td className="px-6 py-5 font-bold text-slate-800">{m.nome}</td>
                <td className="px-6 py-5 text-right font-bold text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                <td className="px-6 py-5 text-right text-red-500 font-medium">R$ {(m.repasse + m.gastosTotal).toLocaleString('pt-BR')}</td>
                <td className={`px-6 py-5 text-right font-black ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                  R$ {m.liquido.toLocaleString('pt-BR')}
                </td>
                <td className="px-6 py-5 text-center flex justify-center gap-2">
                  <button onClick={() => { setSelectedMonth(m.mes); setShowDetailModal(true); }} className="p-2 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-xl transition-all" title="Ver Detalhes">
                    <Eye size={16} />
                  </button>
                  <button onClick={() => { setFormData(prev => ({ ...prev, mes: m.mes })); setShowModal(true); }} className="p-2 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-xl transition-all" title="Editar Lançamento">
                    <Edit2 size={16} />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-white sticky top-0 z-10">
              <h3 className="text-xl font-black text-slate-800">Lançamento de Fechamento</h3>
              <button onClick={() => setShowModal(false)} className="bg-slate-50 p-3 rounded-full text-slate-400 hover:text-slate-600"><X /></button>
            </div>

            <div className="p-8 overflow-y-auto space-y-8 flex-1">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mês de Referência</label>
                  <select 
                    className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-sm" 
                    value={formData.mes} 
                    onChange={(e) => setFormData({...formData, mes: Number(e.target.value)})}
                  >
                    {meses.map((m, i) => <option key={m} value={i+1}>{m}</option>)}
                  </select>
                </div>
                <Input label="Receita Assinaturas" value={formData.assinaturas} onChange={(v: number) => setFormData({...formData, assinaturas: v})} />
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2 text-red-500">
                  <ArrowDownRight size={18} /> Gestão de Saídas (Gastos)
                </h4>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  {formData.gastos.map((g, idx) => (
                    <div key={g.categoria}>
                      <label className="text-[8px] font-black text-slate-400 uppercase block mb-1 truncate">{g.categoria}</label>
                      <input type="number" value={g.valor === 0 ? '' : g.valor} onChange={(e) => { let n = [...formData.gastos]; n[idx].valor = Number(e.target.value); setFormData({...formData, gastos: n}); }} className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold" />
                    </div>
                  ))}
                </div>
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="Nova Categoria de Saída..." 
                    className="flex-1 p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold" 
                    value={newCategory} 
                    onChange={(e) => setNewCategory(e.target.value)} 
                  />
                  <button onClick={handleAddCategory} className="bg-slate-900 text-white p-3 rounded-xl hover:bg-slate-800">
                    <Plus size={16} />
                  </button>
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2 text-blue-600">
                  <Scissors size={18} /> Produção e Atendimentos
                </h4>
                <div className="space-y-3">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-5 bg-slate-50 rounded-[28px] border border-slate-100 grid grid-cols-3 gap-3">
                      <span className="col-span-3 text-[10px] font-black text-slate-400 uppercase">{p.nome}</span>
                      <MiniInput label="Bruto" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                      <MiniInput label="Repasse" value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                      <MiniInput label="Rec. Assin." value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-4 flex items-center gap-2 text-emerald-600">
                  <UserCheck size={18} /> Movimentação de Assinantes
                </h4>
                <div className="grid grid-cols-2 gap-4">
                  <Input label="Novos Assinantes" value={formData.novosAssinantes} onChange={(v: number) => setFormData({...formData, novosAssinantes: v})} />
                  <Input label="Perda de Assinantes" value={formData.cancelamentosAssinantes} onChange={(v: number) => setFormData({...formData, cancelamentosAssinantes: v})} />
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t border-slate-100">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-4 rounded-3xl font-black shadow-lg flex items-center justify-center gap-2 hover:bg-blue-500 transition-all">
                <Save size={18} /> SALVAR FECHAMENTO
              </button>
            </div>
          </div>
        </div>
      )}

      {showDetailModal && monthDetailData && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[40px] shadow-2xl overflow-hidden max-h-[95vh] flex flex-col animate-in slide-in-from-bottom-8">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-900 text-white">
              <div>
                <h3 className="text-2xl font-black">Detalhamento: {monthDetailData.nome} {year}</h3>
                <p className="text-[10px] font-bold text-blue-400 uppercase tracking-widest">Dashboards Estratégicos do Período</p>
              </div>
              <button onClick={() => setShowDetailModal(false)} className="bg-white/10 p-3 rounded-full text-white/50 hover:text-white"><X /></button>
