        <SubCard label="Crescimento (Ano)" value={`+${totalNovos}`} icon={TrendingUp} color="text-emerald-600" bg="bg-emerald-50" />
        <SubCard label="Churn (Cancelamentos)" value={`${churnRate.toFixed(1)}%`} icon={UserMinus} color="text-red-500" bg="bg-red-50" />
        <SubCard label="Ticket Recorrente" value={`R$ ${mediaMensal.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}`} icon={DollarSign} color="text-blue-600" bg="bg-blue-50" />
        <SubCard label="Potencial LTV" value={`R$ ${ltv.toLocaleString('pt-BR', { maximumFractionDigits: 0 })}`} icon={Activity} color="text-purple-600" bg="bg-purple-50" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 text-xl mb-8 flex items-center gap-2">
            <UserCheck size={20} className="text-blue-600" /> Evolução da Base de Assinantes
          </h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={meses}>
                <defs>
                  <linearGradient id="colorAss" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#2563eb" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 'bold'}} />
                <YAxis hide />
