/**
 * GBCortes7 - Service Worker Transformer
 * Responsável por transformar arquivos .tsx e .ts em JavaScript válido para o navegador.
 */

importScripts('https://unpkg.com/@babel/standalone/babel.min.js');

const CACHE_NAME = 'gbcortes-v12';

self.addEventListener('install', (event) => {
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(clients.claim());
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // Intercepta arquivos .tsx ou .ts do mesmo domínio
  if (url.origin === self.location.origin && (url.pathname.endsWith('.tsx') || url.pathname.endsWith('.ts'))) {
    event.respondWith(
      fetch(event.request)
        .then(async (response) => {
          if (!response.ok) return response;

          const source = await response.text();

          try {
            // Transforma o código TSX/TS em JS puro usando Babel
            const transformed = Babel.transform(source, {
              presets: [
                'react',
                ['typescript', { isTSX: true, allExtensions: true }]
              ],
              filename: url.pathname
            }).code;

            return new Response(transformed, {
              headers: { 'Content-Type': 'application/javascript' }
            });
          } catch (err) {
            console.error('Erro de Compilação em ' + url.pathname, err);
            return new Response(`console.error("Erro Babel em ${url.pathname}:", ${JSON.stringify(err.message)});`, {
              headers: { 'Content-Type': 'application/javascript' }
            });
          }
        })
    );
  }
});

import React, { useState, useEffect } from 'react';
