      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {ranking.map((prof, idx) => (
          <div key={prof.id} className="bg-white rounded-[40px] p-8 border border-slate-50 shadow-sm relative overflow-hidden group hover:border-blue-200 transition-all border-b-4 border-b-transparent hover:border-b-blue-500">

            {/* Botões de Ação Rápidos */}
            <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => openEdit(prof)} className="p-2 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-100" title="Editar">
                <Edit3 size={16} />
              </button>
              <button onClick={() => handleDelete(prof.id, prof.nome)} className="p-2 bg-red-50 text-red-500 rounded-xl hover:bg-red-100" title="Excluir">
                <Trash2 size={16} />
              </button>
            </div>

            <div className="flex items-center gap-4 mb-6">
              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-white shadow-lg ${
                idx === 0 ? 'bg-amber-400 rotate-3' : idx === 1 ? 'bg-slate-400' : 'bg-slate-800'
              }`}>
                {idx + 1}º
              </div>
              <div>
                <h3 className="font-black text-slate-800 text-lg leading-tight">{prof.nome}</h3>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full uppercase">Cadeira {prof.cadeira}</span>
                  <span className="text-[10px] font-black bg-blue-50 text-blue-600 px-2 py-0.5 rounded-full uppercase">{prof.comissao}% Comiss.</span>
