import React, { useState, useMemo } from 'react';
import { AppData, Profissional, ProfissionalPerfil } from '../types.ts';
import { Plus, Trash2, X, Edit3, Scissors, UserPlus, Save, Target } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, setData, year }) => {
  const [modalMode, setModalMode] = useState<'add' | 'edit' | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formProf, setFormProf] = useState({ 
    nome: '', 
    cadeira: 1, 
    comissao: 50,
    metaMensal: 5000,
    ativo: true 
  });

  const [formPerfil, setFormPerfil] = useState<ProfissionalPerfil>({
    experiencia: '',
    perfilComportamental: '',
    especialidade: '',
    objetivo: ''
  });

  const ranking = useMemo(() => {
    return data.profissionais
      .filter(p => p.ativo !== false)
      .map(prof => {
        const records = data.producao.filter(p => p.profissionalId === prof.id && p.ano === year);
        const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
        return { ...prof, totalProd };
      })
      .sort((a, b) => b.totalProd - a.totalProd);
  }, [data.profissionais, data.producao, year]);

  const openAdd = () => {
    setModalMode('add');
    setEditingId(null);
    setFormProf({ nome: '', cadeira: 1, comissao: 50, metaMensal: 5000, ativo: true });
    setFormPerfil({ experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const openEdit = (prof: Profissional) => {
    setModalMode('edit');
    setEditingId(prof.id);
    setFormProf({ 
      nome: prof.nome, 
      cadeira: prof.cadeira, 
      comissao: prof.comissao || 50,
      metaMensal: prof.metaMensal || 5000,
      ativo: prof.ativo 
    });
    setFormPerfil(prof.perfil || { experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const handleSave = () => {
    if (!formProf.nome) return;

    if (modalMode === 'add') {
      const nProf: Profissional = {
        id: Math.random().toString(36).substr(2, 9),
        ...formProf,
        perfil: formPerfil
      };
      setData({ ...data, profissionais: [...data.profissionais, nProf] });
    } else if (modalMode === 'edit' && editingId) {
      const updatedList = data.profissionais.map(p => 
        p.id === editingId ? { ...p, ...formProf, perfil: formPerfil } : p
      );
      setData({ ...data, profissionais: updatedList });
    }
    setModalMode(null);
  };

  const handleDelete = (id: string, nome: string) => {
    if (confirm(`Tem certeza que deseja remover ${nome}?`)) {
      const updatedList = data.profissionais.map(p => 
        p.id === id ? { ...p, ativo: false } : p
      );
      setData({ ...data, profissionais: updatedList });
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-32">
      <header className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Equipe & Performance</h2>
          <p className="text-sm text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de barbeiros e metas</p>
        </div>
        <button onClick={openAdd} className="bg-blue-600 text-white flex items-center gap-2 px-6 py-4 rounded-[24px] shadow-xl shadow-blue-100 font-black text-xs uppercase tracking-widest hover:scale-105 transition-all">
          <UserPlus size={18} /> Novo Barbeiro
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {ranking.map((prof, idx) => (
          <div key={prof.id} className="bg-white rounded-[40px] p-8 border border-slate-50 shadow-sm relative overflow-hidden group hover:border-blue-200 transition-all border-b-4 border-b-transparent hover:border-b-blue-500">
            <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => openEdit(prof)} className="p-2 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-100"><Edit3 size={16} /></button>
              <button onClick={() => handleDelete(prof.id, prof.nome)} className="p-2 bg-red-50 text-red-500 rounded-xl hover:bg-red-100"><Trash2 size={16} /></button>
            </div>

            <div className="flex items-center gap-4 mb-6">
              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-white shadow-lg ${
                idx === 0 ? 'bg-amber-400 rotate-3' : idx === 1 ? 'bg-slate-400' : 'bg-slate-800'
              }`}>
                {idx + 1}º
              </div>
              <div>
                <h3 className="font-black text-slate-800 text-lg leading-tight">{prof.nome}</h3>
                <p className="text-[10px] font-black text-slate-400 uppercase mt-1">Meta Individual: R$ {(prof.metaMensal || 5000).toLocaleString('pt-BR')}</p>
              </div>
            </div>

            <div className="space-y-4">
              <div className="p-5 bg-slate-50 rounded-[32px] border border-slate-100 group-hover:bg-blue-50/50 transition-colors">
                <p className="text-[10px] font-black text-slate-400 uppercase mb-1 flex items-center gap-2">
                   <Scissors size={12} className="text-blue-500" /> Produção Bruta Ano
                </p>
                <p className="text-2xl font-black text-slate-800">R$ {prof.totalProd.toLocaleString('pt-BR')}</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      {modalMode && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[48px] p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h3 className="text-2xl font-black text-slate-800">{modalMode === 'add' ? 'Adicionar' : 'Editar'} Barbeiro</h3>
                <p className="text-xs text-slate-400 font-bold uppercase mt-1">Metas & Cadastro</p>
              </div>
              <button onClick={() => setModalMode(null)} className="p-3 bg-slate-100 text-slate-400 rounded-full"><X /></button>
            </div>

            <div className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">Nome Completo</label>
                  <input type="text" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-700" value={formProf.nome} onChange={(e) => setFormProf({...formProf, nome: e.target.value})} />
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">Cadeira</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" value={formProf.cadeira} onChange={(e) => setFormProf({...formProf, cadeira: Number(e.target.value)})} />
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">% Comissão</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" value={formProf.comissao} onChange={(e) => setFormProf({...formProf, comissao: Number(e.target.value)})} />
                </div>

                <div className="col-span-2 bg-blue-50 p-6 rounded-[32px] border border-blue-100 mt-2">
                  <label className="text-[10px] font-black text-blue-400 uppercase ml-2 mb-2 block flex items-center gap-2">
                    <Target size={14} /> Meta de Produção Mensal (R$)
                  </label>
                  <input type="number" className="w-full p-4 bg-white border border-blue-200 rounded-2xl font-black text-blue-700 text-xl" value={formProf.metaMensal} onChange={(e) => setFormProf({...formProf, metaMensal: Number(e.target.value)})} />
                  <p className="text-[9px] text-blue-400 mt-2 font-bold uppercase">* Esta meta atualiza os dashboards da Home automaticamente.</p>
                </div>
              </div>

              <div className="pt-4">
                <button onClick={handleSave} className="w-full bg-blue-600 text-white py-5 rounded-3xl font-black text-sm uppercase shadow-lg flex items-center justify-center gap-2">
                  <Save size={18} /> {modalMode === 'add' ? 'CADASTRAR' : 'SALVAR ALTERAÇÕES'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Professionals;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal, ParametrosAnuais } from '../types.ts';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, UserMinus, UserCheck, Plus, ArrowUpRight, ArrowDownRight, PieChart as PieChartIcon, Trophy, Scissors, Star, Target } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);
  const [newCategory, setNewCategory] = useState('');

  const currentParams = data.parametros.find(p => p.ano === year) || data.parametros[0];
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  const handleUpdateMetaAnual = (val: number) => {
    const updatedParams = data.parametros.map(p => 
      p.ano === year ? { ...p, metaFaturamento: val } : p
    );
    setData({ ...data, parametros: updatedParams });
  };

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, 
          nome: prof.nome, 
          bruta: p?.producaoBruta || 0, 
          repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0,
          vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0,
        cartao: extra?.cartao || 0,
        pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0,
        pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0,
        cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods,
        gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;

    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const handleAddCategory = () => {
    if (!newCategory || data.categoriasGastos.includes(newCategory)) return;
    const updatedCats = [...data.categoriasGastos, newCategory];
    setData({ ...data, categoriasGastos: updatedCats });
    setFormData({
      ...formData,
      gastos: [...formData.gastos, { categoria: newCategory, valor: 0 }]
    });
    setNewCategory('');
  };

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };

    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
