import React, { useState, useRef } from 'react';
import { AppData, ParametrosAnuais } from '../types.ts';
import { CalendarPlus, Save, Trash2, Download, Upload, ShieldCheck, Plus, X, CheckCircle2 } from 'lucide-react';

interface ConfigProps {
  data: AppData;
  setData: (data: AppData) => void;
  selectedYear: number;
  setSelectedYear: (year: number) => void;
}

const Config: React.FC<ConfigProps> = ({ data, setData, selectedYear, setSelectedYear }) => {
  const [showNewYearModal, setShowNewYearModal] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [newYearForm, setNewYearForm] = useState<ParametrosAnuais>({
    ano: new Date().getFullYear() + 1,
    metaFaturamento: 250000,
    metaLucro: 120000,
    metaAssinaturas: 36000,
    metaGeladeira: 12000,
    metaGastos: 100000,
    metaPorCadeira: 5000
  });

  const exportBackup = () => {
    const dataStr = JSON.stringify(data, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', `backup_barber_bi_${new Date().toISOString().split('T')[0]}.json`);
    linkElement.click();
  };

  const importBackup = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        if (json.profissionais && confirm('Substituir dados atuais pelo backup?')) {
          setData(json);
        }
      } catch (err) { alert('Erro ao ler arquivo.'); }
    };
    reader.readAsText(file);
  };

  const handleCreateNewYear = () => {
    if (data.parametros.some(p => p.ano === newYearForm.ano)) {
      alert('Ano já existente!');
      return;
    }
    setData({ ...data, parametros: [...data.parametros, newYearForm] });
    setSelectedYear(newYearForm.ano);
    setShowNewYearModal(false);
  };

  const handleRemoveYear = (ano: number) => {
    if (data.parametros.length <= 1) return;
    if (confirm(`Excluir as configurações de ${ano}?`)) {
      setData({ ...data, parametros: data.parametros.filter(p => p.ano !== ano) });
      if (selectedYear === ano) setSelectedYear(data.parametros[0].ano);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-32">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Ajustes do Sistema</h2>
        <p className="text-sm text-slate-400 font-bold uppercase">Gestão de dados e planejamento temporal</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-8">
            <h3 className="font-black text-slate-800 text-lg flex items-center gap-2"><CalendarPlus size={22} className="text-blue-600" /> Ciclos Anuais</h3>
            <button onClick={() => setShowNewYearModal(true)} className="bg-blue-600 text-white p-3 rounded-2xl shadow-lg"><Plus /></button>
          </div>
          <div className="space-y-4">
            {data.parametros.sort((a,b) => b.ano - a.ano).map(p => (
              <div key={p.ano} className={`p-6 rounded-[32px] border flex justify-between items-center transition-all ${selectedYear === p.ano ? 'bg-blue-50 border-blue-200 ring-2 ring-blue-100' : 'bg-slate-50 border-slate-100'}`}>
                <div className="flex items-center gap-3">
                  <span className={`text-xl font-black ${selectedYear === p.ano ? 'text-blue-700' : 'text-slate-800'}`}>{p.ano}</span>
                  {selectedYear === p.ano && <CheckCircle2 size={16} className="text-blue-500" />}
                </div>
                <div className="flex gap-3">
                  {selectedYear !== p.ano && (
                    <button onClick={() => setSelectedYear(p.ano)} className="bg-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-sm border border-slate-200">Ativar</button>
                  )}
                  <button onClick={() => handleRemoveYear(p.ano)} className="p-2 text-slate-300 hover:text-red-500"><Trash2 size={18} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-slate-950 p-10 rounded-[48px] shadow-2xl text-white">
          <h3 className="font-black text-lg mb-8 flex items-center gap-2"><ShieldCheck size={22} className="text-emerald-400" /> Segurança dos Dados</h3>
          <div className="space-y-4">
            <button onClick={exportBackup} className="w-full bg-white/5 hover:bg-white/10 border border-white/10 p-6 rounded-3xl flex items-center justify-between transition-all">
              <div className="flex items-center gap-4"><Download size={22} className="text-blue-400" /><div><p className="font-black text-sm text-left">EXPORTAR BACKUP</p><p className="text-[9px] text-slate-400 uppercase text-left">Salva todos os dados em um arquivo .json</p></div></div>
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="w-full bg-white/5 hover:bg-white/10 border border-white/10 p-6 rounded-3xl flex items-center justify-between transition-all">
              <div className="flex items-center gap-4"><Upload size={22} className="text-emerald-400" /><div><p className="font-black text-sm text-left">RESTAURAR SISTEMA</p><p className="text-[9px] text-slate-400 uppercase text-left">Carrega dados de um arquivo externo</p></div></div>
            </button>
            <input type="file" ref={fileInputRef} onChange={importBackup} className="hidden" accept=".json" />
          </div>
        </div>
      </div>

      {showNewYearModal && (
        <div className="fixed inset-0 z-[150] bg-slate-900/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[48px] p-10 shadow-2xl">
            <h3 className="text-2xl font-black text-slate-800 mb-2">Novo Ciclo Anual</h3>
            <p className="text-xs text-slate-400 font-bold uppercase mb-8">Defina as metas iniciais para o novo ano</p>
            <div className="space-y-6">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-1 block">Ano de Referência</label>
                <input type="number" className="w-full p-4 bg-slate-50 border rounded-2xl font-black" value={newYearForm.ano} onChange={(e) => setNewYearForm({...newYearForm, ano: Number(e.target.value)})} />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-1 block">Meta de Faturamento Inicial (R$)</label>
                <input type="number" className="w-full p-4 bg-slate-50 border rounded-2xl font-black" value={newYearForm.metaFaturamento} onChange={(e) => setNewYearForm({...newYearForm, metaFaturamento: Number(e.target.value)})} />
              </div>
              <button onClick={handleCreateNewYear} className="w-full bg-blue-600 text-white py-5 rounded-[32px] font-black shadow-xl flex items-center justify-center gap-2">
                <CalendarPlus size={20} /> INICIAR NOVO ANO
              </button>
              <button onClick={() => setShowNewYearModal(false)} className="w-full text-slate-400 font-bold text-xs uppercase tracking-widest">Cancelar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Config;

import React, { useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, ReferenceLine } from 'recharts';
import { AppData } from '../types.ts';
import { DollarSign, Crown, ArrowDownCircle, Wallet, UserCheck, Target, Scissors, TrendingUp, ChevronRight } from 'lucide-react';

interface DashboardProps {
  data: AppData;
  year: number;
}

const Dashboard: React.FC<DashboardProps> = ({ data, year }) => {
  const calculations = useMemo(() => {
    const params = data.parametros.find(p => p.ano === year) || data.parametros[0];
    const metaAnual = params?.metaFaturamento || 0;

    const profissionaisAtivos = data.profissionais.filter(p => p.ativo !== false);
    const metaMensalOperacional = profissionaisAtivos.reduce((acc, p) => acc + (p.metaMensal || params?.metaPorCadeira || 0), 0);
    const metaProducaoAnual = metaMensalOperacional * 12;

    const producaoAno = data.producao.filter(p => p.ano === year);
    const receitasAno = data.receitasExtras.filter(r => r.ano === year);
    const gastosAno = data.gastos.filter(g => g.ano === year);

    const faturamentoServicos = producaoAno.reduce((acc, curr) => acc + curr.producaoBruta, 0);
    const faturamentoAssinaturas = receitasAno.reduce((acc, r) => acc + r.assinaturas, 0);
    const faturamentoOutros = receitasAno.reduce((acc, r) => acc + r.pacotes + r.geladeira + r.dinheiro + r.cartao + r.pix, 0);

    const faturamentoTotal = faturamentoServicos + faturamentoOutros + faturamentoAssinaturas;
    const totalGastos = gastosAno.reduce((acc, curr) => acc + curr.valor, 0);
    const totalRepasses = producaoAno.reduce((acc, curr) => acc + curr.repasseProfissional + curr.repasseAssinatura, 0);
    const saidaTotal = totalGastos + totalRepasses;
    const saldoFinal = faturamentoTotal - saidaTotal;

    // Cálculo do mês atual para o progresso individual (considerando o último mês com dados)
    const ultimoMesComDados = producaoAno.length > 0 ? Math.max(...producaoAno.map(p => p.mes)) : new Date().getMonth() + 1;

    const meses = Array.from({ length: 12 }, (_, i) => {
      const mes = i + 1;
      const pMes = producaoAno.filter(p => p.mes === mes);
      const rMes = receitasAno.find(r => r.mes === mes);

      const prodMes = pMes.reduce((s, c) => s + c.producaoBruta, 0);
      const totalMes = prodMes + (rMes ? (rMes.pacotes + rMes.assinaturas + rMes.geladeira + rMes.dinheiro + rMes.cartao + rMes.pix) : 0);

      const repMes = pMes.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
      const gMes = gastosAno.filter(g => g.mes === mes).reduce((s, c) => s + c.valor, 0);

      return { 
        name: ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][i], 
        Faturamento: totalMes,
        ProducaoReal: prodMes,
        Lucro: totalMes - repMes - gMes
      };
    });

    const performanceIndividuais = profissionaisAtivos.map(prof => {
      const prodMesAtual = producaoAno
        .filter(p => p.mes === ultimoMesComDados && p.profissionalId === prof.id)
        .reduce((acc, curr) => acc + curr.producaoBruta, 0);

      const meta = prof.metaMensal || params?.metaPorCadeira || 5000;
      const porcentagem = meta > 0 ? (prodMesAtual / meta) * 100 : 0;

      return {
        id: prof.id,
        nome: prof.nome,
        real: prodMesAtual,
        meta: meta,
        porcentagem: Math.min(porcentagem, 100),
        rawPorcentagem: porcentagem
      };
    });

    const melhorMes = [...meses].sort((a, b) => b.Lucro - a.Lucro)[0];

    return { 
      faturamentoTotal, faturamentoAssinaturas, saidaTotal, saldoFinal, 
      melhorMes, metaAnual, metaProducaoAnual, faturamentoServicos, meses, 
      metaMensalOperacional, performanceIndividuais, ultimoMesComDados
    };
  }, [data, year]);

  const { 
    faturamentoTotal, faturamentoAssinaturas, saidaTotal, saldoFinal, 
    melhorMes, metaAnual, metaProducaoAnual, faturamentoServicos, meses, 
    metaMensalOperacional, performanceIndividuais, ultimoMesComDados 
  } = calculations;

  const dataMetaAnual = [
    { name: 'Realizado', value: faturamentoTotal, fill: '#2563eb' },
    { name: 'Meta Restante', value: Math.max(0, metaAnual - faturamentoTotal), fill: '#f1f5f9' }
  ];

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
