            <div className="p-3 bg-blue-50 rounded-2xl border border-blue-100 text-center">
              <p className="text-[8px] font-black text-blue-400 uppercase">Meta Anual</p>
              <p className="text-xs font-black">R$ {metaAnual.toLocaleString('pt-BR')}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-800 text-lg flex items-center gap-2 mb-2">
            <Scissors size={20} className="text-purple-600" /> Monitoramento Individual
          </h3>
          <p className="text-[10px] text-slate-400 font-bold uppercase mb-6">Mês de Referência: {['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'][ultimoMesComDados - 1]}</p>

          <div className="space-y-4 max-h-[320px] overflow-y-auto pr-2 custom-scrollbar">
            {performanceIndividuais.map((prof) => (
              <div key={prof.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 group hover:border-blue-200 transition-all">
                <div className="flex justify-between items-center mb-2">
                  <span className="text-xs font-black text-slate-700 uppercase tracking-tighter">{prof.nome}</span>
                  <span className="text-[10px] font-black text-blue-600">R$ {prof.real.toLocaleString('pt-BR')} / R$ {prof.meta.toLocaleString('pt-BR')}</span>
                </div>
                <div className="w-full h-3 bg-slate-200 rounded-full overflow-hidden">
                  <div 
                    className={`h-full transition-all duration-1000 ${prof.rawPorcentagem >= 100 ? 'bg-emerald-500' : 'bg-blue-500'}`}
                    style={{ width: `${prof.porcentagem}%` }}
                  />
                </div>
                <div className="flex justify-between items-center mt-1">
                  <p className="text-[9px] font-bold text-slate-400 uppercase">{Math.round(prof.rawPorcentagem)}% Atingido</p>
                  {prof.rawPorcentagem >= 100 && <span className="text-[9px] font-black text-emerald-500 uppercase flex items-center gap-1"><ChevronRight size={10} /> Meta Batida</span>}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
