              <ReferenceLine y={metaMensalOperacional} stroke="#f87171" strokeDasharray="5 5" strokeWidth={2} label={{ position: 'right', value: 'ALVO', fill: '#ef4444', fontSize: 10, fontWeight: 'black' }} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

