import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal, ParametrosAnuais } from '../types.ts';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, UserMinus, UserCheck, Plus, ArrowUpRight, ArrowDownRight, PieChart as PieChartIcon, Trophy, Scissors, Star, Target } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);
  const [newCategory, setNewCategory] = useState('');

  const currentParams = data.parametros.find(p => p.ano === year) || data.parametros[0] || { metaFaturamento: 0 };
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  const handleUpdateMetaAnual = (val: number) => {
    const updatedParams = data.parametros.map(p => 
      p.ano === year ? { ...p, metaFaturamento: val } : p
    );
    // Se o ano não existir nos parâmetros, adicionamos
    if (!data.parametros.find(p => p.ano === year)) {
      updatedParams.push({
        ano: year,
        metaFaturamento: val,
        metaLucro: 0,
        metaAssinaturas: 0,
        metaGeladeira: 0,
        metaGastos: 0,
        metaPorCadeira: 5000
      });
    }
    setData({ ...data, parametros: updatedParams });
  };

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, 
          nome: prof.nome, 
          bruta: p?.producaoBruta || 0, 
          repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0,
          vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0,
        cartao: extra?.cartao || 0,
        pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0,
        pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0,
        cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods,
        gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);

    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + 
                  (extra?.dinheiro || 0) + (extra?.cartao || 0) + 
                  (extra?.pix || 0) + (extra?.assinaturas || 0) + 
                  (extra?.pacotes || 0);

    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;

    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
