                  ))}
                </div>
              </div>
            </div>

            <div className="p-10 bg-slate-50 border-t border-slate-100">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-6 rounded-[28px] font-black text-sm uppercase tracking-widest shadow-2xl shadow-blue-100 flex items-center justify-center gap-3 hover:bg-blue-700 transition-all active:scale-95">
                <Save size={20} /> FINALIZAR E SALVAR DADOS
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

