import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal, ParametrosAnuais, Profissional } from '../types.ts';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, UserCheck, Plus, ArrowDownRight, Scissors, Target, PieChart as PieChartIcon, Award, UserPlus, UserMinus, BarChart2 } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);

  const currentParams = data.parametros.find(p => p.ano === year) || data.parametros[0] || { metaFaturamento: 0 };
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  const handleUpdateMetaAnual = (val: number) => {
    const updatedParams = data.parametros.map(p => 
      p.ano === year ? { ...p, metaFaturamento: val } : p
    );
    if (!data.parametros.find(p => p.ano === year)) {
      updatedParams.push({
        ano: year, metaFaturamento: val, metaLucro: 0, metaAssinaturas: 0, metaGeladeira: 0, metaGastos: 0, metaPorCadeira: 5000
      });
    }
    setData({ ...data, parametros: updatedParams });
  };

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, nome: prof.nome, bruta: p?.producaoBruta || 0, repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0, vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0, cartao: extra?.cartao || 0, pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0, pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0, cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods, gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);
    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + (extra?.dinheiro || 0) + (extra?.cartao || 0) + (extra?.pix || 0) + (extra?.assinaturas || 0) + (extra?.pacotes || 0);
    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;
    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const monthDashboard = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];
    const expenseData = m.gastosList.map(g => ({ name: g.categoria, value: g.valor })).filter(g => g.value > 0);
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const profRanking = data.profissionais.map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const totalProd = p?.producaoBruta || 0;
      const recServicos = p ? (p.producaoBruta - p.repasseProfissional - p.repasseAssinatura) : 0;
      const recAssinaturas = p?.repasseAssinatura || 0;
      return { nome: prof.nome, totalProd, recServicos, recAssinaturas, totalHouse: recServicos + recAssinaturas };
    }).sort((a, b) => b.totalHouse - a.totalHouse);

    const destaque = profRanking[0];

    return { ...m, expenseData, COLORS, profRanking, destaque };
  }, [selectedMonth, matrix, data.profissionais]);

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };
    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));
    const newGastos: GastoMensal[] = formData.gastos.map(g => ({ ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });
    setShowModal(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="bg-slate-950 p-10 rounded-[48px] shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8 border border-white/5 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full -mr-32 -mt-32 blur-[80px]"></div>
        <div className="flex items-center gap-5 z-10">
          <div className="p-4 bg-blue-600 rounded-3xl text-white shadow-xl shadow-blue-500/20 rotate-3">
            <Target size={28} />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tighter">Planejamento Estratégico {year}</h2>
            <p className="text-[10px] text-blue-400 font-bold uppercase mt-1 tracking-widest text-left">Defina o alvo anual de faturamento</p>
          </div>
        </div>
        <div className="w-full md:w-auto flex flex-col items-end z-10">
          <label className="text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Alvo Anual (R$)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-blue-500 font-black text-2xl">R$</span>
            <input 
              type="number" 
              value={currentParams.metaFaturamento} 
              onChange={(e) => handleUpdateMetaAnual(Number(e.target.value))}
              className="bg-white/5 border border-white/10 p-5 pl-14 rounded-[28px] text-white font-black text-3xl w-full md:w-72 focus:border-blue-500 outline-none transition-all"
            />
          </div>
        </div>
      </div>

      <div className="flex justify-between items-center px-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Fluxo de Caixa</h2>
          <p className="text-xs text-slate-400 font-bold uppercase mt-1 tracking-widest">Controle de entradas e saídas mensais</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-8 py-4 rounded-[24px] font-black text-xs uppercase shadow-xl shadow-blue-100 flex items-center gap-2 hover:scale-105 transition-all">
          <PlusCircle size={18} /> Novo Fechamento
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
            <tr>
              <th className="px-8 py-6">Mês</th>
              <th className="px-8 py-6 text-right">Faturamento</th>
              <th className="px-8 py-6 text-right">Saídas</th>
              <th className="px-8 py-6 text-right">Líquido</th>
              <th className="px-8 py-6 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((m) => (
              <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                <td className="px-8 py-6 font-black text-slate-800 text-base">{m.nome}</td>
                <td className="px-8 py-6 text-right font-bold text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                <td className="px-8 py-6 text-right text-red-500 font-bold">R$ {(m.repasse + m.gastosTotal).toLocaleString('pt-BR')}</td>
                <td className={`px-8 py-6 text-right font-black text-base ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                  R$ {m.liquido.toLocaleString('pt-BR')}
                </td>
                <td className="px-8 py-6 text-center">
                  <div className="flex justify-center gap-2">
                    <button onClick={() => { setSelectedMonth(m.mes); setShowDetailModal(true); }} className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl transition-all" title="Ver Dashboard do Mês"><Eye size={16} /></button>
                    <button onClick={() => { setFormData(prev => ({ ...prev, mes: m.mes })); setShowModal(true); }} className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl transition-all" title="Editar Lançamento"><Edit2 size={16} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* DASHBOARD MENSAL DETALHADO */}
      {showDetailModal && monthDashboard && (
        <div className="fixed inset-0 z-[150] bg-slate-950/80 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-slate-50 w-full max-w-5xl h-[90vh] rounded-[48px] shadow-2xl overflow-hidden flex flex-col animate-in zoom-in duration-300">
            <header className="p-10 bg-white border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-3xl font-black text-slate-800 tracking-tighter">Painel de {monthDashboard.nome} / {year}</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Análise profunda de resultados</p>
              </div>
              <button onClick={() => setShowDetailModal(false)} className="bg-slate-100 p-5 rounded-full text-slate-400 hover:bg-slate-200"><X /></button>
            </header>

            <div className="flex-1 overflow-y-auto p-10 space-y-8 custom-scrollbar">
              {/* Cards de Topo */}
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <MiniStats label="Entradas" value={`R$ ${monthDashboard.bruta.toLocaleString('pt-BR')}`} icon={TrendingUp} color="text-blue-600" bg="bg-blue-50" />
                <MiniStats label="Saídas" value={`R$ ${(monthDashboard.repasse + monthDashboard.gastosTotal).toLocaleString('pt-BR')}`} icon={ArrowDownRight} color="text-red-500" bg="bg-red-50" />
                <MiniStats label="Líquido" value={`R$ ${monthDashboard.liquido.toLocaleString('pt-BR')}`} icon={Wallet} color="text-emerald-600" bg="bg-emerald-50" />
                <div className="bg-slate-900 p-5 rounded-[32px] flex items-center gap-4 text-white">
                  <div className="p-3 bg-blue-500 rounded-2xl"><Award size={24} /></div>
                  <div>
                    <p className="text-[8px] font-black text-blue-400 uppercase">Destaque do Mês</p>
                    <p className="text-sm font-black truncate">{monthDashboard.destaque?.nome || 'N/A'}</p>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Ranking de Gastos */}
                <div className="bg-white p-8 rounded-[40px] border border-slate-100">
                  <h4 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2"><PieChartIcon size={20} className="text-red-500" /> Ranking de Gastos</h4>
                  <div className="h-48 mb-6">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={monthDashboard.expenseData} innerRadius={50} outerRadius={70} dataKey="value" stroke="none">
                          {monthDashboard.expenseData.map((entry, index) => <Cell key={index} fill={monthDashboard.COLORS[index % monthDashboard.COLORS.length]} />)}
                        </Pie>
                        <Tooltip formatter={(v: number) => `R$ ${v.toLocaleString('pt-BR')}`} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="space-y-3">
                    {monthDashboard.expenseData.sort((a,b) => b.value - a.value).map((g, idx) => (
                      <div key={idx} className="flex justify-between items-center p-3 bg-slate-50 rounded-2xl">
                        <span className="text-xs font-bold text-slate-600">{g.name}</span>
                        <span className="text-xs font-black text-slate-800">R$ {g.value.toLocaleString('pt-BR')}</span>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Assinaturas */}
                <div className="bg-slate-950 p-8 rounded-[40px] text-white">
                  <h4 className="text-lg font-black mb-6 flex items-center gap-2"><UserCheck size={20} className="text-blue-400" /> Movimentação Clube</h4>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="p-6 bg-white/5 border border-white/10 rounded-3xl">
                      <p className="text-[9px] font-black text-blue-400 uppercase mb-2">Novos Assinantes</p>
                      <div className="flex items-center gap-3">
                        <UserPlus className="text-emerald-500" size={24} />
                        <span className="text-3xl font-black">{monthDashboard.extra?.novosAssinantes || 0}</span>
                      </div>
                    </div>
                    <div className="p-6 bg-white/5 border border-white/10 rounded-3xl">
                      <p className="text-[9px] font-black text-red-400 uppercase mb-2">Cancelamentos</p>
                      <div className="flex items-center gap-3">
                        <UserMinus className="text-red-500" size={24} />
                        <span className="text-3xl font-black">{monthDashboard.extra?.cancelamentosAssinantes || 0}</span>
                      </div>
                    </div>
                  </div>
                  <div className="mt-6 p-6 bg-blue-600 rounded-3xl">
                    <p className="text-[9px] font-black text-blue-100 uppercase mb-1 tracking-widest text-left">Faturamento Assinaturas</p>
                    <p className="text-3xl font-black">R$ {(monthDashboard.extra?.assinaturas || 0).toLocaleString('pt-BR')}</p>
                  </div>
                </div>
              </div>

              {/* Ranking Profissionais */}
              <div className="bg-white p-8 rounded-[40px] border border-slate-100">
                <h4 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2"><BarChart2 size={20} className="text-blue-600" /> Performance dos Barbeiros</h4>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                      <tr>
                        <th className="py-4 px-2">Barbeiro</th>
                        <th className="py-4 px-2 text-right">Prod. Bruta</th>
                        <th className="py-4 px-2 text-right">Casa (Serviço)</th>
                        <th className="py-4 px-2 text-right">Casa (Assin.)</th>
                        <th className="py-4 px-2 text-right">Total Casa</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {monthDashboard.profRanking.map((p, idx) => (
                        <tr key={idx} className="hover:bg-slate-50">
                          <td className="py-4 px-2 font-black text-slate-800">{p.nome}</td>
                          <td className="py-4 px-2 text-right font-bold text-slate-400">R$ {p.totalProd.toLocaleString('pt-BR')}</td>
                          <td className="py-4 px-2 text-right font-bold text-slate-700">R$ {p.recServicos.toLocaleString('pt-BR')}</td>
                          <td className="py-4 px-2 text-right font-bold text-blue-600">R$ {p.recAssinaturas.toLocaleString('pt-BR')}</td>
                          <td className="py-4 px-2 text-right font-black text-slate-900 bg-slate-50/50">R$ {p.totalHouse.toLocaleString('pt-BR')}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* MODAL DE LANÇAMENTO */}
      {showModal && (
        <div className="fixed inset-0 z-[100] bg-slate-900/70 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-[48px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in duration-300">
            <div className="p-10 border-b border-slate-50 flex justify-between items-center bg-white sticky top-0 z-10">
              <div>
                <h3 className="text-2xl font-black text-slate-800">Fechamento Mensal</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase mt-1 tracking-widest">Insira os dados reais do período</p>
              </div>
              <button onClick={() => setShowModal(false)} className="bg-slate-100 p-4 rounded-full text-slate-400 hover:bg-slate-200 transition-all"><X /></button>
            </div>

            <div className="p-10 overflow-y-auto space-y-10 flex-1 custom-scrollbar">
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Mês do Ano</label>
                  <select className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[24px] font-black text-slate-700 outline-none focus:border-blue-500" value={formData.mes} onChange={(e) => setFormData({...formData, mes: Number(e.target.value)})}>
                    {meses.map((m, i) => <option key={m} value={i+1}>{m}</option>)}
                  </select>
                </div>
                <Input label="Rec. Assinaturas (R$)" value={formData.assinaturas} onChange={(v: number) => setFormData({...formData, assinaturas: v})} />
                <Input label="Novos Assinantes" value={formData.novosAssinantes} onChange={(v: number) => setFormData({...formData, novosAssinantes: v})} />
                <Input label="Cancelamentos" value={formData.cancelamentosAssinantes} onChange={(v: number) => setFormData({...formData, cancelamentosAssinantes: v})} />
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-red-500"><ArrowDownRight size={22} /> Despesas Reais</h4>
                <div className="grid grid-cols-2 gap-6">
                  {formData.gastos.map((g, idx) => (
                    <div key={g.categoria}>
                      <label className="text-[9px] font-black text-slate-400 uppercase block mb-2 ml-2">{g.categoria}</label>
                      <input type="number" value={g.valor === 0 ? '' : g.valor} onChange={(e) => { let n = [...formData.gastos]; n[idx].valor = Number(e.target.value); setFormData({...formData, gastos: n}); }} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-[20px] text-sm font-bold focus:border-red-400 outline-none" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-blue-600"><Scissors size={22} /> Produção por Profissional</h4>
                <div className="space-y-4">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-6 bg-slate-50 rounded-[32px] border border-slate-100 grid grid-cols-3 gap-4">
                      <span className="col-span-3 text-xs font-black text-slate-800 uppercase">{p.nome}</span>
                      <MiniInput label="Bruto" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                      <MiniInput label="Repasse" value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                      <MiniInput label="Assin." value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-10 bg-slate-50 border-t border-slate-100">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-6 rounded-[28px] font-black text-sm uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3">
                <Save size={20} /> SALVAR FECHAMENTO MENSAL
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

