import { GoogleGenAI } from "@google/genai";
import { Transaction, Profissional } from "../types.ts";

/**
 * Serviço de insights estratégico usando a inteligência do Google Gemini.
 */
export const getBusinessInsights = async (transactions: Transaction[], collaborators: Profissional[]) => {
  // Initialize the GenAI client with the mandatory process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const summary = transactions.reduce((acc, curr) => {
    if (curr.type === 'INCOME') acc.totalIncome += curr.amount;
    else acc.totalExpense += curr.amount;
    return acc;
  }, { totalIncome: 0, totalExpense: 0 });

  const prompt = `
    Como um consultor especialista em Barbearias, analise os seguintes dados financeiros anuais e forneça insights estratégicos curtos:

    Total de Entradas: R$ ${summary.totalIncome}
    Total de Saídas: R$ ${summary.totalExpense}
    Número de Colaboradores: ${collaborators.length}
    Transações: ${JSON.stringify(transactions.slice(-5))}

    Responda em Português do Brasil:
    1. Análise direta do lucro.
    2. Uma dica prática para aumentar o faturamento.
  `;

  try {
    // Correct usage of generateContent with model name and prompt
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    // Use .text property to access the result
    return response.text;
  } catch (error) {
    console.error("Erro ao obter insights da IA:", error);
    return "Ocorreu um erro ao consultar a inteligência estratégica. Verifique sua conexão.";
  }
};

import React, { useState } from 'react';
import { AppData, MeetingNote } from '../types.ts';
import { GoogleGenAI } from "@google/genai";
import { MessageSquare, Plus, BrainCircuit, Trash2, Calendar, Sparkles, UserCircle, ShoppingCart } from 'lucide-react';

interface MeetingsProps {
  data: AppData;
  setData: (data: AppData) => void;
}

const Meetings: React.FC<MeetingsProps> = ({ data, setData }) => {
  const [selectedProfId, setSelectedProfId] = useState(data.profissionais[0]?.id || '');
  const [newNote, setNewNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiScript, setAiScript] = useState('');

  const selectedProf = data.profissionais.find(p => p.id === selectedProfId);
  const notes = data.meetingNotes?.filter(n => n.profissionalId === selectedProfId) || [];

  const perfData = data.producao.filter(p => p.profissionalId === selectedProfId).slice(-3);
  const mediaVenda = perfData.reduce((s,c) => s + (c.vendasProdutos || 0), 0) / (perfData.length || 1);
  const mediaAtend = perfData.reduce((s,c) => s + (c.quantidadeAtendimentos || 0), 0) / (perfData.length || 1);
  const conversao = mediaAtend > 0 ? mediaVenda / mediaAtend : 0;

  const handleAddNote = () => {
    if (!newNote) return;
    const note: MeetingNote = {
      id: Math.random().toString(36).substr(2, 9),
      profissionalId: selectedProfId,
      data: new Date().toISOString(),
      texto: newNote
    };
    setData({ ...data, meetingNotes: [...(data.meetingNotes || []), note] });
    setNewNote('');
  };

  const handleGenerateScript = async () => {
    setIsGenerating(true);
    setAiScript('');

    // Create new instance right before use to ensure latest API KEY is used
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `Analise o barbeiro ${selectedProf?.nome} com conversão de R$ ${conversao.toFixed(2)}. Gere um feedback curto de gestão.`;

    try {
      // Call generateContent with both model name and prompt as per updated SDK rules
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      // Access text via the .text property
      setAiScript(response.text || "Erro ao processar.");
    } catch (error) {
      console.error("Erro na geração de feedback:", error);
      setAiScript("Erro na IA.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-24">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Mentoria Estratégica</h2>
      </header>

      <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide">
        {data.profissionais.map(p => (
          <button
            key={p.id}
            onClick={() => { setSelectedProfId(p.id); setAiScript(''); }}
            className={`px-6 py-3 rounded-2xl text-xs font-black whitespace-nowrap border ${
              selectedProfId === p.id ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-100 text-slate-400'
            }`}
          >
            {p.nome}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[40px] border border-slate-50">
          <textarea className="w-full bg-slate-50 border rounded-[32px] p-6 text-sm min-h-[120px]" placeholder="Nova nota..." value={newNote} onChange={(e) => setNewNote(e.target.value)} />
          <button onClick={handleAddNote} className="w-full mt-4 bg-slate-900 text-white py-4 rounded-2xl font-black text-sm">SALVAR NOTA</button>
        </div>

        <div className="bg-slate-900 p-8 rounded-[40px] text-white">
          <button onClick={handleGenerateScript} disabled={isGenerating} className="w-full bg-blue-600 text-white py-5 rounded-3xl font-black text-sm flex items-center justify-center gap-2">
            {isGenerating ? 'ANALISANDO...' : 'GERAR FEEDBACK IA'}
          </button>
          {aiScript && <div className="mt-6 p-6 bg-white/5 rounded-2xl text-sm italic">{aiScript}</div>}
        </div>
      </div>
    </div>
  );
};

