import React, { useState, useMemo } from 'react';
import { AppData, MeetingNote } from '../types.ts';
import { GoogleGenAI } from "@google/genai";
import { MessageSquare, Plus, BrainCircuit, Trash2, Calendar, Sparkles, UserCircle, ShoppingCart, TrendingUp, Scissors, Target, UserCheck, DollarSign } from 'lucide-react';

interface MeetingsProps {
  data: AppData;
  setData: (data: AppData) => void;
}

const Meetings: React.FC<MeetingsProps> = ({ data, setData }) => {
  const [selectedProfId, setSelectedProfId] = useState(data.profissionais[0]?.id || '');
  const [newNote, setNewNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiScript, setAiScript] = useState('');

  const selectedProf = data.profissionais.find(p => p.id === selectedProfId);
  const notes = data.meetingNotes?.filter(n => n.profissionalId === selectedProfId) || [];

  // Cálculo de Performance para o Dashboard de Reunião
  const performance = useMemo(() => {
    if (!selectedProfId) return null;

    // Pegamos a produção mais recente para o ano atual
    const anoAtual = new Date().getFullYear();
    const producaoProf = data.producao.filter(p => p.profissionalId === selectedProfId && p.ano === anoAtual);
    const ultimoMes = producaoProf.length > 0 ? Math.max(...producaoProf.map(p => p.mes)) : 0;
    const dadosMes = producaoProf.find(p => p.mes === ultimoMes);

    if (!dadosMes) return null;

    const bruto = dadosMes.producaoBruta || 0;
    const atendimentos = dadosMes.quantidadeAtendimentos || 0;
    const produtos = dadosMes.vendasProdutos || 0;
    const ticketMedio = atendimentos > 0 ? bruto / atendimentos : 0;
    const comissao = dadosMes.repasseProfissional || 0;
    const meta = selectedProf?.metaMensal || 5000;
    const progressoMeta = Math.min((bruto / meta) * 100, 100);

    return {
      mes: ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'][ultimoMes - 1],
      bruto,
      atendimentos,
      produtos,
      ticketMedio,
      comissao,
      meta,
      progressoMeta,
      porcentagemReal: (bruto / meta) * 100
    };
  }, [data, selectedProfId, selectedProf]);

  const handleAddNote = () => {
    if (!newNote) return;
    const note: MeetingNote = {
      id: Math.random().toString(36).substr(2, 9),
      profissionalId: selectedProfId,
      data: new Date().toISOString(),
      texto: newNote
    };
    setData({ ...data, meetingNotes: [...(data.meetingNotes || []), note] });
    setNewNote('');
  };

  const handleDeleteNote = (id: string) => {
    if (confirm("Deseja remover esta nota de reunião?")) {
      setData({ ...data, meetingNotes: data.meetingNotes.filter(n => n.id !== id) });
    }
  };

  const handleGenerateScript = async () => {
    setIsGenerating(true);
    setAiScript('');
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      Atue como um gestor de barbearia de elite. Analise o desempenho do barbeiro ${selectedProf?.nome} 
      neste mês de ${performance?.mes}:
      - Faturamento Bruto: R$ ${performance?.bruto}
      - Meta Mensal: R$ ${performance?.meta}
      - Ticket Médio: R$ ${performance?.ticketMedio.toFixed(2)}
      - Venda de Produtos: R$ ${performance?.produtos}
      - Atendimentos: ${performance?.atendimentos}

      Gere um roteiro de feedback para reunião de alinhamento individual. Seja motivador mas direto ao ponto, 
      focando em como ele pode bater a meta ou melhorar o ticket médio.
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiScript(response.text || "Erro ao processar feedback.");
    } catch (error) {
      console.error("Erro na geração de feedback:", error);
      setAiScript("Erro na conexão com a IA. Tente novamente.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-32">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Pauta de Reunião</h2>
        <p className="text-sm text-slate-400 font-bold uppercase mt-1">Análise de performance e alinhamento individual</p>
      </header>

      {/* Seleção de Profissional */}
      <div className="flex gap-3 overflow-x-auto pb-4 custom-scrollbar">
        {data.profissionais.filter(p => p.ativo).map(p => (
          <button
            key={p.id}
            onClick={() => { setSelectedProfId(p.id); setAiScript(''); }}
            className={`px-8 py-4 rounded-[24px] text-xs font-black whitespace-nowrap transition-all border ${
              selectedProfId === p.id 
              ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100' 
              : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200'
            }`}
          >
            {p.nome}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Dashboard de Performance na Reunião */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
                  <BarChart2 size={24} className="text-blue-600" /> Resultados de {performance?.mes || 'Mês Atual'}
                </h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Dados para alinhamento com {selectedProf?.nome}</p>
              </div>
              <div className="px-4 py-2 bg-slate-50 rounded-xl text-[10px] font-black text-slate-500 uppercase">
                Referência: {new Date().getFullYear()}
              </div>
            </div>

            {performance ? (
              <div className="space-y-8">
                {/* Metas e Progresso Principal */}
                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <div className="flex justify-between items-end mb-4">
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Atingimento da Meta</p>
                      <h4 className="text-3xl font-black text-slate-800">R$ {performance.bruto.toLocaleString('pt-BR')}</h4>
                    </div>
                    <div className="text-right">
                      <span className={`text-xl font-black ${performance.porcentagemReal >= 100 ? 'text-emerald-500' : 'text-blue-600'}`}>
                        {Math.round(performance.porcentagemReal)}%
                      </span>
                    </div>
                  </div>
                  <div className="w-full h-4 bg-slate-200 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ${performance.porcentagemReal >= 100 ? 'bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.3)]' : 'bg-blue-600'}`}
                      style={{ width: `${performance.progressoMeta}%` }}
                    />
                  </div>
                  <div className="flex justify-between mt-3 text-[9px] font-black uppercase text-slate-400">
                    <span>Produzido</span>
                    <span>Alvo: R$ {performance.meta.toLocaleString('pt-BR')}</span>
                  </div>
                </div>

                {/* Grid de Métricas Secundárias */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  <PerformanceMetric label="Atendimentos" value={performance.atendimentos} icon={Scissors} color="text-slate-600" />
                  <PerformanceMetric label="Ticket Médio" value={`R$ ${performance.ticketMedio.toFixed(2)}`} icon={TrendingUp} color="text-blue-600" />
                  <PerformanceMetric label="Venda Prod." value={`R$ ${performance.produtos}`} icon={ShoppingCart} color="text-purple-600" />
                  <PerformanceMetric label="Sua Comissão" value={`R$ ${performance.comissao.toLocaleString('pt-BR')}`} icon={DollarSign} color="text-emerald-600" />
                </div>
              </div>
            ) : (
              <div className="py-20 text-center space-y-4">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto text-slate-300">
                  <Target size={32} />
                </div>
                <p className="text-slate-400 font-bold text-sm">Sem dados de produção para este mês ainda.</p>
              </div>
            )}
          </div>

          {/* Histórico de Notas da Reunião */}
          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <h3 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2">
              <MessageSquare size={20} className="text-blue-600" /> Histórico de Feedbacks
            </h3>
            <div className="space-y-4">
              {notes.length > 0 ? notes.map(note => (
                <div key={note.id} className="p-6 bg-slate-50 rounded-[32px] border border-slate-100 group relative">
                  <button 
                    onClick={() => handleDeleteNote(note.id)}
                    className="absolute top-4 right-4 p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                  >
                    <Trash2 size={14} />
                  </button>
                  <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase mb-2">
                    <Calendar size={10} /> {new Date(note.data).toLocaleDateString('pt-BR')}
                  </div>
                  <p className="text-sm font-medium text-slate-600 leading-relaxed whitespace-pre-wrap">{note.texto}</p>
                </div>
              )) : (
                <p className="text-center py-8 text-slate-400 font-medium text-xs italic">Nenhuma nota registrada para este barbeiro.</p>
              )}
            </div>
          </div>
        </div>

        {/* Lado Direito: Ações */}
        <div className="space-y-6">
          {/* Gerador de Script IA */}
          <div className="bg-slate-900 p-8 rounded-[48px] shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
            <div className="flex items-center gap-3 mb-8">
              <div className="p-3 bg-blue-600 rounded-2xl text-white shadow-lg shadow-blue-500/20 group-hover:rotate-6 transition-all">
                <BrainCircuit size={24} />
              </div>
              <div>
                <h3 className="font-black text-white text-lg leading-tight">Gestor IA</h3>
                <p className="text-[10px] text-blue-400 font-bold uppercase">Feedback Estratégico</p>
              </div>
            </div>

            <button 
              onClick={handleGenerateScript} 
              disabled={isGenerating || !performance}
              className={`w-full py-5 rounded-[28px] font-black text-sm uppercase flex items-center justify-center gap-3 transition-all ${
                isGenerating 
                ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                : 'bg-white text-slate-900 hover:bg-blue-50 shadow-xl'
              }`}
            >
              {isGenerating ? 'ANALISANDO DADOS...' : <><Sparkles size={18} className="text-blue-500" /> GERAR ROTEIRO</>}
            </button>

            {aiScript && (
              <div className="mt-8 p-6 bg-white/5 rounded-[32px] border border-white/10 animate-in fade-in zoom-in duration-500">
                <p className="text-sm text-slate-300 italic font-medium leading-relaxed whitespace-pre-wrap">{aiScript}</p>
              </div>
            )}

            {!performance && (
              <p className="mt-4 text-[9px] text-slate-500 font-bold text-center uppercase tracking-widest">
                Adicione produção no fluxo para usar a IA
              </p>
            )}
          </div>

          {/* Adicionar Nova Nota */}
          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <h3 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2">
              <Plus size={20} className="text-blue-600" /> Registrar Alinhamento
            </h3>
            <textarea 
              className="w-full bg-slate-50 border border-slate-100 rounded-[28px] p-6 text-sm font-medium focus:ring-2 focus:ring-blue-100 outline-none transition-all min-h-[160px]"
              placeholder="O que foi conversado nesta reunião? Metas acordadas, dificuldades, elogios..."
              value={newNote}
              onChange={(e) => setNewNote(e.target.value)}
            />
            <button 
              onClick={handleAddNote} 
              disabled={!newNote}
              className="w-full mt-4 bg-blue-600 text-white py-5 rounded-[24px] font-black text-xs uppercase shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all disabled:opacity-50"
            >
              SALVAR NOTA DE REUNIÃO
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

