import React, { useState, useMemo } from 'react';
import { AppData, Profissional, ProfissionalPerfil } from '../types.ts';
import { Plus, Trash2, X, Edit3, Scissors, UserPlus, Save, Target, Info } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, setData, year }) => {
  const [modalMode, setModalMode] = useState<'add' | 'edit' | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formProf, setFormProf] = useState({ 
    nome: '', 
    cadeira: 1, 
    comissao: 50,
    metaMensal: 5000,
    ativo: true 
  });

  const [formPerfil, setFormPerfil] = useState<ProfissionalPerfil>({
    experiencia: '',
    perfilComportamental: '',
    especialidade: '',
    objetivo: ''
  });

  const ranking = useMemo(() => {
    return data.profissionais
      .filter(p => p.ativo !== false)
      .map(prof => {
        const records = data.producao.filter(p => p.profissionalId === prof.id && p.ano === year);
        const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
        return { ...prof, totalProd };
      })
      .sort((a, b) => b.totalProd - a.totalProd);
  }, [data.profissionais, data.producao, year]);

  const openAdd = () => {
    setModalMode('add');
    setEditingId(null);
    setFormProf({ nome: '', cadeira: 1, comissao: 50, metaMensal: 5000, ativo: true });
    setFormPerfil({ experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const openEdit = (prof: Profissional) => {
    setModalMode('edit');
    setEditingId(prof.id);
    setFormProf({ 
      nome: prof.nome, 
      cadeira: prof.cadeira, 
      comissao: prof.comissao || 50,
      metaMensal: prof.metaMensal || 5000,
      ativo: prof.ativo 
    });
    setFormPerfil(prof.perfil || { experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const handleSave = () => {
    if (!formProf.nome) return;

    if (modalMode === 'add') {
      const nProf: Profissional = {
        id: Math.random().toString(36).substr(2, 9),
        ...formProf,
        perfil: formPerfil
      };
      setData({ ...data, profissionais: [...data.profissionais, nProf] });
    } else if (modalMode === 'edit' && editingId) {
      const updatedList = data.profissionais.map(p => 
        p.id === editingId ? { ...p, ...formProf, perfil: formPerfil } : p
      );
      setData({ ...data, profissionais: updatedList });
    }
    setModalMode(null);
  };

  const handleDelete = (id: string, nome: string) => {
    if (confirm(`Tem certeza que deseja remover ${nome}?`)) {
      const updatedList = data.profissionais.map(p => 
        p.id === id ? { ...p, ativo: false } : p
      );
      setData({ ...data, profissionais: updatedList });
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-32">
      <header className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Equipe & Performance</h2>
          <p className="text-sm text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de barbeiros e metas</p>
        </div>
        <button onClick={openAdd} className="bg-blue-600 text-white flex items-center gap-2 px-6 py-4 rounded-[24px] shadow-xl shadow-blue-100 font-black text-xs uppercase tracking-widest hover:scale-105 transition-all">
          <UserPlus size={18} /> Novo Barbeiro
        </button>
      </header>

      {/* Aviso de Inserção Manual */}
      <div className="bg-amber-50 border border-amber-100 p-4 rounded-2xl flex items-start gap-3">
        <Info className="text-amber-500 mt-1 shrink-0" size={18} />
        <p className="text-xs font-bold text-amber-700 leading-relaxed uppercase">
