            <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => openEdit(prof)} className="p-2 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-100"><Edit3 size={16} /></button>
              <button onClick={() => handleDelete(prof.id, prof.nome)} className="p-2 bg-red-50 text-red-500 rounded-xl hover:bg-red-100"><Trash2 size={16} /></button>
            </div>

            <div className="flex items-center gap-4 mb-6">
              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-white shadow-lg ${
                idx === 0 ? 'bg-amber-400 rotate-3' : idx === 1 ? 'bg-slate-400' : 'bg-slate-800'
              }`}>
                {idx + 1}º
              </div>
              <div>
                <h3 className="font-black text-slate-800 text-lg leading-tight">{prof.nome}</h3>
                <p className="text-[10px] font-black text-slate-400 uppercase mt-1">Meta Individual: R$ {(prof.metaMensal || 5000).toLocaleString('pt-BR')}</p>
              </div>
            </div>

            <div className="space-y-4">
              <div className="p-5 bg-slate-50 rounded-[32px] border border-slate-100 group-hover:bg-blue-50/50 transition-colors">
                <p className="text-[10px] font-black text-slate-400 uppercase mb-1 flex items-center gap-2">
                   <Scissors size={12} className="text-blue-500" /> Produção Bruta Ano
                </p>
                <p className="text-2xl font-black text-slate-800">R$ {prof.totalProd.toLocaleString('pt-BR')}</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      {modalMode && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[48px] p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h3 className="text-2xl font-black text-slate-800">{modalMode === 'add' ? 'Adicionar' : 'Editar'} Barbeiro</h3>
                <p className="text-xs text-slate-400 font-bold uppercase mt-1">Metas & Cadastro</p>
              </div>
              <button onClick={() => setModalMode(null)} className="p-3 bg-slate-100 text-slate-400 rounded-full"><X /></button>
            </div>

            <div className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">Nome Completo</label>
                  <input type="text" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-700" value={formProf.nome} onChange={(e) => setFormProf({...formProf, nome: e.target.value})} />
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">Cadeira</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" value={formProf.cadeira} onChange={(e) => setFormProf({...formProf, cadeira: Number(e.target.value)})} />
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">% Comissão</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" value={formProf.comissao} onChange={(e) => setFormProf({...formProf, comissao: Number(e.target.value)})} />
                </div>

                <div className="col-span-2 bg-blue-50 p-6 rounded-[32px] border border-blue-100 mt-2">
                  <label className="text-[10px] font-black text-blue-400 uppercase ml-2 mb-2 block flex items-center gap-2">
                    <Target size={14} /> Meta de Produção Mensal (R$)
                  </label>
                  <input type="number" className="w-full p-4 bg-white border border-blue-200 rounded-2xl font-black text-blue-700 text-xl" value={formProf.metaMensal} onChange={(e) => setFormProf({...formProf, metaMensal: Number(e.target.value)})} />
                  <p className="text-[9px] text-blue-400 mt-2 font-bold uppercase">* Esta meta atualiza os dashboards da Home automaticamente.</p>
                </div>
              </div>

              <div className="pt-4">
                <button onClick={handleSave} className="w-full bg-blue-600 text-white py-5 rounded-3xl font-black text-sm uppercase shadow-lg flex items-center justify-center gap-2">
                  <Save size={18} /> {modalMode === 'add' ? 'CADASTRAR' : 'SALVAR ALTERAÇÕES'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Professionals;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal, ParametrosAnuais, Profissional } from '../types.ts';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, UserCheck, Plus, ArrowDownRight, Scissors, Target, PieChart as PieChartIcon, Award, UserPlus, UserMinus, BarChart2, Wallet, Users, DollarSign } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);

  const currentParams = data.parametros.find(p => p.ano === year) || data.parametros[0] || { metaFaturamento: 0 };
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  const handleUpdateMetaAnual = (val: number) => {
    const updatedParams = data.parametros.map(p => 
      p.ano === year ? { ...p, metaFaturamento: val } : p
    );
    if (!data.parametros.find(p => p.ano === year)) {
      updatedParams.push({
        ano: year, metaFaturamento: val, metaLucro: 0, metaAssinaturas: 0, metaGeladeira: 0, metaGastos: 0, metaPorCadeira: 5000
      });
    }
    setData({ ...data, parametros: updatedParams });
  };

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, nome: prof.nome, bruta: p?.producaoBruta || 0, repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0, vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0, cartao: extra?.cartao || 0, pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0, pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0, cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods, gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);
    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + (extra?.dinheiro || 0) + (extra?.cartao || 0) + (extra?.pix || 0) + (extra?.assinaturas || 0) + (extra?.pacotes || 0);
    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;
    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const monthDashboard = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];
    const expenseData = m.gastosList.map(g => ({ name: g.categoria, value: g.valor })).filter(g => g.value > 0);
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const profRanking = data.profissionais.map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const totalProd = p?.producaoBruta || 0;
      const comissaoBarbeiro = p?.repasseProfissional || 0;
      const recAssinaturas = p?.repasseAssinatura || 0;
      const totalHouse = (totalProd - comissaoBarbeiro) + recAssinaturas;
      return { nome: prof.nome, totalProd, comissaoBarbeiro, recAssinaturas, totalHouse };
    });

    // O barbeiro Gabriel não pode estar incluso no ranking de destaque
    const rankingParaDestaque = profRanking
      .filter(p => !p.nome.toLowerCase().includes('gabriel'))
      .sort((a, b) => b.totalProd - a.totalProd);

    const destaque = rankingParaDestaque[0];

    const totalProdBruta = profRanking.reduce((s, p) => s + p.totalProd, 0);
    const totalComissaoBarbeiros = profRanking.reduce((s, p) => s + p.comissaoBarbeiro, 0);
    const totalAssinaturas = profRanking.reduce((s, p) => s + p.recAssinaturas, 0);
    const totalFicouBarbearia = profRanking.reduce((s, p) => s + p.totalHouse, 0);

    return { ...m, expenseData, COLORS, profRanking, destaque, totalProdBruta, totalComissaoBarbeiros, totalAssinaturas, totalFicouBarbearia };
  }, [selectedMonth, matrix, data.profissionais]);

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };
    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));
    const newGastos: GastoMensal[] = formData.gastos.map(g => ({ ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });
    setShowModal(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="bg-slate-950 p-10 rounded-[48px] shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8 border border-white/5 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full -mr-32 -mt-32 blur-[80px]"></div>
        <div className="flex items-center gap-5 z-10">
          <div className="p-4 bg-blue-600 rounded-3xl text-white shadow-xl shadow-blue-500/20 rotate-3">
            <Target size={28} />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tighter">Planejamento Estratégico {year}</h2>
            <p className="text-[10px] text-blue-400 font-bold uppercase mt-1 tracking-widest text-left">Defina o alvo anual de faturamento</p>
          </div>
        </div>
        <div className="w-full md:w-auto flex flex-col items-end z-10">
          <label className="text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Alvo Anual (R$)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-blue-500 font-black text-2xl">R$</span>
            <input 
              type="number" 
              value={currentParams.metaFaturamento} 
              onChange={(e) => handleUpdateMetaAnual(Number(e.target.value))}
              className="bg-white/5 border border-white/10 p-5 pl-14 rounded-[28px] text-white font-black text-3xl w-full md:w-72 focus:border-blue-500 outline-none transition-all"
            />
          </div>
        </div>
      </div>

      <div className="flex justify-between items-center px-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Fluxo de Caixa</h2>
          <p className="text-xs text-slate-400 font-bold uppercase mt-1 tracking-widest">Controle de entradas e saídas mensais</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-8 py-4 rounded-[24px] font-black text-xs uppercase shadow-xl shadow-blue-100 flex items-center gap-2 hover:scale-105 transition-all">
          <PlusCircle size={18} /> Novo Fechamento
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
            <tr>
              <th className="px-8 py-6">Mês</th>
              <th className="px-8 py-6 text-right">Faturamento</th>
              <th className="px-8 py-6 text-right">Saídas</th>
              <th className="px-8 py-6 text-right">Líquido</th>
              <th className="px-8 py-6 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((m) => (
              <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                <td className="px-8 py-6 font-black text-slate-800 text-base">{m.nome}</td>
                <td className="px-8 py-6 text-right font-bold text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                <td className="px-8 py-6 text-right text-red-500 font-bold">R$ {(m.repasse + m.gastosTotal).toLocaleString('pt-BR')}</td>
                <td className={`px-8 py-6 text-right font-black text-base ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                  R$ {m.liquido.toLocaleString('pt-BR')}
                </td>
                <td className="px-8 py-6 text-center">
                  <div className="flex justify-center gap-2">
                    <button onClick={() => { setSelectedMonth(m.mes); setShowDetailModal(true); }} className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl transition-all" title="Ver Dashboard do Mês"><Eye size={16} /></button>
                    <button onClick={() => { setFormData(prev => ({ ...prev, mes: m.mes })); setShowModal(true); }} className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl transition-all" title="Editar Lançamento"><Edit2 size={16} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* DASHBOARD MENSAL DETALHADO */}
      {showDetailModal && monthDashboard && (
        <div className="fixed inset-0 z-[150] bg-slate-950/80 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-slate-50 w-full max-w-5xl h-[90vh] rounded-[48px] shadow-2xl overflow-hidden flex flex-col animate-in zoom-in duration-300">
            <header className="p-10 bg-white border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-3xl font-black text-slate-800 tracking-tighter">Painel de {monthDashboard.nome} / {year}</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Análise profunda de resultados</p>
              </div>
              <button onClick={() => setShowDetailModal(false)} className="bg-slate-100 p-5 rounded-full text-slate-400 hover:bg-slate-200"><X /></button>
            </header>

            <div className="flex-1 overflow-y-auto p-10 space-y-8 custom-scrollbar">
              {/* Cards de Topo - ESPECÍFICOS */}
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <MiniStats label="Produção Bruta" value={`R$ ${monthDashboard.totalProdBruta.toLocaleString('pt-BR')}`} icon={Scissors} color="text-slate-600" bg="bg-slate-100" />
                <MiniStats label="Comissão Recebida" value={`R$ ${monthDashboard.totalComissaoBarbeiros.toLocaleString('pt-BR')}`} icon={Users} color="text-red-500" bg="bg-red-50" />
                <MiniStats label="Rec. de Assinatura" value={`R$ ${monthDashboard.totalAssinaturas.toLocaleString('pt-BR')}`} icon={UserCheck} color="text-blue-600" bg="bg-blue-50" />
                <MiniStats label="Total Barbearia" value={`R$ ${monthDashboard.totalFicouBarbearia.toLocaleString('pt-BR')}`} icon={DollarSign} color="text-emerald-600" bg="bg-emerald-50" />
              </div>

              {/* Destaque e Gastos */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Ranking de Gastos */}
                <div className="bg-white p-8 rounded-[40px] border border-slate-100">
                  <h4 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2"><PieChartIcon size={20} className="text-red-500" /> Ranking de Gastos</h4>
                  <div className="h-48 mb-6">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={monthDashboard.expenseData} innerRadius={50} outerRadius={70} dataKey="value" stroke="none">
                          {monthDashboard.expenseData.map((entry, index) => <Cell key={index} fill={monthDashboard.COLORS[index % monthDashboard.COLORS.length]} />)}
                        </Pie>
                        <Tooltip formatter={(v: number) => `R$ ${v.toLocaleString('pt-BR')}`} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="space-y-3">
                    {monthDashboard.expenseData.sort((a,b) => b.value - a.value).map((g, idx) => (
                      <div key={idx} className="flex justify-between items-center p-3 bg-slate-50 rounded-2xl">
                        <span className="text-xs font-bold text-slate-600">{g.name}</span>
                        <span className="text-xs font-black text-slate-800">R$ {g.value.toLocaleString('pt-BR')}</span>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Destaque Individual */}
                <div className="bg-slate-950 p-8 rounded-[40px] text-white relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <h4 className="text-lg font-black mb-6 flex items-center gap-2"><Award size={20} className="text-amber-400" /> Destaque do Mês</h4>

                  {monthDashboard.destaque ? (
                    <div className="space-y-6">
                      <div className="p-8 bg-white/5 border border-white/10 rounded-[32px] text-center">
                        <div className="w-20 h-20 bg-amber-400 rounded-3xl mx-auto flex items-center justify-center text-amber-900 font-black text-3xl mb-4 rotate-3 shadow-2xl shadow-amber-400/20">
                          1º
                        </div>
                        <h5 className="text-2xl font-black">{monthDashboard.destaque.nome}</h5>
                        <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Líder em Produção (Exceto Gabriel)</p>
                      </div>
                      <div className="p-6 bg-blue-600 rounded-[32px] flex justify-between items-center">
                        <div>
                          <p className="text-[9px] font-black text-blue-100 uppercase">Produção Individual</p>
                          <p className="text-xl font-black">R$ {monthDashboard.destaque.totalProd.toLocaleString('pt-BR')}</p>
                        </div>
                        <div className="text-right">
                          <p className="text-[9px] font-black text-blue-100 uppercase">Total para Casa</p>
                          <p className="text-xl font-black">R$ {monthDashboard.destaque.totalHouse.toLocaleString('pt-BR')}</p>
                        </div>
                      </div>
                    </div>
                  ) : (
                    <div className="text-center py-20 text-slate-500">
                      <p className="text-sm font-bold">Nenhum barbeiro elegível no ranking.</p>
                    </div>
                  )}
                </div>
              </div>

              {/* Ranking Profissionais - Colunas Específicas */}
              <div className="bg-white p-8 rounded-[40px] border border-slate-100">
                <h4 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2"><BarChart2 size={20} className="text-blue-600" /> Divisão Financeira por Barbeiro</h4>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                      <tr>
                        <th className="py-4 px-2">Barbeiro</th>
                        <th className="py-4 px-2 text-right">Prod. Bruta</th>
                        <th className="py-4 px-2 text-right text-red-500">Comissão Recebida</th>
                        <th className="py-4 px-2 text-right text-blue-500">Rec. Assinatura</th>
                        <th className="py-4 px-2 text-right">Total Barbearia</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {monthDashboard.profRanking.map((p, idx) => (
                        <tr key={idx} className="hover:bg-slate-50">
                          <td className="py-4 px-2 font-black text-slate-800">{p.nome}</td>
                          <td className="py-4 px-2 text-right font-bold text-slate-400">R$ {p.totalProd.toLocaleString('pt-BR')}</td>
                          <td className="py-4 px-2 text-right font-bold text-red-400">R$ {p.comissaoBarbeiro.toLocaleString('pt-BR')}</td>
                          <td className="py-4 px-2 text-right font-bold text-blue-500">R$ {p.recAssinaturas.toLocaleString('pt-BR')}</td>
                          <td className="py-4 px-2 text-right font-black text-emerald-600 bg-emerald-50/20">R$ {p.totalHouse.toLocaleString('pt-BR')}</td>
                        </tr>
                      ))}
                    </tbody>
                    <tfoot className="bg-slate-50 font-black">
                      <tr>
                        <td className="py-4 px-2 text-xs uppercase">TOTAIS DO MÊS</td>
                        <td className="py-4 px-2 text-right text-slate-400">R$ {monthDashboard.totalProdBruta.toLocaleString('pt-BR')}</td>
                        <td className="py-4 px-2 text-right text-red-400">R$ {monthDashboard.totalComissaoBarbeiros.toLocaleString('pt-BR')}</td>
                        <td className="py-4 px-2 text-right text-blue-600">R$ {monthDashboard.totalAssinaturas.toLocaleString('pt-BR')}</td>
                        <td className="py-4 px-2 text-right text-emerald-600">R$ {monthDashboard.totalFicouBarbearia.toLocaleString('pt-BR')}</td>
                      </tr>
                    </tfoot>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* MODAL DE LANÇAMENTO */}
      {showModal && (
        <div className="fixed inset-0 z-[100] bg-slate-900/70 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-3xl rounded-[48px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in duration-300">
            <div className="p-10 border-b border-slate-50 flex justify-between items-center bg-white sticky top-0 z-10">
              <div>
                <h3 className="text-2xl font-black text-slate-800">Fechamento Mensal</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase mt-1 tracking-widest">Insira os dados reais do período para análise de BI</p>
              </div>
              <button onClick={() => setShowModal(false)} className="bg-slate-100 p-4 rounded-full text-slate-400 hover:bg-slate-200 transition-all"><X /></button>
            </div>

            <div className="p-10 overflow-y-auto space-y-10 flex-1 custom-scrollbar">
              <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Mês do Ano</label>
                  <select className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[24px] font-black text-slate-700 outline-none focus:border-blue-500" value={formData.mes} onChange={(e) => setFormData({...formData, mes: Number(e.target.value)})}>
                    {meses.map((m, i) => <option key={m} value={i+1}>{m}</option>)}
                  </select>
                </div>
                <Input label="Rec. Assinaturas (R$)" value={formData.assinaturas} onChange={(v: number) => setFormData({...formData, assinaturas: v})} />
                <Input label="Novos Assinantes" value={formData.novosAssinantes} onChange={(v: number) => setFormData({...formData, novosAssinantes: v})} />
                <Input label="Cancelamentos" value={formData.cancelamentosAssinantes} onChange={(v: number) => setFormData({...formData, cancelamentosAssinantes: v})} />
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-red-500"><ArrowDownRight size={22} /> Despesas Reais</h4>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                  {formData.gastos.map((g, idx) => (
                    <div key={g.categoria}>
                      <label className="text-[9px] font-black text-slate-400 uppercase block mb-2 ml-2">{g.categoria}</label>
                      <input type="number" value={g.valor === 0 ? '' : g.valor} onChange={(e) => { let n = [...formData.gastos]; n[idx].valor = Number(e.target.value); setFormData({...formData, gastos: n}); }} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-[20px] text-sm font-bold focus:border-red-400 outline-none" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-blue-600"><Scissors size={22} /> Produção & Métricas Individuais</h4>
                <div className="space-y-6">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-8 bg-slate-50 rounded-[40px] border border-slate-100">
                      <div className="flex justify-between items-center mb-6">
                        <span className="text-sm font-black text-slate-800 uppercase tracking-tighter">{p.nome}</span>
                        <div className="px-4 py-2 bg-blue-100 rounded-2xl">
                          <span className="text-[10px] font-black text-blue-600 uppercase">
                            Ticket Médio: R$ {p.quantidadeAtendimentos > 0 ? (p.bruta / p.quantidadeAtendimentos).toFixed(2) : '0.00'}
                          </span>
                        </div>
                      </div>
                      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                        <MiniInput label="Prod. Bruta" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse Serv." value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse Assin." value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Atendimentos" value={p.quantidadeAtendimentos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].quantidadeAtendimentos = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Venda Prod." value={p.vendasProdutos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].vendasProdutos = v; setFormData({...formData, producoes: n}); }} />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-10 bg-slate-50 border-t border-slate-100">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-6 rounded-[28px] font-black text-sm uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3 hover:bg-blue-700 transition-all active:scale-95">
                <Save size={20} /> FINALIZAR E SINCRONIZAR DADOS
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const MiniStats = ({ label, value, icon: Icon, color, bg }: any) => (
  <div className="bg-white p-5 rounded-[32px] border border-slate-100 flex items-center gap-4">
    <div className={`p-3 ${bg} ${color} rounded-2xl`}><Icon size={20} /></div>
    <div>
      <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest text-left">{label}</p>
      <p className={`text-sm font-black ${color}`}>{value}</p>
    </div>
  </div>
);

const Input = ({ label, value, onChange }: any) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">{label}</label>
    <input type="number" value={value === 0 ? '' : value} onChange={(e) => onChange(Number(e.target.value))} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[24px] font-black text-slate-800 outline-none focus:border-blue-500" />
  </div>
);

const MiniInput = ({ label, value, onChange }: any) => (
  <div>
    <label className="text-[8px] font-black text-slate-400 uppercase block mb-2 ml-1">{label}</label>
    <input type="number" value={value === 0 ? '' : value} onChange={(e) => onChange(Number(e.target.value))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-xs font-bold focus:border-blue-500 outline-none" />
  </div>
);

export default CashFlow;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal, ParametrosAnuais, Profissional } from '../types.ts';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, UserCheck, Plus, ArrowDownRight, Scissors, Target, PieChart as PieChartIcon, Award, UserPlus, UserMinus, BarChart2, Wallet, Users, DollarSign, Star } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);

  const currentParams = data.parametros.find(p => p.ano === year) || data.parametros[0] || { metaFaturamento: 0 };
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  const handleUpdateMetaAnual = (val: number) => {
    const updatedParams = data.parametros.map(p => 
      p.ano === year ? { ...p, metaFaturamento: val } : p
    );
    if (!data.parametros.find(p => p.ano === year)) {
      updatedParams.push({
        ano: year, metaFaturamento: val, metaLucro: 0, metaAssinaturas: 0, metaGeladeira: 0, metaGastos: 0, metaPorCadeira: 5000
      });
    }
    setData({ ...data, parametros: updatedParams });
  };

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, nome: prof.nome, bruta: p?.producaoBruta || 0, repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0, vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0, cartao: extra?.cartao || 0, pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0, pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0, cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods, gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);
    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + (extra?.dinheiro || 0) + (extra?.cartao || 0) + (extra?.pix || 0) + (extra?.assinaturas || 0) + (extra?.pacotes || 0);
    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;
    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const monthDashboard = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];
    const expenseData = m.gastosList.map(g => ({ name: g.categoria, value: g.valor })).filter(g => g.value > 0);
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const rawProfRanking = data.profissionais.map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const totalProd = p?.producaoBruta || 0;
      const comissaoBarbeiro = p?.repasseProfissional || 0;
      const recAssinaturas = p?.repasseAssinatura || 0;
      const totalRecebidoBarbeiro = comissaoBarbeiro + recAssinaturas;
      // O que sobra do barbeiro para a barbearia: Produção - o que ele levou de comissão - o que ele levou de assinatura
      const totalHouse = totalProd - comissaoBarbeiro - recAssinaturas;
      return { 
        id: prof.id,
        nome: prof.nome, 
        totalProd, 
        comissaoBarbeiro, 
        recAssinaturas, 
        totalRecebidoBarbeiro, 
        totalHouse 
      };
    });

    // O barbeiro Gabriel não pode estar incluso no ranking de destaque
    const elegiveisDestaque = rawProfRanking
      .filter(p => !p.nome.toLowerCase().includes('gabriel'))
      .sort((a, b) => b.totalProd - a.totalProd);

    const destaque = elegiveisDestaque[0];

    const profRanking = rawProfRanking.map(p => ({
      ...p,
      isDestaque: destaque && p.id === destaque.id
    })).sort((a, b) => b.totalProd - a.totalProd);

    const totalProdBruta = profRanking.reduce((s, p) => s + p.totalProd, 0);
    const totalComissaoBarbeiros = profRanking.reduce((s, p) => s + p.comissaoBarbeiro, 0);
    const totalAssinaturasPagas = profRanking.reduce((s, p) => s + p.recAssinaturas, 0);
    const totalFicouBarbearia = profRanking.reduce((s, p) => s + p.totalHouse, 0);

    return { ...m, expenseData, COLORS, profRanking, destaque, totalProdBruta, totalComissaoBarbeiros, totalAssinaturasPagas, totalFicouBarbearia };
  }, [selectedMonth, matrix, data.profissionais]);

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };
    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));
    const newGastos: GastoMensal[] = formData.gastos.map(g => ({ ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });
    setShowModal(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="bg-slate-950 p-10 rounded-[48px] shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8 border border-white/5 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full -mr-32 -mt-32 blur-[80px]"></div>
        <div className="flex items-center gap-5 z-10">
          <div className="p-4 bg-blue-600 rounded-3xl text-white shadow-xl shadow-blue-500/20 rotate-3">
            <Target size={28} />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tighter">Planejamento Estratégico {year}</h2>
            <p className="text-[10px] text-blue-400 font-bold uppercase mt-1 tracking-widest text-left">Defina o alvo anual de faturamento</p>
          </div>
        </div>
        <div className="w-full md:w-auto flex flex-col items-end z-10">
          <label className="text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Alvo Anual (R$)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-blue-500 font-black text-2xl">R$</span>
            <input 
              type="number" 
              value={currentParams.metaFaturamento} 
              onChange={(e) => handleUpdateMetaAnual(Number(e.target.value))}
              className="bg-white/5 border border-white/10 p-5 pl-14 rounded-[28px] text-white font-black text-3xl w-full md:w-72 focus:border-blue-500 outline-none transition-all"
            />
          </div>
        </div>
      </div>

      <div className="flex justify-between items-center px-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Fluxo de Caixa</h2>
          <p className="text-xs text-slate-400 font-bold uppercase mt-1 tracking-widest">Controle de entradas e saídas mensais</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-8 py-4 rounded-[24px] font-black text-xs uppercase shadow-xl shadow-blue-100 flex items-center gap-2 hover:scale-105 transition-all">
          <PlusCircle size={18} /> Novo Fechamento
        </button>
      </div>

      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
            <tr>
              <th className="px-8 py-6">Mês</th>
              <th className="px-8 py-6 text-right">Faturamento</th>
              <th className="px-8 py-6 text-right">Saídas</th>
              <th className="px-8 py-6 text-right">Líquido</th>
              <th className="px-8 py-6 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((m) => (
              <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                <td className="px-8 py-6 font-black text-slate-800 text-base">{m.nome}</td>
                <td className="px-8 py-6 text-right font-bold text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                <td className="px-8 py-6 text-right text-red-500 font-bold">R$ {(m.repasse + m.gastosTotal).toLocaleString('pt-BR')}</td>
                <td className={`px-8 py-6 text-right font-black text-base ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                  R$ {m.liquido.toLocaleString('pt-BR')}
                </td>
                <td className="px-8 py-6 text-center">
                  <div className="flex justify-center gap-2">
                    <button onClick={() => { setSelectedMonth(m.mes); setShowDetailModal(true); }} className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl transition-all" title="Ver Dashboard do Mês"><Eye size={16} /></button>
                    <button onClick={() => { setFormData(prev => ({ ...prev, mes: m.mes })); setShowModal(true); }} className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl transition-all" title="Editar Lançamento"><Edit2 size={16} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* DASHBOARD MENSAL DETALHADO */}
      {showDetailModal && monthDashboard && (
        <div className="fixed inset-0 z-[150] bg-slate-950/80 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-slate-50 w-full max-w-6xl h-[90vh] rounded-[48px] shadow-2xl overflow-hidden flex flex-col animate-in zoom-in duration-300">
            <header className="p-10 bg-white border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-3xl font-black text-slate-800 tracking-tighter">Painel de {monthDashboard.nome} / {year}</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Análise profunda de resultados e performance individual</p>
              </div>
              <button onClick={() => setShowDetailModal(false)} className="bg-slate-100 p-5 rounded-full text-slate-400 hover:bg-slate-200"><X /></button>
            </header>

            <div className="flex-1 overflow-y-auto p-10 space-y-10 custom-scrollbar">
              {/* Cards de Topo do Mês */}
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <MiniStats label="Produção Bruta" value={`R$ ${monthDashboard.totalProdBruta.toLocaleString('pt-BR')}`} icon={Scissors} color="text-slate-600" bg="bg-slate-100" />
                <MiniStats label="Comissão Barbeiros" value={`R$ ${monthDashboard.totalComissaoBarbeiros.toLocaleString('pt-BR')}`} icon={Users} color="text-red-500" bg="bg-red-50" />
                <MiniStats label="Pago Assinaturas" value={`R$ ${monthDashboard.totalAssinaturasPagas.toLocaleString('pt-BR')}`} icon={UserCheck} color="text-blue-600" bg="bg-blue-50" />
                <MiniStats label="Total Barbearia" value={`R$ ${monthDashboard.totalFicouBarbearia.toLocaleString('pt-BR')}`} icon={DollarSign} color="text-emerald-600" bg="bg-emerald-50" />
              </div>

              {/* Tabela de Performance Específica por Barbeiro */}
              <div className="bg-white p-8 rounded-[40px] border border-slate-100 shadow-sm overflow-hidden">
                <div className="flex justify-between items-center mb-6">
                   <h4 className="text-lg font-black text-slate-800 flex items-center gap-2"><BarChart2 size={20} className="text-blue-600" /> Divisão Financeira Detalhada</h4>
                   <div className="flex items-center gap-2 px-4 py-2 bg-amber-50 rounded-2xl text-[10px] font-black text-amber-600 uppercase">
                     <Star size={12} fill="currentColor" /> Gabriel Excluído do Ranking Destaque
                   </div>
                </div>

                <div className="overflow-x-auto">
                  <table className="w-full text-left">
