                          <td className="py-5 px-3 text-right font-black text-emerald-600 bg-emerald-50/20">R$ {p.totalHouse.toLocaleString('pt-BR')}</td>
                        </tr>
                      ))}
                    </tbody>
                    <tfoot className="bg-slate-100/50 font-black">
                      <tr>
                        <td colSpan={2} className="py-5 px-3 text-xs uppercase text-slate-400">Consolidado do Período</td>
