      {/* MODAL DE LANÇAMENTO */}
      {showModal && (
        <div className="fixed inset-0 z-[100] bg-slate-900/70 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-3xl rounded-[48px] shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in duration-300">
            <div className="p-10 border-b border-slate-50 flex justify-between items-center bg-white sticky top-0 z-10">
              <div>
                <h3 className="text-2xl font-black text-slate-800">Fechamento Mensal</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase mt-1 tracking-widest">Insira os dados reais do período para análise de BI</p>
              </div>
              <button onClick={() => setShowModal(false)} className="bg-slate-100 p-4 rounded-full text-slate-400 hover:bg-slate-200 transition-all"><X /></button>
            </div>

            <div className="p-10 overflow-y-auto space-y-10 flex-1 custom-scrollbar">
              <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Mês do Ano</label>
                  <select className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[24px] font-black text-slate-700 outline-none focus:border-blue-500" value={formData.mes} onChange={(e) => setFormData({...formData, mes: Number(e.target.value)})}>
                    {meses.map((m, i) => <option key={m} value={i+1}>{m}</option>)}
                  </select>
                </div>
                <Input label="Rec. Assinaturas (R$)" value={formData.assinaturas} onChange={(v: number) => setFormData({...formData, assinaturas: v})} />
                <Input label="Novos Assinantes" value={formData.novosAssinantes} onChange={(v: number) => setFormData({...formData, novosAssinantes: v})} />
                <Input label="Cancelamentos" value={formData.cancelamentosAssinantes} onChange={(v: number) => setFormData({...formData, cancelamentosAssinantes: v})} />
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-red-500"><ArrowDownRight size={22} /> Despesas Reais</h4>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                  {formData.gastos.map((g, idx) => (
                    <div key={g.categoria}>
                      <label className="text-[9px] font-black text-slate-400 uppercase block mb-2 ml-2">{g.categoria}</label>
                      <input type="number" value={g.valor === 0 ? '' : g.valor} onChange={(e) => { let n = [...formData.gastos]; n[idx].valor = Number(e.target.value); setFormData({...formData, gastos: n}); }} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-[20px] text-sm font-bold focus:border-red-400 outline-none" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-blue-600"><Scissors size={22} /> Produção & Métricas Individuais</h4>
                <div className="space-y-6">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-8 bg-slate-50 rounded-[40px] border border-slate-100">
                      <div className="flex justify-between items-center mb-6">
                        <span className="text-sm font-black text-slate-800 uppercase tracking-tighter">{p.nome}</span>
                        <div className="px-4 py-2 bg-blue-100 rounded-2xl">
                          <span className="text-[10px] font-black text-blue-600 uppercase">
                            Ticket Médio: R$ {p.quantidadeAtendimentos > 0 ? (p.bruta / p.quantidadeAtendimentos).toFixed(2) : '0.00'}
                          </span>
                        </div>
                      </div>
                      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                        <MiniInput label="Prod. Bruta" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse Serv." value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse Assin." value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Atendimentos" value={p.quantidadeAtendimentos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].quantidadeAtendimentos = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Venda Prod." value={p.vendasProdutos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].vendasProdutos = v; setFormData({...formData, producoes: n}); }} />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-10 bg-slate-50 border-t border-slate-100">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-6 rounded-[28px] font-black text-sm uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3 hover:bg-blue-700 transition-all active:scale-95">
                <Save size={20} /> FINALIZAR E SINCRONIZAR DADOS
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

