                      </div>
                      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                        <MiniInput label="Prod. Bruta" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse Serv." value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse Assin." value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Atendimentos" value={p.quantidadeAtendimentos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].quantidadeAtendimentos = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Venda Prod." value={p.vendasProdutos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].vendasProdutos = v; setFormData({...formData, producoes: n}); }} />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="p-10 bg-slate-50 border-t border-slate-100">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-6 rounded-[28px] font-black text-sm uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3 hover:bg-blue-700 transition-all active:scale-95">
                <Save size={20} /> FINALIZAR E SINCRONIZAR DADOS
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const SummaryCard = ({ label, value, icon: Icon, color, bg }: any) => (
  <div className={`${bg} p-6 rounded-[32px] border border-slate-100 flex flex-col gap-3 shadow-sm`}>
    <div className={`w-10 h-10 bg-slate-50 ${color} rounded-xl flex items-center justify-center`}>
      <Icon size={20} />
    </div>
    <div>
      <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{label}</p>
      <p className={`text-sm font-black ${color}`}>{value}</p>
    </div>
  </div>
);

const Input = ({ label, value, onChange }: any) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">{label}</label>
    <input type="number" value={value === 0 ? '' : value} onChange={(e) => onChange(Number(e.target.value))} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-[24px] font-black text-slate-800 outline-none focus:border-blue-500" />
  </div>
);

const MiniInput = ({ label, value, onChange }: any) => (
  <div>
    <label className="text-[8px] font-black text-slate-400 uppercase block mb-2 ml-1">{label}</label>
    <input type="number" value={value === 0 ? '' : value} onChange={(e) => onChange(Number(e.target.value))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-xs font-bold focus:border-blue-500 outline-none" />
  </div>
);

export default CashFlow;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal, ParametrosAnuais, Profissional } from '../types.ts';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, UserCheck, Plus, ArrowDownRight, Scissors, Target, PieChart as PieChartIcon, Award, UserPlus, UserMinus, BarChart2, Wallet, Users, DollarSign, Star, Trophy, Sparkles, Settings2, Trash2, Check } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);
  const [newCatName, setNewCatName] = useState('');
  const [editingCatIndex, setEditingCatIndex] = useState<number | null>(null);
  const [tempCatName, setTempCatName] = useState('');

  const currentParams = data.parametros.find(p => p.ano === year) || data.parametros[0] || { metaFaturamento: 0 };
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  const handleUpdateMetaAnual = (val: number) => {
    const updatedParams = data.parametros.map(p => 
      p.ano === year ? { ...p, metaFaturamento: val } : p
    );
    setData({ ...data, parametros: updatedParams });
  };

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, nome: prof.nome, bruta: p?.producaoBruta || 0, repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0, vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0, cartao: extra?.cartao || 0, pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0, pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0, cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods, gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);
    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + (extra?.dinheiro || 0) + (extra?.cartao || 0) + (extra?.pix || 0) + (extra?.assinaturas || 0) + (extra?.pacotes || 0);
    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;
    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const monthDashboard = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const profData = data.profissionais.map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const totalProd = p?.producaoBruta || 0;
      const comissaoProducao = p?.repasseProfissional || 0;
      const recebidoAssinatura = p?.repasseAssinatura || 0;

      const totalRecebidoBarbeiro = comissaoProducao + recebidoAssinatura;
      const saldoBarbeariaServico = totalProd - comissaoProducao;

      return { 
        id: prof.id,
        nome: prof.nome, 
        totalProd, 
        comissaoProducao, 
        recebidoAssinatura, 
        totalRecebidoBarbeiro, 
        saldoBarbeariaServico 
      };
    });

    const elegiveisDestaque = profData
      .filter(p => !p.nome.toLowerCase().includes('gabriel'))
      .sort((a, b) => b.totalProd - a.totalProd);

    const destaque = elegiveisDestaque[0];

    const profRanking = profData.map(p => ({
      ...p,
      isDestaque: destaque && p.id === destaque.id && p.totalProd > 0
    })).sort((a, b) => b.totalProd - a.totalProd);

    const totalProducaoBruta = profRanking.reduce((s, p) => s + p.totalProd, 0);
    const totalComissoesPagas = profRanking.reduce((s, p) => s + p.comissaoProducao, 0);
    const totalRepassesAssinatura = profRanking.reduce((s, p) => s + p.recebidoAssinatura, 0);
    const totalSaldoBarbeariaServicos = profRanking.reduce((s, p) => s + p.saldoBarbeariaServico, 0);
    const faturamentoTotalAssinaturas = m.extra?.assinaturas || 0;
    const liquidoAssinaturasCasa = faturamentoTotalAssinaturas - totalRepassesAssinatura;

    const expenseData = m.gastosList.map(g => ({ name: g.categoria, value: g.valor })).filter(g => g.value > 0);

    return { 
      ...m, 
      expenseData, 
      COLORS, 
      profRanking, 
      destaque, 
      totalProducaoBruta, 
      totalComissoesPagas, 
      totalRepassesAssinatura, 
      totalSaldoBarbeariaServicos,
      faturamentoTotalAssinaturas,
      liquidoAssinaturasCasa
    };
  }, [selectedMonth, matrix, data.profissionais]);

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };
    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));
    const newGastos: GastoMensal[] = formData.gastos.map(g => ({ ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });
    setShowModal(false);
  };

  // Funções de Gerenciamento de Categorias
  const addCategory = () => {
    if (!newCatName || data.categoriasGastos.includes(newCatName)) return;
    setData({ ...data, categoriasGastos: [...data.categoriasGastos, newCatName] });
    setNewCatName('');
  };

  const removeCategory = (cat: string) => {
    if (confirm(`Ao excluir a categoria "${cat}", todos os gastos históricos registrados nela serão perdidos. Confirmar?`)) {
      setData({
        ...data,
        categoriasGastos: data.categoriasGastos.filter(c => c !== cat),
        gastos: data.gastos.filter(g => g.categoria !== cat)
      });
    }
  };

  const startEditCategory = (index: number, name: string) => {
    setEditingCatIndex(index);
    setTempCatName(name);
  };

  const saveEditedCategory = (oldName: string) => {
    if (!tempCatName || data.categoriasGastos.includes(tempCatName)) {
      setEditingCatIndex(null);
      return;
    }

    const newCategories = [...data.categoriasGastos];
    newCategories[editingCatIndex!] = tempCatName;

    // Sincroniza o histórico de gastos com o novo nome da categoria
    const newGastos = data.gastos.map(g => 
      g.categoria === oldName ? { ...g, categoria: tempCatName } : g
    );

    setData({
      ...data,
      categoriasGastos: newCategories,
      gastos: newGastos
    });

    setEditingCatIndex(null);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      {/* Planejamento Anual Card */}
      <div className="bg-slate-950 p-10 rounded-[48px] shadow-2xl flex flex-col md:flex-row justify-between items-center gap-8 border border-white/5 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full -mr-32 -mt-32 blur-[80px]"></div>
        <div className="flex items-center gap-5 z-10">
          <div className="p-4 bg-blue-600 rounded-3xl text-white shadow-xl shadow-blue-500/20 rotate-3">
            <Target size={28} />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tighter">Objetivo Estratégico {year}</h2>
            <p className="text-[10px] text-blue-400 font-bold uppercase mt-1 tracking-widest text-left">Faturamento anual esperado</p>
          </div>
        </div>
        <div className="w-full md:w-auto flex flex-col items-end z-10">
          <label className="text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Alvo Anual (R$)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-blue-500 font-black text-2xl">R$</span>
            <input 
              type="number" 
              value={currentParams.metaFaturamento} 
              onChange={(e) => handleUpdateMetaAnual(Number(e.target.value))}
              className="bg-white/5 border border-white/10 p-5 pl-14 rounded-[28px] text-white font-black text-3xl w-full md:w-72 focus:border-blue-500 outline-none transition-all"
            />
          </div>
        </div>
      </div>

      <div className="flex justify-between items-center px-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Fluxo de Caixa</h2>
          <p className="text-xs text-slate-400 font-bold uppercase mt-1 tracking-widest">Histórico de lançamentos mensais</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setShowCategoryModal(true)} className="bg-white text-slate-600 px-6 py-4 rounded-[24px] font-black text-xs uppercase shadow-sm border border-slate-100 flex items-center gap-2 hover:bg-slate-50 transition-all">
            <Settings2 size={18} /> Config. Categorias
          </button>
          <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-8 py-4 rounded-[24px] font-black text-xs uppercase shadow-xl shadow-blue-100 flex items-center gap-2 hover:scale-105 transition-all">
            <PlusCircle size={18} /> Novo Fechamento
          </button>
        </div>
      </div>

      {/* TABELA DE MESES */}
      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
            <tr>
              <th className="px-8 py-6">Mês</th>
              <th className="px-8 py-6 text-right">Faturamento</th>
              <th className="px-8 py-6 text-right">Saídas</th>
              <th className="px-8 py-6 text-right">Líquido</th>
              <th className="px-8 py-6 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {matrix.map((m) => (
              <tr key={m.nome} className="hover:bg-blue-50/20 transition-all group">
                <td className="px-8 py-6 font-black text-slate-800 text-base">{m.nome}</td>
                <td className="px-8 py-6 text-right font-bold text-slate-600">R$ {m.bruta.toLocaleString('pt-BR')}</td>
                <td className="px-8 py-6 text-right text-red-500 font-bold">R$ {(m.repasse + m.gastosTotal).toLocaleString('pt-BR')}</td>
                <td className={`px-8 py-6 text-right font-black text-base ${m.liquido >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                  R$ {m.liquido.toLocaleString('pt-BR')}
                </td>
                <td className="px-8 py-6 text-center">
                  <div className="flex justify-center gap-2">
                    <button onClick={() => { setSelectedMonth(m.mes); setShowDetailModal(true); }} className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl transition-all" title="Ver Detalhamento"><Eye size={16} /></button>
                    <button onClick={() => { setFormData(prev => ({ ...prev, mes: m.mes })); setShowModal(true); }} className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl transition-all" title="Editar"><Edit2 size={16} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* MODAL DE CATEGORIAS */}
      {showCategoryModal && (
        <div className="fixed inset-0 z-[200] bg-slate-900/70 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[48px] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-10 border-b border-slate-50 flex justify-between items-center bg-white">
              <div>
                <h3 className="text-2xl font-black text-slate-800">Categorias de Despesas</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase mt-1 tracking-widest">Gerencie os nomes dos custos operacionais</p>
              </div>
              <button onClick={() => setShowCategoryModal(false)} className="bg-slate-100 p-4 rounded-full text-slate-400 hover:bg-slate-200"><X /></button>
            </div>

            <div className="p-10 space-y-6">
              <div className="flex gap-2">
                <input 
                  type="text" 
                  placeholder="Nova categoria..." 
                  className="flex-1 p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none focus:border-blue-500"
                  value={newCatName}
                  onChange={(e) => setNewCatName(e.target.value)}
                />
                <button onClick={addCategory} className="bg-blue-600 text-white p-4 rounded-2xl shadow-lg"><Plus size={20} /></button>
              </div>

              <div className="space-y-3 max-h-64 overflow-y-auto pr-2 custom-scrollbar">
                {data.categoriasGastos.map((cat, idx) => (
                  <div key={idx} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                    {editingCatIndex === idx ? (
                      <input 
                        autoFocus
                        type="text" 
                        className="flex-1 bg-white border border-blue-200 p-2 rounded-xl font-bold text-sm outline-none"
                        value={tempCatName}
                        onChange={(e) => setTempCatName(e.target.value)}
                        onBlur={() => saveEditedCategory(cat)}
                        onKeyDown={(e) => e.key === 'Enter' && saveEditedCategory(cat)}
                      />
                    ) : (
                      <span className="font-bold text-slate-700 text-sm">{cat}</span>
                    )}

                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      {editingCatIndex === idx ? (
                        <button onClick={() => saveEditedCategory(cat)} className="p-2 text-emerald-500 hover:bg-emerald-50 rounded-xl"><Check size={16} /></button>
                      ) : (
                        <button onClick={() => startEditCategory(idx, cat)} className="p-2 text-blue-500 hover:bg-blue-50 rounded-xl"><Edit2 size={16} /></button>
                      )}
                      <button onClick={() => removeCategory(cat)} className="p-2 text-red-400 hover:bg-red-50 rounded-xl"><Trash2 size={16} /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* PAINEL DE FECHAMENTO DETALHADO POR PROFISSIONAL */}
      {showDetailModal && monthDashboard && (
        <div className="fixed inset-0 z-[150] bg-slate-950/80 backdrop-blur-xl flex items-center justify-center p-4">
          <div className="bg-slate-50 w-full max-w-7xl h-[95vh] rounded-[48px] shadow-2xl overflow-hidden flex flex-col animate-in zoom-in duration-300">
            <header className="p-10 bg-white border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-3xl font-black text-slate-800 tracking-tighter uppercase">Painel Detalhado • {monthDashboard.nome} / {year}</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Visão completa por barbeiro e balanço da casa</p>
              </div>
              <button onClick={() => setShowDetailModal(false)} className="bg-slate-100 p-5 rounded-full text-slate-400 hover:bg-slate-200"><X /></button>
            </header>

            <div className="flex-1 overflow-y-auto p-10 space-y-12 custom-scrollbar">
              {/* Resumo Consolidado */}
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <SummaryCard label="Produção Bruta (Serviços)" value={`R$ ${monthDashboard.totalProducaoBruta.toLocaleString('pt-BR')}`} icon={Scissors} color="text-slate-700" bg="bg-white" />
                <SummaryCard label="Comissões Pagas" value={`R$ ${monthDashboard.totalComissoesPagas.toLocaleString('pt-BR')}`} icon={Users} color="text-red-500" bg="bg-white" />
                <SummaryCard label="Assinaturas (Líquido Casa)" value={`R$ ${monthDashboard.liquidoAssinaturasCasa.toLocaleString('pt-BR')}`} icon={UserCheck} color="text-blue-600" bg="bg-blue-50" />
                <SummaryCard label="Saldo Barbearia (Serviços)" value={`R$ ${monthDashboard.totalSaldoBarbeariaServicos.toLocaleString('pt-BR')}`} icon={DollarSign} color="text-emerald-600" bg="bg-emerald-50/50" />
              </div>

              {/* Tabela de Detalhamento por Barbeiro Solicitada */}
              <div className="bg-white p-10 rounded-[56px] border border-slate-100 shadow-sm relative overflow-hidden">
                <div className="absolute top-0 right-0 w-96 h-96 bg-blue-50/50 rounded-full -mr-48 -mt-48 blur-3xl -z-10"></div>
                <div className="flex justify-between items-center mb-10">
                   <div>
                     <h4 className="text-2xl font-black text-slate-800 flex items-center gap-3"><BarChart2 size={28} className="text-blue-600" /> Performance & Divisão Financeira</h4>
                     <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Transparência nos ganhos e retenção por cadeira</p>
                   </div>
                   <div className="flex flex-col items-end gap-2">
                     <div className="flex items-center gap-2 px-6 py-3 bg-amber-50 rounded-2xl text-[10px] font-black text-amber-600 uppercase border border-amber-100">
                       <Trophy size={14} className="text-amber-500" /> Ranking Ativo (Excluindo Gabriel)
                     </div>
                     <span className="text-[9px] text-slate-300 font-bold uppercase">* Saldo Barbearia calculado apenas sobre produção</span>
                   </div>
                </div>

                <div className="overflow-x-auto">
                  <table className="w-full text-left">
