export default CashFlow;

import React, { useState, useEffect, useMemo } from 'react';
import { AppData, ProducaoMensal, ReceitasExtras, GastoMensal, ParametrosAnuais, Profissional } from '../types.ts';
import { PlusCircle, X, Save, Edit2, Eye, TrendingUp, UserCheck, Plus, ArrowDownRight, Scissors, Target, PieChart as PieChartIcon, Award, UserPlus, UserMinus, BarChart2, Wallet, Users, DollarSign, Star, Trophy, Sparkles, Settings2, Trash2, Check } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface CashFlowProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const CashFlow: React.FC<CashFlowProps> = ({ data, setData, year }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<number | null>(null);
  const [newCatName, setNewCatName] = useState('');
  const [editingCatIndex, setEditingCatIndex] = useState<number | null>(null);
  const [tempCatName, setTempCatName] = useState('');

  const currentParams = data.parametros.find(p => p.ano === year) || data.parametros[0] || { metaFaturamento: 0 };
  const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const [formData, setFormData] = useState({
    mes: 1,
    dinheiro: 0,
    cartao: 0,
    pix: 0,
    assinaturas: 0,
    pacotes: 0,
    novosAssinantes: 0,
    cancelamentosAssinantes: 0,
    producoes: data.profissionais.map(p => ({ id: p.id, nome: p.nome, bruta: 0, repasse: 0, assinatura: 0, vendasProdutos: 0, quantidadeAtendimentos: 0 })),
    gastos: data.categoriasGastos.map(cat => ({ categoria: cat, valor: 0 }))
  });

  const handleUpdateMetaAnual = (val: number) => {
    const updatedParams = data.parametros.map(p => 
      p.ano === year ? { ...p, metaFaturamento: val } : p
    );
    setData({ ...data, parametros: updatedParams });
  };

  useEffect(() => {
    if (showModal) {
      const extra = data.receitasExtras.find(r => r.ano === year && r.mes === formData.mes);
      const prods = data.profissionais.map(prof => {
        const p = data.producao.find(p => p.ano === year && p.mes === formData.mes && p.profissionalId === prof.id);
        return { 
          id: prof.id, nome: prof.nome, bruta: p?.producaoBruta || 0, repasse: p?.repasseProfissional || 0,
          assinatura: p?.repasseAssinatura || 0, vendasProdutos: p?.vendasProdutos || 0,
          quantidadeAtendimentos: p?.quantidadeAtendimentos || 0
        };
      });
      const gastos = data.categoriasGastos.map(cat => {
        const g = data.gastos.find(g => g.ano === year && g.mes === formData.mes && g.categoria === cat);
        return { categoria: cat, valor: g?.valor || 0 };
      });

      setFormData(prev => ({
        ...prev,
        dinheiro: extra?.dinheiro || 0, cartao: extra?.cartao || 0, pix: extra?.pix || 0,
        assinaturas: extra?.assinaturas || 0, pacotes: extra?.pacotes || 0,
        novosAssinantes: extra?.novosAssinantes || 0, cancelamentosAssinantes: extra?.cancelamentosAssinantes || 0,
        producoes: prods, gastos: gastos
      }));
    }
  }, [formData.mes, showModal, data.profissionais, data.categoriasGastos, data.receitasExtras, data.producao, data.gastos, year]);

  const matrix = useMemo(() => meses.map((nome, i) => {
    const mes = i + 1;
    const prod = data.producao.filter(p => p.ano === year && p.mes === mes);
    const extra = data.receitasExtras.find(r => r.ano === year && r.mes === mes);
    const gastosList = data.gastos.filter(g => g.ano === year && g.mes === mes);
    const gastosTotal = gastosList.reduce((s, c) => s + c.valor, 0);
    const bruta = prod.reduce((s, c) => s + c.producaoBruta, 0) + (extra?.dinheiro || 0) + (extra?.cartao || 0) + (extra?.pix || 0) + (extra?.assinaturas || 0) + (extra?.pacotes || 0);
    const repasse = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
    const liquido = bruta - repasse - gastosTotal;
    return { nome, mes, bruta, repasse, gastosTotal, liquido, extra, prod, gastosList };
  }), [data, year]);

  const monthDashboard = useMemo(() => {
    if (selectedMonth === null) return null;
    const m = matrix[selectedMonth - 1];
    const COLORS = ['#2563eb', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#64748b'];

    const profData = data.profissionais.map(prof => {
      const p = m.prod.find(p => p.profissionalId === prof.id);
      const totalProd = p?.producaoBruta || 0;
      const comissaoProducao = p?.repasseProfissional || 0;
      const recebidoAssinatura = p?.repasseAssinatura || 0;

      const totalRecebidoBarbeiro = comissaoProducao + recebidoAssinatura;
      // Saldo que fica para a barbearia é apenas da soma dos serviços prestados (Produção - Repasse)
      const saldoBarbeariaServico = totalProd - comissaoProducao;

      return { 
        id: prof.id,
        nome: prof.nome, 
        totalProd, 
        comissaoProducao, 
        recebidoAssinatura, 
        totalRecebidoBarbeiro, 
        saldoBarbeariaServico 
      };
    });

    const elegiveisDestaque = profData
      .filter(p => !p.nome.toLowerCase().includes('gabriel'))
      .sort((a, b) => b.totalProd - a.totalProd);

    const destaque = elegiveisDestaque[0];

    const profRanking = profData.map(p => ({
      ...p,
      isDestaque: destaque && p.id === destaque.id && p.totalProd > 0
    })).sort((a, b) => b.totalProd - a.totalProd);

    const totalProducaoBruta = profRanking.reduce((s, p) => s + p.totalProd, 0);
    const totalComissoesPagas = profRanking.reduce((s, p) => s + p.comissaoProducao, 0);
    const totalRepassesAssinatura = profRanking.reduce((s, p) => s + p.recebidoAssinatura, 0);

    // Valor que entrou das assinaturas (do painel de receitas extras)
    const totalAssinaturasEntrada = m.extra?.assinaturas || 0;

    // Saldo final da barbearia (Lucro do Serviço + Lucro da Assinatura)
    const totalSaldoBarbeariaFinal = (totalProducaoBruta - totalComissoesPagas) + (totalAssinaturasEntrada - totalRepassesAssinatura);

    const expenseData = m.gastosList.map(g => ({ name: g.categoria, value: g.valor })).filter(g => g.value > 0);

    return { 
      ...m, 
      expenseData, 
      COLORS, 
      profRanking, 
      destaque, 
      totalProducaoBruta, 
      totalComissoesPagas, 
      totalRepassesAssinatura, 
      totalAssinaturasEntrada,
      totalSaldoBarbeariaFinal
    };
  }, [selectedMonth, matrix, data.profissionais]);

  const handleSaveClosing = () => {
    const newExtra: ReceitasExtras = {
      ano: year, mes: formData.mes, dinheiro: formData.dinheiro, cartao: formData.cartao,
      pix: formData.pix, assinaturas: formData.assinaturas, pacotes: formData.pacotes,
      geladeira: 0, outras: 0, novosAssinantes: formData.novosAssinantes, cancelamentosAssinantes: formData.cancelamentosAssinantes
    };
    const newProducao: ProducaoMensal[] = formData.producoes.map(p => ({
      ano: year, mes: formData.mes, profissionalId: p.id, producaoBruta: p.bruta,
      repasseProfissional: p.repasse, repasseAssinatura: p.assinatura,
      recebidoPelaCasa: p.bruta - p.repasse - p.assinatura,
      vendasProdutos: p.vendasProdutos, quantidadeAtendimentos: p.quantidadeAtendimentos
    }));
    const newGastos: GastoMensal[] = formData.gastos.map(g => ({ ano: year, mes: formData.mes, categoria: g.categoria, valor: g.valor }));

    setData({
      ...data,
      receitasExtras: [...data.receitasExtras.filter(r => !(r.ano === year && r.mes === formData.mes)), newExtra],
      producao: [...data.producao.filter(p => !(p.ano === year && p.mes === formData.mes)), ...newProducao],
      gastos: [...data.gastos.filter(g => !(g.ano === year && g.mes === formData.mes)), ...newGastos]
    });
    setShowModal(false);
  };

  const addCategory = () => {
    if (!newCatName || data.categoriasGastos.includes(newCatName)) return;
    setData({ ...data, categoriasGastos: [...data.categoriasGastos, newCatName] });
    setNewCatName('');
  };

  const removeCategory = (cat: string) => {
    if (confirm(`Ao excluir a categoria "${cat}", todos os gastos históricos registrados nela serão perdidos. Confirmar?`)) {
      setData({
        ...data,
        categoriasGastos: data.categoriasGastos.filter(c => c !== cat),
