                <SummaryCard label="Produção bruta (prestação de serviços)" value={`R$ ${monthDashboard.totalProducaoBruta.toLocaleString('pt-BR')}`} icon={Scissors} color="text-slate-700" bg="bg-white" sub="Geração de Valor" />
                <SummaryCard label="Comissões pagas" value={`R$ ${monthDashboard.totalComissoesPagas.toLocaleString('pt-BR')}`} icon={Users} color="text-red-500" bg="bg-white" sub="Repasse sobre serviços" />
                <SummaryCard label="Valor que entrou das assinaturas" value={`R$ ${monthDashboard.totalAssinaturasEntrada.toLocaleString('pt-BR')}`} icon={UserCheck} color="text-blue-600" bg="bg-blue-50/50" sub="Faturamento Clube" />
                <SummaryCard label="Valor pago assinatura (profissionais)" value={`R$ ${monthDashboard.totalRepassesAssinatura.toLocaleString('pt-BR')}`} icon={Wallet} color="text-orange-500" bg="bg-white" sub="Repasse fixo clube" />
                <SummaryCard label="Saldo para a barbearia" value={`R$ ${monthDashboard.totalSaldoBarbeariaFinal.toLocaleString('pt-BR')}`} icon={DollarSign} color="text-emerald-600" bg="bg-emerald-50" sub="Lucro Total Acumulado" />
              </div>

              <div className="bg-white p-10 rounded-[56px] border border-slate-100 shadow-sm relative overflow-hidden">
                <div className="absolute top-0 right-0 w-96 h-96 bg-blue-50/50 rounded-full -mr-48 -mt-48 blur-3xl -z-10"></div>
                <div className="flex justify-between items-center mb-10">
                   <div>
                     <h4 className="text-2xl font-black text-slate-800 flex items-center gap-3"><BarChart2 size={28} className="text-blue-600" /> Performance & Ganhos por Profissional</h4>
