                      <input type="number" value={g.valor === 0 ? '' : g.valor} onChange={(e) => { let n = [...formData.gastos]; n[idx].valor = Number(e.target.value); setFormData({...formData, gastos: n}); }} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-[20px] text-sm font-bold focus:border-rose-400 outline-none" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-blue-600"><Scissors size={22} /> Produção & Métricas Individuais</h4>
                <div className="space-y-6">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-8 bg-slate-50 rounded-[40px] border border-slate-100">
                      <div className="flex justify-between items-center mb-6">
                        <span className="text-sm font-black text-slate-800 uppercase tracking-tighter">{p.nome}</span>
                      </div>
                      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                        <MiniInput label="Prod. Bruta" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse Serv." value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Repasse Assin." value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Atendimentos" value={p.quantidadeAtendimentos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].quantidadeAtendimentos = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Venda Prod." value={p.vendasProdutos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].vendasProdutos = v; setFormData({...formData, producoes: n}); }} />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
            <div className="p-10 bg-slate-50 border-t border-slate-100">
              <button onClick={handleSaveClosing} className="w-full bg-blue-600 text-white py-6 rounded-[28px] font-black text-sm uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3 hover:bg-blue-700 transition-all active:scale-95">
                <Save size={20} /> FINALIZAR E SINCRONIZAR DADOS
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

