                      <h4 className="text-2xl font-black text-slate-800 flex items-center gap-3"><TrendingUp size={28} className="text-emerald-500" /> Ranking de Entradas</h4>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Fontes de receita por performance</p>
