                <Input label="Total Assinaturas (R$)" value={formData.assinaturas} onChange={(v: number) => setFormData({...formData, assinaturas: v})} />
                <Input label="Novos Assinantes" value={formData.novosAssinantes} onChange={(v: number) => setFormData({...formData, novosAssinantes: v})} />
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-rose-500"><ArrowDownRight size={22} /> Despesas Reais do Mês</h4>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                  {formData.gastos.map((g, idx) => (
                    <div key={g.categoria}>
                      <label className="text-[9px] font-black text-slate-400 uppercase block mb-2 ml-2">{g.categoria}</label>
                      <input type="number" value={g.valor === 0 ? '' : g.valor} onChange={(e) => { let n = [...formData.gastos]; n[idx].valor = Number(e.target.value); setFormData({...formData, gastos: n}); }} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-[20px] text-sm font-bold focus:border-rose-400 outline-none" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3 text-blue-600"><Scissors size={22} /> Produção & Métricas Individuais</h4>
                <div className="space-y-8">
                  {formData.producoes.map((p, idx) => (
                    <div key={p.id} className="p-8 bg-slate-50 rounded-[40px] border border-slate-100">
                      <div className="flex justify-between items-center mb-6">
                        <span className="text-sm font-black text-slate-800 uppercase tracking-tighter">{p.nome}</span>
                      </div>
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <MiniInput label="Prod. Serviços" value={p.bruta} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].bruta = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Comissão Serviços" value={p.repasse} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].repasse = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Comissão Assinaturas" value={p.assinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].assinatura = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Atendimentos Serviços" value={p.quantidadeAtendimentos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].quantidadeAtendimentos = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Atendimentos Assinatura" value={p.atendimentosAssinatura} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].atendimentosAssinatura = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Vendas Bruta (Prod.)" value={p.vendasProdutos} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].vendasProdutos = v; setFormData({...formData, producoes: n}); }} />
                        <MiniInput label="Comissão Vendas" value={p.vendasProdutosComissao} onChange={(v: number) => { let n = [...formData.producoes]; n[idx].vendasProdutosComissao = v; setFormData({...formData, producoes: n}); }} />
