export default Subscriptions;

import React, { useState, useMemo } from 'react';
import { AppData, Profissional, ProfissionalPerfil } from '../types.ts';
import { Plus, Trash2, X, Edit3, Scissors, UserPlus, Save, Target, Info, UserMinus, UserCheck } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, setData, year }) => {
  const [modalMode, setModalMode] = useState<'add' | 'edit' | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formProf, setFormProf] = useState({ 
    nome: '', 
    cadeira: 1, 
    comissao: 50,
    metaMensal: 5000,
    ativo: true 
  });

  const [formPerfil, setFormPerfil] = useState<ProfissionalPerfil>({
    experiencia: '',
    perfilComportamental: '',
    especialidade: '',
    objetivo: ''
  });

  const { ativos, inativos } = useMemo(() => {
    const list = data.profissionais.map(prof => {
      const records = data.producao.filter(p => p.profissionalId === prof.id && p.ano === year);
      const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
      return { ...prof, totalProd };
    });

    return {
      ativos: list.filter(p => p.ativo).sort((a, b) => b.totalProd - a.totalProd),
      inativos: list.filter(p => !p.ativo).sort((a, b) => b.totalProd - a.totalProd)
    };
  }, [data.profissionais, data.producao, year]);

  const openAdd = () => {
    setModalMode('add');
    setEditingId(null);
    setFormProf({ nome: '', cadeira: 1, comissao: 50, metaMensal: 5000, ativo: true });
    setFormPerfil({ experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const openEdit = (prof: Profissional) => {
    setModalMode('edit');
    setEditingId(prof.id);
    setFormProf({ 
      nome: prof.nome, 
      cadeira: prof.cadeira, 
      comissao: prof.comissao || 50,
      metaMensal: prof.metaMensal || 5000,
      ativo: prof.ativo 
    });
    setFormPerfil(prof.perfil || { experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const handleSave = () => {
    if (!formProf.nome) return;

    if (modalMode === 'add') {
      const nProf: Profissional = {
        id: Math.random().toString(36).substr(2, 9),
        ...formProf,
        perfil: formPerfil
      };
      setData({ ...data, profissionais: [...data.profissionais, nProf] });
    } else if (modalMode === 'edit' && editingId) {
      const updatedList = data.profissionais.map(p => 
        p.id === editingId ? { ...p, ...formProf, perfil: formPerfil } : p
      );
      setData({ ...data, profissionais: updatedList });
    }
    setModalMode(null);
  };

  const toggleStatus = (id: string, currentStatus: boolean) => {
    const action = currentStatus ? 'desativar' : 'ativar';
    if (confirm(`Deseja ${action} este barbeiro? Os dados históricos serão preservados.`)) {
      const updatedList = data.profissionais.map(p => 
        p.id === id ? { ...p, ativo: !currentStatus } : p
      );
      setData({ ...data, profissionais: updatedList });
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-32">
      <header className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Equipe & Performance</h2>
          <p className="text-sm text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de barbeiros e metas</p>
        </div>
        <button onClick={openAdd} className="bg-blue-600 text-white flex items-center gap-2 px-6 py-4 rounded-[24px] shadow-xl shadow-blue-100 font-black text-xs uppercase tracking-widest hover:scale-105 transition-all">
          <UserPlus size={18} /> Novo Barbeiro
        </button>
      </header>

      <div className="bg-amber-50 border border-amber-100 p-4 rounded-2xl flex items-start gap-3">
        <Info className="text-amber-500 mt-1 shrink-0" size={18} />
        <p className="text-xs font-bold text-amber-700 leading-relaxed uppercase">
          Gestão de Ativos: Barbeiros inativos não aparecem nos lançamentos mensais, mas seus dados históricos permanecem salvos para consultas e fechamentos.
        </p>
      </div>

      <div className="space-y-12">
        {/* Ativos */}
        <section>
          <h3 className="text-lg font-black text-slate-700 uppercase tracking-widest mb-6 flex items-center gap-2">
            <UserCheck size={20} className="text-emerald-500" /> Barbeiros Ativos
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {ativos.map((prof, idx) => (
              <ProfCard 
                key={prof.id} 
                prof={prof} 
                idx={idx} 
                onEdit={() => openEdit(prof)} 
                onToggleStatus={() => toggleStatus(prof.id, true)}
              />
            ))}
            {ativos.length === 0 && (
              <div className="col-span-full py-12 text-center border-2 border-dashed border-slate-200 rounded-[40px] text-slate-400 font-bold uppercase text-xs">
                Nenhum barbeiro ativo cadastrado.
              </div>
            )}
          </div>
        </section>

        {/* Inativos */}
        {inativos.length > 0 && (
          <section className="opacity-60 grayscale hover:grayscale-0 transition-all">
            <h3 className="text-lg font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center gap-2">
              <UserMinus size={20} /> Ex-Colaboradores (Inativos)
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {inativos.map((prof, idx) => (
                <ProfCard 
                  key={prof.id} 
                  prof={prof} 
                  idx={idx} 
                  inactive
                  onEdit={() => openEdit(prof)} 
                  onToggleStatus={() => toggleStatus(prof.id, false)}
                />
              ))}
            </div>
          </section>
        )}
      </div>

      {modalMode && (
        <div className="fixed inset-0 z-[120] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[48px] p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h3 className="text-2xl font-black text-slate-800">{modalMode === 'add' ? 'Adicionar' : 'Editar'} Barbeiro</h3>
                <p className="text-xs text-slate-400 font-bold uppercase mt-1">Metas & Cadastro</p>
              </div>
              <button onClick={() => setModalMode(null)} className="p-3 bg-slate-100 text-slate-400 rounded-full"><X /></button>
            </div>

            <div className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">Nome Completo</label>
                  <input type="text" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-700" value={formProf.nome} onChange={(e) => setFormProf({...formProf, nome: e.target.value})} />
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">Cadeira</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" value={formProf.cadeira} onChange={(e) => setFormProf({...formProf, cadeira: Number(e.target.value)})} />
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-2 block">% Comissão</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" value={formProf.comissao} onChange={(e) => setFormProf({...formProf, comissao: Number(e.target.value)})} />
                </div>

                <div className="col-span-2 bg-blue-50 p-6 rounded-[32px] border border-blue-100 mt-2">
                  <label className="text-[10px] font-black text-blue-400 uppercase ml-2 mb-2 block flex items-center gap-2">
                    <Target size={14} /> Meta de Produção Mensal (R$)
                  </label>
                  <input type="number" className="w-full p-4 bg-white border border-blue-200 rounded-2xl font-black text-blue-700 text-xl" value={formProf.metaMensal} onChange={(e) => setFormProf({...formProf, metaMensal: Number(e.target.value)})} />
                </div>
              </div>

              <div className="pt-4">
                <button onClick={handleSave} className="w-full bg-blue-600 text-white py-5 rounded-3xl font-black text-sm uppercase shadow-lg flex items-center justify-center gap-2">
                  <Save size={18} /> {modalMode === 'add' ? 'CADASTRAR' : 'SALVAR ALTERAÇÕES'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const ProfCard = ({ prof, idx, inactive, onEdit, onToggleStatus }: any) => (
  <div className="bg-white rounded-[40px] p-8 border border-slate-50 shadow-sm relative overflow-hidden group hover:border-blue-200 transition-all border-b-4 border-b-transparent hover:border-b-blue-500">
    <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
      <button onClick={onEdit} className="p-2 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-100" title="Editar"><Edit3 size={16} /></button>
      <button 
        onClick={onToggleStatus} 
        className={`p-2 rounded-xl ${inactive ? 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100' : 'bg-orange-50 text-orange-600 hover:bg-orange-100'}`}
        title={inactive ? "Ativar" : "Desativar"}
      >
        {inactive ? <UserCheck size={16} /> : <UserMinus size={16} />}
      </button>
    </div>

    <div className="flex items-center gap-4 mb-6">
      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-white shadow-lg ${
        inactive ? 'bg-slate-400' : (idx === 0 ? 'bg-amber-400 rotate-3' : idx === 1 ? 'bg-slate-400' : 'bg-slate-800')
      }`}>
        {idx + 1}º
      </div>
      <div>
        <h3 className="font-black text-slate-800 text-lg leading-tight">{prof.nome}</h3>
        {!inactive && (
          <p className="text-[10px] font-black text-slate-400 uppercase mt-1">Meta: R$ {(prof.metaMensal || 5000).toLocaleString('pt-BR')}</p>
        )}
        {inactive && (
          <p className="text-[10px] font-black text-rose-400 uppercase mt-1">Status: Inativo</p>
        )}
      </div>
    </div>

    <div className="space-y-4">
      <div className={`p-5 rounded-[32px] border transition-colors ${inactive ? 'bg-slate-50 border-slate-100' : 'bg-slate-50 border-slate-100 group-hover:bg-blue-50/50'}`}>
        <p className="text-[10px] font-black text-slate-400 uppercase mb-1 flex items-center gap-2">
           <Scissors size={12} className="text-blue-500" /> Produção Bruta Ano
        </p>
        <p className="text-2xl font-black text-slate-800">R$ {(prof.totalProd || 0).toLocaleString('pt-BR')}</p>
      </div>
    </div>
  </div>
);

export default Professionals;

import React, { useState, useMemo } from 'react';
import { AppData, MeetingNote } from '../types.ts';
import { GoogleGenAI } from "@google/genai";
import { MessageSquare, Plus, BrainCircuit, Trash2, Calendar, Sparkles, UserCircle, ShoppingCart, TrendingUp, Scissors, Target, UserCheck, DollarSign, Wallet, ShoppingBag, BarChart2, ListChecks, History } from 'lucide-react';

interface MeetingsProps {
  data: AppData;
  setData: (data: AppData) => void;
}

const Meetings: React.FC<MeetingsProps> = ({ data, setData }) => {
  const [selectedProfId, setSelectedProfId] = useState(data.profissionais[0]?.id || '');
  const [newNote, setNewNote] = useState('');
  const [weeklyNote, setWeeklyNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiScript, setAiScript] = useState('');

  const selectedProf = data.profissionais.find(p => p.id === selectedProfId);
  const notes = data.meetingNotes?.filter(n => n.profissionalId === selectedProfId) || [];

  const performance = useMemo(() => {
    if (!selectedProfId) return null;

    const anoAtual = new Date().getFullYear();
    const producaoProf = data.producao.filter(p => p.profissionalId === selectedProfId && p.ano === anoAtual);
    const ultimoMes = producaoProf.length > 0 ? Math.max(...producaoProf.map(p => p.mes)) : 0;
    const d = producaoProf.find(p => p.mes === ultimoMes);

    if (!d) return null;

    const atendimentosServico = d.quantidadeAtendimentos || 0;
    const atendimentosAssinatura = d.atendimentosAssinatura || 0;

    const vendasProdutosBruto = d.vendasProdutos || 0;
    const comissaoVendas = d.vendasProdutosComissao || 0;

    const producaoServicosBruta = d.producaoBruta || 0;
    const comissaoServicos = d.repasseProfissional || 0;
    const comissaoAssinaturas = d.repasseAssinatura || 0;

    const recebidoTotais = comissaoServicos + comissaoAssinaturas + comissaoVendas;

    // Ticket Médio solicitado: Apenas produção de serviços / atendimentos de serviços
    const ticketMedio = atendimentosServico > 0 ? producaoServicosBruta / atendimentosServico : 0;

    const meta = selectedProf?.metaMensal || 5000;
    const progressoMeta = Math.min((producaoServicosBruta / meta) * 100, 100);

    return {
      mes: ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'][ultimoMes - 1],
      atendimentosServico,
      atendimentosAssinatura,
      vendasProdutosBruto,
      comissaoVendas,
      producaoServicosBruta,
      comissaoServicos,
      comissaoAssinaturas,
      recebidoTotais,
      ticketMedio,
      meta,
      progressoMeta,
      porcentagemReal: (producaoServicosBruta / meta) * 100
    };
  }, [data, selectedProfId, selectedProf]);

  const handleAddNote = (text: string, isWeekly: boolean = false) => {
    if (!text) return;
    const note: MeetingNote = {
      id: Math.random().toString(36).substr(2, 9),
      profissionalId: selectedProfId,
      data: new Date().toISOString(),
      texto: isWeekly ? `[ANÁLISE DA SEMANA] ${text}` : text
    };
    setData({ ...data, meetingNotes: [...(data.meetingNotes || []), note] });
    if (isWeekly) setWeeklyNote(''); else setNewNote('');
  };

  const handleDeleteNote = (id: string) => {
    if (confirm("Deseja remover esta nota de reunião?")) {
      setData({ ...data, meetingNotes: data.meetingNotes.filter(n => n.id !== id) });
    }
  };

  const handleGenerateScript = async () => {
    setIsGenerating(true);
    setAiScript('');
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      Atue como um gestor de barbearia de elite. Analise o desempenho do barbeiro ${selectedProf?.nome} 
      neste mês de ${performance?.mes}:
      - Produção de Serviços: R$ ${performance?.producaoServicosBruta}
      - Ticket Médio de Serviços (Produção / ${performance?.atendimentosServico} atendimentos): R$ ${performance?.ticketMedio.toFixed(2)}
      - Venda de Produtos: R$ ${performance?.vendasProdutosBruto}
      - Comissão Total Recebida: R$ ${performance?.recebidoTotais}

      Gere um roteiro de feedback motivador focado em aumentar a recorrência e o ticket médio de produtos.
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiScript(response.text || "Erro ao processar feedback.");
    } catch (error) {
      console.error("Erro na geração de feedback:", error);
      setAiScript("Erro na conexão com a IA.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-32">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Pauta de Reunião</h2>
        <p className="text-sm text-slate-400 font-bold uppercase mt-1">Análise estratégica individualizada</p>
      </header>

      <div className="flex gap-3 overflow-x-auto pb-4 custom-scrollbar">
        {data.profissionais.filter(p => p.ativo).map(p => (
          <button
            key={p.id}
            onClick={() => { setSelectedProfId(p.id); setAiScript(''); }}
            className={`px-8 py-4 rounded-[24px] text-xs font-black whitespace-nowrap transition-all border ${
              selectedProfId === p.id 
              ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100' 
              : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200'
            }`}
          >
            {p.nome}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
                  <BarChart2 size={24} className="text-blue-600" /> Resultados de {performance?.mes || 'Mês Atual'}
                </h3>
              </div>
            </div>

            {performance ? (
              <div className="space-y-8">
                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <div className="flex justify-between items-end mb-4">
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Atingimento da Meta de Serviços</p>
                      <h4 className="text-3xl font-black text-slate-800">R$ {(performance.producaoServicosBruta || 0).toLocaleString('pt-BR')}</h4>
                    </div>
                    <div className="text-right">
                      <span className={`text-xl font-black ${performance.porcentagemReal >= 100 ? 'text-emerald-500' : 'text-blue-600'}`}>
                        {Math.round(performance.porcentagemReal || 0)}%
                      </span>
                    </div>
                  </div>
                  <div className="w-full h-4 bg-slate-200 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ${performance.porcentagemReal >= 100 ? 'bg-emerald-500' : 'bg-blue-600'}`}
                      style={{ width: `${performance.progressoMeta}%` }}
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  <PerformanceMetric label="Atendimentos (Serviço)" value={performance.atendimentosServico || 0} icon={Scissors} color="text-slate-600" />
                  <PerformanceMetric label="Atend. Assinatura" value={performance.atendimentosAssinatura || 0} icon={UserCheck} color="text-emerald-600" />
                  <PerformanceMetric label="Vendas Bruto (Produtos)" value={`R$ ${(performance.vendasProdutosBruto || 0).toLocaleString('pt-BR')}`} icon={ShoppingCart} color="text-purple-600" />
                  <PerformanceMetric label="Comissão de Vendas" value={`R$ ${(performance.comissaoVendas || 0).toLocaleString('pt-BR')}`} icon={ShoppingBag} color="text-purple-400" />
                  <PerformanceMetric label="Produção Serviços" value={`R$ ${(performance.producaoServicosBruta || 0).toLocaleString('pt-BR')}`} icon={Target} color="text-blue-600" />
                  <PerformanceMetric label="Comissão Serviços" value={`R$ ${(performance.comissaoServicos || 0).toLocaleString('pt-BR')}`} icon={Wallet} color="text-blue-400" />
                  <PerformanceMetric label="Comissão Assinatura" value={`R$ ${(performance.comissaoAssinaturas || 0).toLocaleString('pt-BR')}`} icon={UserCheck} color="text-emerald-400" />
                  <PerformanceMetric label="Recebido Total" value={`R$ ${(performance.recebidoTotais || 0).toLocaleString('pt-BR')}`} icon={DollarSign} color="text-slate-900" isTotal />
                </div>

                <div className="p-6 bg-blue-50/50 rounded-3xl border border-blue-100 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-white rounded-2xl text-blue-600 shadow-sm"><TrendingUp size={20} /></div>
                    <div>
                        <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest leading-tight">Ticket Médio de Serviços</p>
                        <p className="text-[8px] text-slate-400 uppercase font-bold">(Exclui Assinaturas)</p>
                    </div>
                  </div>
                  <p className="text-2xl font-black text-blue-700">R$ {(performance.ticketMedio || 0).toFixed(2)}</p>
                </div>
              </div>
            ) : (
              <div className="py-20 text-center text-slate-400 font-bold uppercase text-xs">Sem dados para este profissional.</div>
            )}
          </div>

          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <h3 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2">
              <History size={20} className="text-blue-600" /> Histórico de Feedbacks
            </h3>
            <div className="space-y-4">
              {notes.length > 0 ? notes.sort((a,b) => new Date(b.data).getTime() - new Date(a.data).getTime()).map(note => (
                <div key={note.id} className={`p-6 rounded-[32px] border border-slate-100 group relative ${note.texto.includes('[ANÁLISE DA SEMANA]') ? 'bg-blue-50/30 border-blue-100' : 'bg-slate-50'}`}>
                  <button onClick={() => handleDeleteNote(note.id)} className="absolute top-4 right-4 p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100"><Trash2 size={14} /></button>
                  <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase mb-2">
                    <Calendar size={10} /> {new Date(note.data).toLocaleDateString('pt-BR')} 
                    {note.texto.includes('[ANÁLISE DA SEMANA]') && <span className="ml-2 px-2 py-0.5 bg-blue-100 text-blue-600 rounded-md">Nota Semanal</span>}
                  </div>
                  <p className="text-sm font-medium text-slate-600 leading-relaxed">
                    {note.texto.replace('[ANÁLISE DA SEMANA] ', '')}
                  </p>
                </div>
              )) : <p className="text-center py-8 text-slate-400 text-xs uppercase font-bold tracking-widest">Aguardando novo registro.</p>}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          {/* Seção Nova: Notas da Semana */}
          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <div className="flex items-center gap-3 mb-6">
              <div className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl"><ListChecks size={20} /></div>
              <div>
                <h3 className="text-lg font-black text-slate-800 leading-tight">Notas da Semana</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase">Acompanhamento Semanal</p>
              </div>
            </div>
            <textarea 
              className="w-full bg-slate-50 border border-slate-100 rounded-[28px] p-6 text-sm font-medium outline-none min-h-[140px] focus:border-emerald-200 transition-colors" 
              placeholder="Como foi a semana do barbeiro? Pontos positivos, comportamento, técnica..." 
              value={weeklyNote} 
              onChange={(e) => setWeeklyNote(e.target.value)} 
            />
            <button 
              onClick={() => handleAddNote(weeklyNote, true)} 
              disabled={!weeklyNote} 
              className="w-full mt-4 bg-emerald-600 text-white py-5 rounded-[24px] font-black text-xs uppercase shadow-lg shadow-emerald-100 disabled:opacity-50 transition-all active:scale-95"
            >
              SALVAR NOTA DA SEMANA
            </button>
          </div>

          <div className="bg-slate-900 p-8 rounded-[48px] shadow-2xl relative overflow-hidden">
            <div className="flex items-center gap-3 mb-8">
              <div className="p-3 bg-blue-600 rounded-2xl text-white shadow-lg"><BrainCircuit size={24} /></div>
              <div>
                <h3 className="font-black text-white text-lg leading-tight">Gestor IA</h3>
                <p className="text-[10px] text-blue-400 font-bold uppercase">Feedback Técnico</p>
              </div>
            </div>
            <button onClick={handleGenerateScript} disabled={isGenerating || !performance} className="w-full py-5 rounded-[28px] font-black text-sm uppercase flex items-center justify-center gap-3 bg-white text-slate-900 hover:bg-blue-50 transition-all active:scale-95 disabled:opacity-50">
              {isGenerating ? 'ANALISANDO...' : <><Sparkles size={18} className="text-blue-500" /> GERAR ROTEIRO</>}
            </button>
            {aiScript && <div className="mt-8 p-6 bg-white/5 rounded-[32px] border border-white/10 animate-in fade-in zoom-in duration-500 max-h-60 overflow-y-auto custom-scrollbar"><p className="text-xs text-slate-300 font-medium leading-relaxed">{aiScript}</p></div>}
          </div>

          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <h3 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2"><MessageSquare size={20} className="text-blue-600" /> Registro de Reunião</h3>
            <textarea className="w-full bg-slate-50 border border-slate-100 rounded-[28px] p-6 text-sm font-medium outline-none min-h-[120px]" placeholder="Outras notas da conversa ou feedbacks gerais..." value={newNote} onChange={(e) => setNewNote(e.target.value)} />
            <button onClick={() => handleAddNote(newNote)} disabled={!newNote} className="w-full mt-4 bg-blue-600 text-white py-5 rounded-[24px] font-black text-xs uppercase shadow-lg disabled:opacity-50">SALVAR NOTA GERAL</button>
          </div>
        </div>
      </div>
    </div>
  );
};

const PerformanceMetric = ({ label, value, icon: Icon, color, isTotal }: any) => (
  <div className={`p-5 ${isTotal ? 'bg-slate-900 text-white border-slate-800' : 'bg-slate-50/50 border-slate-100 text-slate-800'} rounded-3xl border flex flex-col items-center text-center shadow-sm`}>
    <div className={`mb-2 ${isTotal ? 'text-blue-400' : color}`}>
      <Icon size={18} />
    </div>
    <p className={`text-[8px] font-black uppercase mb-1 ${isTotal ? 'text-slate-400' : 'text-slate-400'}`}>{label}</p>
    <p className={`text-xs font-black ${isTotal ? 'text-white' : ''}`}>{value}</p>
  </div>
);

export default Meetings;

import React, { useState, useRef, useMemo } from 'react';
import { AppData, ParametrosAnuais } from '../types.ts';
import { CalendarPlus, Save, Trash2, Download, Upload, ShieldCheck, Plus, X, CheckCircle2, ArrowRightLeft, TrendingUp, TrendingDown, Database, ClipboardList, RefreshCw } from 'lucide-react';

interface ConfigProps {
  data: AppData;
  setData: (data: AppData) => void;
  selectedYear: number;
  setSelectedYear: (year: number) => void;
}

const Config: React.FC<ConfigProps> = ({ data, setData, selectedYear, setSelectedYear }) => {
  const [showNewYearModal, setShowNewYearModal] = useState(false);
  const [compareYearA, setCompareYearA] = useState<number>(data.parametros[0]?.ano || 2024);
  const [compareYearB, setCompareYearB] = useState<number>(data.parametros[1]?.ano || data.parametros[0]?.ano || 2024);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [newYearForm, setNewYearForm] = useState<ParametrosAnuais>({
    ano: new Date().getFullYear() + 1,
    metaFaturamento: 250000,
    metaLucro: 120000,
    metaAssinaturas: 36000,
    metaGeladeira: 12000,
    metaGastos: 100000,
    metaPorCadeira: 5000
  });

  const yearsWithData = useMemo(() => {
    const years = new Set<number>();
    data.producao.forEach(p => years.add(p.ano));
    data.gastos.forEach(g => years.add(g.ano));
    data.receitasExtras.forEach(r => years.add(r.ano));
    return years;
  }, [data]);

  const exportBackup = () => {
    const dataStr = JSON.stringify(data, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', `backup_barber_bi_${new Date().toISOString().split('T')[0]}.json`);
    linkElement.click();
  };

  const importBackup = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        if (json.profissionais && confirm('Substituir dados atuais pelo backup?')) {
          setData(json);
        }
      } catch (err) { alert('Erro ao ler arquivo.'); }
    };
    reader.readAsText(file);
  };

  const handleCreateNewYear = () => {
    if (data.parametros.some(p => p.ano === newYearForm.ano)) {
      alert('Ano já existente!');
      return;
    }

    // Garantia de dados zerados para o novo ano: 
    // Como os dados de produção/gastos já são armazenados com o campo 'ano', 
    // criar o novo parâmetro é suficiente, pois as listas de dados do novo ano estarão vazias inicialmente.

    setData({ ...data, parametros: [...data.parametros, newYearForm] });
    setSelectedYear(newYearForm.ano);
    setShowNewYearModal(false);
  };

  const handleRemoveYear = (ano: number) => {
    if (data.parametros.length <= 1) return;
    if (confirm(`Excluir as configurações de ${ano}? Todas as produções e gastos deste ano serão mantidos mas o ciclo parametrizado será removido.`)) {
      setData({ ...data, parametros: data.parametros.filter(p => p.ano !== ano) });
      if (selectedYear === ano) setSelectedYear(data.parametros[0].ano);
    }
  };

  const comparisonResults = useMemo(() => {
    const getYearStats = (yr: number) => {
      const prod = data.producao.filter(p => p.ano === yr);
      const extra = data.receitasExtras.filter(r => r.ano === yr);
      const gastos = data.gastos.filter(g => g.ano === yr);

      const faturamento = prod.reduce((s, c) => s + c.producaoBruta, 0) +
        extra.reduce((s, r) => s + r.dinheiro + r.cartao + r.pix + r.assinaturas + r.pacotes, 0);

      const repasses = prod.reduce((s, c) => s + c.repasseProfissional + c.repasseAssinatura, 0);
      const gastosOperacionais = gastos.reduce((s, g) => s + g.valor, 0);
      const saidas = repasses + gastosOperacionais;
      const lucro = faturamento - saidas;
      const assinaturas = extra.reduce((s, r) => s + r.assinaturas, 0);

      return { faturamento, saidas, lucro, assinaturas };
    };

    const statsA = getYearStats(compareYearA);
    const statsB = getYearStats(compareYearB);

    const calcDiff = (valA: number, valB: number) => {
      const diff = valB - valA;
      const pct = valA !== 0 ? (diff / valA) * 100 : 0;
      return { diff, pct };
    };

    return {
      statsA,
      statsB,
      faturamento: calcDiff(statsA.faturamento, statsB.faturamento),
      saidas: calcDiff(statsA.saidas, statsB.saidas),
      lucro: calcDiff(statsA.lucro, statsB.lucro),
      assinaturas: calcDiff(statsA.assinaturas, statsB.assinaturas),
    };
  }, [data, compareYearA, compareYearB]);

  return (
    <div className="space-y-10 animate-in slide-in-from-right-4 duration-500 pb-32">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Ajustes do Sistema</h2>
        <p className="text-sm text-slate-400 font-bold uppercase">Gestão de dados e planejamento temporal</p>
      </header>

      <section className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
        <div className="flex justify-between items-center mb-8">
          <div>
            <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
              <CalendarPlus size={22} className="text-blue-600" /> Ciclos de Gestão
            </h3>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Cada novo ano inicia com produção zerada automaticamente</p>
          </div>
          <button onClick={() => setShowNewYearModal(true)} className="bg-blue-600 text-white p-4 rounded-2xl shadow-xl shadow-blue-100 hover:scale-105 transition-all">
            <Plus size={20} />
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {data.parametros.sort((a,b) => b.ano - a.ano).map(p => {
            const hasData = yearsWithData.has(p.ano);
            const isSelected = selectedYear === p.ano;

            return (
              <div 
                key={p.ano} 
                className={`p-8 rounded-[40px] border transition-all relative overflow-hidden group ${
                  isSelected 
                  ? 'bg-blue-600 border-blue-600 shadow-2xl shadow-blue-100 text-white' 
                  : 'bg-white border-slate-100 hover:border-blue-200'
                }`}
              >
                <div className="flex justify-between items-start mb-6">
                  <div className="space-y-1">
                    <span className={`text-4xl font-black ${isSelected ? 'text-white' : 'text-slate-800'}`}>{p.ano}</span>
                    <div className="flex items-center gap-2">
                      {isSelected ? (
                        <div className="flex items-center gap-1 px-2 py-1 bg-white/20 rounded-lg text-[9px] font-black uppercase">
                          <CheckCircle2 size={10} /> Logado
                        </div>
                      ) : (
                        <div className="flex items-center gap-1 px-2 py-1 bg-slate-100 rounded-lg text-[9px] font-black uppercase text-slate-400">
                          Sessão Fechada
                        </div>
                      )}

                      {hasData && (
                        <div className={`flex items-center gap-1 px-2 py-1 rounded-lg text-[9px] font-black uppercase ${isSelected ? 'bg-emerald-400 text-emerald-900' : 'bg-emerald-50 text-emerald-600'}`}>
                          <Database size={10} /> Com Dados
                        </div>
                      )}
                    </div>
                  </div>

                  {hasData && !isSelected && (
                    <div className="p-3 bg-emerald-50 text-emerald-500 rounded-2xl">
                      <ClipboardList size={20} />
                    </div>
                  )}
                </div>

                <div className="flex gap-2 mt-4">
                  {!isSelected ? (
                    <button 
                      onClick={() => setSelectedYear(p.ano)} 
                      className="flex-1 bg-slate-900 text-white py-4 rounded-2xl text-[10px] font-black uppercase shadow-lg hover:bg-slate-800 transition-colors"
                    >
                      Acessar Ano
                    </button>
                  ) : (
                    <div className="flex-1 bg-white text-blue-600 py-4 rounded-2xl text-[10px] font-black uppercase text-center border border-white/20">
                      Visualizando Agora
                    </div>
                  )}

                  {!isSelected && (
                    <button 
                      onClick={() => handleRemoveYear(p.ano)} 
                      className="p-4 bg-red-50 text-red-400 hover:text-red-600 hover:bg-red-100 rounded-2xl transition-all"
                    >
                      <Trash2 size={18} />
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </section>

      <section className="bg-slate-50 p-10 rounded-[48px] border border-slate-100 border-dashed">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
          <div>
            <h3 className="font-black text-slate-800 text-xl flex items-center gap-2">
              <ArrowRightLeft size={24} className="text-purple-600" /> Comparativo de Performance
            </h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Analise o crescimento entre períodos</p>
          </div>
          <div className="flex items-center gap-3 bg-white p-3 rounded-3xl shadow-sm border border-slate-100">
            <select 
              value={compareYearA} 
              onChange={(e) => setCompareYearA(Number(e.target.value))}
              className="bg-slate-50 border-none text-xs font-black p-2 rounded-xl outline-none"
            >
              {data.parametros.map(p => <option key={p.ano} value={p.ano}>{p.ano}</option>)}
