                idx={idx} 
                onEdit={() => openEdit(prof)} 
                onDelete={() => handleDelete(prof.id, prof.nome)}
                onToggleStatus={() => toggleStatus(prof.id, true)}
              />
            ))}
            {ativos.length === 0 && (
              <div className="col-span-full py-16 text-center border-2 border-dashed border-slate-200 rounded-[40px] text-slate-400 font-bold uppercase text-xs">
                Nenhum barbeiro ativo cadastrado.
              </div>
            )}
