import React, { useState, useMemo } from 'react';
import { AppData, Profissional, ProfissionalPerfil } from '../types.ts';
import { Plus, Trash2, X, Edit3, Scissors, UserPlus, Save, Target, Info, UserMinus, UserCheck, AlertTriangle, UserX } from 'lucide-react';

interface ProfessionalsProps {
  data: AppData;
  setData: React.Dispatch<React.SetStateAction<AppData>>;
  year: number;
}

const Professionals: React.FC<ProfessionalsProps> = ({ data, setData, year }) => {
  const [modalMode, setModalMode] = useState<'add' | 'edit' | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formProf, setFormProf] = useState({ 
    nome: '', 
    cadeira: 1, 
    comissao: 50,
    metaMensal: 5000,
    ativo: true 
  });

  const [formPerfil, setFormPerfil] = useState<ProfissionalPerfil>({
    experiencia: '',
    perfilComportamental: '',
    especialidade: '',
    objetivo: ''
  });

  // Separação entre ativos e inativos com cálculo de produção do ano selecionado
  const { ativos, inativos } = useMemo(() => {
    const list = data.profissionais.map(prof => {
      const records = data.producao.filter(p => p.profissionalId === prof.id && p.ano === year);
      const totalProd = records.reduce((s, c) => s + c.producaoBruta, 0);
      return { ...prof, totalProd };
    });

    return {
      ativos: list.filter(p => p.ativo !== false).sort((a, b) => b.totalProd - a.totalProd),
      inativos: list.filter(p => p.ativo === false).sort((a, b) => b.totalProd - a.totalProd)
    };
  }, [data.profissionais, data.producao, year]);

  const openAdd = () => {
    setModalMode('add');
    setEditingId(null);
    setFormProf({ nome: '', cadeira: 1, comissao: 50, metaMensal: 5000, ativo: true });
    setFormPerfil({ experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const openEdit = (prof: Profissional) => {
    setModalMode('edit');
    setEditingId(prof.id);
    setFormProf({ 
      nome: prof.nome, 
      cadeira: prof.cadeira, 
      comissao: prof.comissao || 50,
      metaMensal: prof.metaMensal || 5000,
      ativo: prof.ativo 
    });
    setFormPerfil(prof.perfil || { experiencia: '', perfilComportamental: '', especialidade: '', objetivo: '' });
  };

  const handleSave = () => {
    if (!formProf.nome) return;

    if (modalMode === 'add') {
      const nProf: Profissional = {
        id: Math.random().toString(36).substr(2, 9),
        ...formProf,
        perfil: formPerfil
      };
      setData(prev => ({ 
        ...prev, 
        profissionais: [...prev.profissionais, nProf] 
      }));
    } else if (modalMode === 'edit' && editingId) {
      setData(prev => ({
        ...prev,
        profissionais: prev.profissionais.map(p => 
          p.id === editingId ? { ...p, ...formProf, perfil: formPerfil } : p
        )
      }));
    }
    setModalMode(null);
  };

  const handleDelete = (id: string, nome: string) => {
    if (window.confirm(`⚠️ AVISO CRÍTICO: Deseja EXCLUIR PERMANENTEMENTE o profissional "${nome}"?\n\nEsta ação não pode ser desfeita. Se ele já trabalhou na barbearia, recomendamos apenas "Inativar" para manter os relatórios financeiros do passado corretos.`)) {
      setData(prev => ({
        ...prev,
        profissionais: prev.profissionais.filter(p => p.id !== id)
      }));
    }
  };

  const toggleStatus = (id: string, currentStatus: boolean) => {
