      ? `Deseja INATIVAR este barbeiro?\n\nEle sairá da lista de ativos e não aparecerá nos novos fechamentos mensais, mas o histórico de faturamento dele será preservado.`
      : `Deseja REATIVAR este barbeiro?\n\nEle voltará para a equipe ativa e poderá receber novos lançamentos de serviço.`;

    if (window.confirm(message)) {
      setData(prev => ({
        ...prev,
        profissionais: prev.profissionais.map(p => 
          p.id === id ? { ...p, ativo: !currentStatus } : p
        )
      }));
    }
  };

