import React, { useState, useEffect } from 'react';
import { MOCK_DATA } from './constants.tsx';
import { AppData, ParametrosAnuais } from './types.ts';
import Dashboard from './components/Dashboard.tsx';
import Professionals from './components/Professionals.tsx';
import CashFlow from './components/CashFlow.tsx';
import Expenses from './components/Expenses.tsx';
import Config from './components/Config.tsx';
import Meetings from './components/Meetings.tsx';
import Subscriptions from './components/Subscriptions.tsx';
import Navigation from './components/Navigation.tsx';
import { Save } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('barber_bi_data');
    let baseData: AppData = MOCK_DATA;

    if (saved) {
      try {
        baseData = JSON.parse(saved);
      } catch (e) {
        baseData = MOCK_DATA;
      }
    }

    // Garante estrutura básica
    if (!baseData.parametros) baseData.parametros = [...MOCK_DATA.parametros];
    if (!baseData.profissionais) baseData.profissionais = [...MOCK_DATA.profissionais];

    // CORREÇÃO: Garante que todos os profissionais tenham a propriedade 'ativo'
    baseData.profissionais = baseData.profissionais.map(p => ({
      ...p,
      ativo: p.ativo !== false
    }));

    if (!baseData.producao) baseData.producao = [];
    if (!baseData.receitasExtras) baseData.receitasExtras = [];
    if (!baseData.gastos) baseData.gastos = [];

    // CORREÇÃO: Garante que anotações antigas tenham um ano atribuído (migração)
    if (!baseData.meetingNotes) {
      baseData.meetingNotes = [];
    } else {
      baseData.meetingNotes = baseData.meetingNotes.map(n => ({
        ...n,
        ano: n.ano || 2024 // Assume 2024 para notas legadas sem ano
      }));
    }

    if (!baseData.categoriasGastos) baseData.categoriasGastos = [...MOCK_DATA.categoriasGastos];

    // Garante que o ano atual existe nos parâmetros
    const currentYear = new Date().getFullYear();
    if (!baseData.parametros.some(p => p.ano === currentYear)) {
      const lastYearParams = baseData.parametros[baseData.parametros.length - 1] || MOCK_DATA.parametros[0];
      const newYearParams: ParametrosAnuais = {
        ...lastYearParams,
        ano: currentYear
      };
      baseData.parametros.push(newYearParams);
    }

    return baseData;
  });

  const [lastSaved, setLastSaved] = useState<string>('');

  useEffect(() => {
    localStorage.setItem('barber_bi_data', JSON.stringify(data));
    setLastSaved(new Date().toLocaleTimeString());
  }, [data]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard data={data} year={selectedYear} />;
      case 'professionals': return <Professionals data={data} setData={setData} year={selectedYear} />;
      case 'fluxo': return <CashFlow data={data} setData={setData} year={selectedYear} />;
      case 'assinaturas': return <Subscriptions data={data} year={selectedYear} />;
      case 'reuniao': return <Meetings data={data} setData={setData} year={selectedYear} />;
      case 'gastos': return <Expenses data={data} year={selectedYear} />;
      case 'config': return <Config data={data} setData={setData} selectedYear={selectedYear} setSelectedYear={setSelectedYear} />;
      default: return <Dashboard data={data} year={selectedYear} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col pb-24 md:pb-0 bg-slate-50">
      <header className="bg-white/80 backdrop-blur-md sticky top-0 z-50 px-6 py-4 flex justify-between items-center border-b border-slate-100">
        <div className="flex items-center gap-4">
          <div>
            <h2 className="text-lg font-extrabold text-slate-800">BarberPro BI</h2>
            <div className="flex items-center gap-2">
              <span className="text-[10px] text-blue-600 font-bold uppercase tracking-widest">Ano: {selectedYear}</span>
              <span className="text-[8px] text-slate-300">•</span>
              <div className="flex items-center gap-1 text-[9px] text-emerald-500 font-bold uppercase">
                <Save size={10} />
                Salvo {lastSaved}
              </div>
            </div>
          </div>
        </div>
        <div className="bg-slate-900 text-white px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-tighter shadow-lg shadow-slate-200">
          GBCortes7
        </div>
      </header>

      <main className="flex-1 p-6 max-w-5xl mx-auto w-full">
        {renderContent()}
      </main>

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { AppData, MeetingNote } from '../types.ts';
import { GoogleGenAI } from "@google/genai";
import { MessageSquare, Plus, BrainCircuit, Trash2, Calendar, Sparkles, UserCircle, ShoppingCart, TrendingUp, Scissors, Target, UserCheck, DollarSign, Wallet, ShoppingBag, BarChart2, ListChecks, History } from 'lucide-center';

interface MeetingsProps {
  data: AppData;
  setData: (data: AppData) => void;
  year: number;
}

const Meetings: React.FC<MeetingsProps> = ({ data, setData, year }) => {
  const [selectedProfId, setSelectedProfId] = useState(data.profissionais[0]?.id || '');
  const [newNote, setNewNote] = useState('');
  const [weeklyNote, setWeeklyNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiScript, setAiScript] = useState('');

  const selectedProf = data.profissionais.find(p => p.id === selectedProfId);

  // CORREÇÃO: Filtrar anotações pelo profissional selecionado E pelo ano ativo
  const notes = useMemo(() => {
    return (data.meetingNotes || []).filter(n => 
      n.profissionalId === selectedProfId && n.ano === year
    );
  }, [data.meetingNotes, selectedProfId, year]);

  const performance = useMemo(() => {
    if (!selectedProfId) return null;

    const producaoProf = data.producao.filter(p => p.profissionalId === selectedProfId && p.ano === year);
    const ultimoMes = producaoProf.length > 0 ? Math.max(...producaoProf.map(p => p.mes)) : 0;
    const d = producaoProf.find(p => p.mes === ultimoMes);

    if (!d) return null;

    const atendimentosServico = d.quantidadeAtendimentos || 0;
    const atendimentosAssinatura = d.atendimentosAssinatura || 0;

    const vendasProdutosBruto = d.vendasProdutos || 0;
    const comissaoVendas = d.vendasProdutosComissao || 0;

    const producaoServicosBruta = d.producaoBruta || 0;
    const comissaoServicos = d.repasseProfissional || 0;
    const comissaoAssinaturas = d.repasseAssinatura || 0;

    const recebidoTotais = comissaoServicos + comissaoAssinaturas + comissaoVendas;

    const ticketMedio = atendimentosServico > 0 ? producaoServicosBruta / atendimentosServico : 0;

    const meta = selectedProf?.metaMensal || 5000;
    const progressoMeta = Math.min((producaoServicosBruta / meta) * 100, 100);

    return {
      mes: ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'][ultimoMes - 1],
      atendimentosServico,
      atendimentosAssinatura,
      vendasProdutosBruto,
      comissaoVendas,
      producaoServicosBruta,
      comissaoServicos,
      comissaoAssinaturas,
      recebidoTotais,
      ticketMedio,
      meta,
      progressoMeta,
      porcentagemReal: (producaoServicosBruta / meta) * 100
    };
  }, [data, selectedProfId, selectedProf, year]);

  const handleAddNote = (text: string, isWeekly: boolean = false) => {
    if (!text) return;
    const note: MeetingNote = {
      id: Math.random().toString(36).substr(2, 9),
      profissionalId: selectedProfId,
      ano: year, // CORREÇÃO: Salvar o ano atual na anotação
      data: new Date().toISOString(),
      texto: isWeekly ? `[ANÁLISE DA SEMANA] ${text}` : text
    };
    setData({ ...data, meetingNotes: [...(data.meetingNotes || []), note] });
    if (isWeekly) setWeeklyNote(''); else setNewNote('');
  };

  const handleDeleteNote = (id: string) => {
    if (confirm("Deseja remover esta nota de reunião?")) {
      setData({ ...data, meetingNotes: data.meetingNotes.filter(n => n.id !== id) });
    }
  };

  const handleGenerateScript = async () => {
    setIsGenerating(true);
    setAiScript('');
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      Atue como um gestor de barbearia de elite. Analise o desempenho do barbeiro ${selectedProf?.nome} 
      neste mês de ${performance?.mes} do ano ${year}:
      - Produção de Serviços: R$ ${performance?.producaoServicosBruta}
      - Ticket Médio Direto (Produção / ${performance?.atendimentosServico} atendimentos): R$ ${performance?.ticketMedio.toFixed(2)}
      - Venda de Produtos: R$ ${performance?.vendasProdutosBruto}
      - Comissão Total Recebida: R$ ${performance?.recebidoTotais}

      Gere um roteiro de feedback motivador focado em aumentar a recorrência e o ticket médio de produtos.
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiScript(response.text || "Erro ao processar feedback.");
    } catch (error) {
      console.error("Erro na geração de feedback:", error);
      setAiScript("Erro na conexão com a IA.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-32">
      <header>
        <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Pauta de Reunião {year}</h2>
        <p className="text-sm text-slate-400 font-bold uppercase mt-1">Análise estratégica individualizada</p>
      </header>

      <div className="flex gap-3 overflow-x-auto pb-4 custom-scrollbar">
        {data.profissionais.filter(p => p.ativo).map(p => (
          <button
            key={p.id}
            onClick={() => { setSelectedProfId(p.id); setAiScript(''); }}
            className={`px-8 py-4 rounded-[24px] text-xs font-black whitespace-nowrap transition-all border ${
              selectedProfId === p.id 
              ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100' 
              : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200'
            }`}
          >
            {p.nome}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
                  <BarChart2 size={24} className="text-blue-600" /> Resultados de {performance?.mes || 'Mês Atual'}
                </h3>
              </div>
            </div>

            {performance ? (
              <div className="space-y-8">
                <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                  <div className="flex justify-between items-end mb-4">
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Atingimento da Meta de Serviços</p>
                      <h4 className="text-3xl font-black text-slate-800">R$ {(performance.producaoServicosBruta || 0).toLocaleString('pt-BR')}</h4>
                    </div>
                    <div className="text-right">
                      <span className={`text-xl font-black ${performance.porcentagemReal >= 100 ? 'text-emerald-500' : 'text-blue-600'}`}>
                        {Math.round(performance.porcentagemReal || 0)}%
                      </span>
                    </div>
                  </div>
                  <div className="w-full h-4 bg-slate-200 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ${performance.porcentagemReal >= 100 ? 'bg-emerald-500' : 'bg-blue-600'}`}
                      style={{ width: `${performance.progressoMeta}%` }}
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  <PerformanceMetric label="Atendimentos (Serviço)" value={performance.atendimentosServico || 0} icon={Scissors} color="text-slate-600" />
                  <PerformanceMetric label="Atend. Assinatura" value={performance.atendimentosAssinatura || 0} icon={UserCheck} color="text-emerald-600" />
                  <PerformanceMetric label="Vendas Bruto (Produtos)" value={`R$ ${(performance.vendasProdutosBruto || 0).toLocaleString('pt-BR')}`} icon={ShoppingCart} color="text-purple-600" />
                  <PerformanceMetric label="Comissão de Vendas" value={`R$ ${(performance.comissaoVendas || 0).toLocaleString('pt-BR')}`} icon={ShoppingBag} color="text-purple-400" />
                  <PerformanceMetric label="Produção Serviços" value={`R$ ${(performance.producaoServicosBruta || 0).toLocaleString('pt-BR')}`} icon={Target} color="text-blue-600" />
                  <PerformanceMetric label="Comissão Serviços" value={`R$ ${(performance.comissaoServicos || 0).toLocaleString('pt-BR')}`} icon={Wallet} color="text-blue-400" />
                  <PerformanceMetric label="Comissão Assinatura" value={`R$ ${(performance.comissaoAssinaturas || 0).toLocaleString('pt-BR')}`} icon={UserCheck} color="text-emerald-400" />
                  <PerformanceMetric label="Recebido Total" value={`R$ ${(performance.recebidoTotais || 0).toLocaleString('pt-BR')}`} icon={DollarSign} color="text-slate-900" isTotal />
                </div>

